impl GameEventLogger {
    fn new(capacity: usize) -> Self {
        Self {
            sessions: BinaryHeap::with_capacity(capacity),
            capacity,
        }
    }

    fn log_session(&mut self, player_id: String, score: u32, timestamp: u64) {
        let session = GameSession {
            player_id,
            score,
            timestamp,
