use std::collections::BinaryHeap;
use std::cmp::Reverse;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct GameSession {
    pub player_id: u32,
    pub score: u32,
    pub timestamp: u64,
}

impl PartialOrd for GameSession {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for GameSession {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.score.cmp(&other.score)
    }
}

pub struct EventLoggingSystem {
    high_scores: BinaryHeap<GameSession>,
    low_scores: BinaryHeap<Reverse<GameSession>>,
    capacity: usize,
}

impl EventLoggingSystem {
    pub fn new() -> Self {
        Self {
            high_scores: BinaryHeap::new(),
            low_scores: BinaryHeap::new(),
            capacity: 500,
        }
    }

    pub fn push(&mut self, session: GameSession) {
        if self.high_scores.len() < self.capacity {
            self.high_scores.push(session);
        } else {
            if let Some(min_high) = self.high_scores.peek() {
                if session.score > min_high.score {
                    if let Some(removed) = self.high_scores.pop() {
                        self.low_scores.push(Reverse(removed));
                    }
                    self.high_scores.push(session);
                } else {
                    self.low_scores.push(Reverse(session));
                }
            }
        }
    }

    pub fn pop(&mut self) -> Option<GameSession> {
        let result = self.high_scores.pop();

        if self.high_scores.len() < self.capacity {
            if let Some(Reverse(session)) = self.low_scores.pop() {
                self.high_scores.push(session);
            }
        }

        result
    }

    pub fn peek(&self) -> Option<&GameSession> {
        self.high_scores.peek()
    }

    pub fn get_leaderboard(&self) -> Vec<GameSession> {
        let mut leaderboard: Vec<GameSession> = self.high_scores.clone().into_sorted_vec();
        leaderboard.reverse();
        leaderboard
    }

    pub fn len(&self) -> usize {
        self.high_scores.len()
    }

    pub fn is_empty(&self) -> bool {
        self.high_scores.is_empty()
    }
}
