use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub struct GameSessionLogger {
    high_scores: BinaryHeap<u32>,
    low_scores: BinaryHeap<Reverse<u32>>,
    capacity: usize,
}

impl GameSessionLogger {
    pub fn new() -> Self {
        Self {
            high_scores: BinaryHeap::new(),
            low_scores: BinaryHeap::new(),
            capacity: 500,
        }
    }

    pub fn push(&mut self, score: u32) {
        if self.high_scores.len() < self.capacity {
            self.high_scores.push(score);
        } else {
            let mut scores: Vec<u32> = self.high_scores.drain().collect();
            scores.push(score);
            scores.sort_by(|a, b| b.cmp(a));
            scores.truncate(self.capacity);
            self.high_scores = scores.into_iter().collect();
        }
    }

    pub fn pop(&mut self) -> Option<u32> {
        self.high_scores.pop()
    }

    pub fn peek(&self) -> Option<&u32> {
        self.high_scores.peek()
    }

    pub fn get_leaderboard(&self) -> Vec<u32> {
        let mut scores: Vec<u32> = self.high_scores.iter().cloned().collect();
        scores.sort_by(|a, b| b.cmp(a));
        scores
    }

    pub fn len(&self) -> usize {
        self.high_scores.len()
    }

    pub fn is_empty(&self) -> bool {
        self.high_scores.is_empty()
    }
}
