import java.util.PriorityQueue;
import java.util.concurrent.locks.ReentrantLock;

public class RealTimeMessageHandler {
    private static final int MAX_CAPACITY = 100;
    private final PriorityQueue<Message> messageQueue;
    private final ReentrantLock lock;

    public RealTimeMessageHandler() {
        this.messageQueue = new PriorityQueue<>((m1, m2) -> Integer.compare(m2.priority, m1.priority));
        this.lock = new ReentrantLock();
    }

    public boolean offer(Message message) {
        lock.lock();
        try {
            if (messageQueue.size() >= MAX_CAPACITY) {
                return false;
            }
            return messageQueue.offer(message);
        } finally {
            lock.unlock();
        }
    }

    public Message poll() {
        lock.lock();
        try {
            return messageQueue.poll();
        } finally {
            lock.unlock();
        }
    }

    public static class Message {
        private final String content;
        private final int priority;
        private final long timestamp;

        public Message(String content, int priority) {
            this.content = content;
            this.priority = priority;
            this.timestamp = System.currentTimeMillis();
        }

        public String getContent() { return content; }
        public int getPriority() { return priority; }
        public long getTimestamp() { return timestamp; }
    }
}
