		mutex.Lock()
		defer mutex.Unlock()

		if len(students) < 50 {
			students = append(students, name)
		}
	}

	getStudentList := func() []string {
		mutex.Lock()
		defer mutex.Unlock()

		result := make([]string, len(students))
		copy(result, students)
		return result
	}

	getStudentCount := func() int {
		mutex.Lock()
		defer mutex.Unlock()

		return len(students)
	}

	return addStudent, getStudentList, getStudentCount
