package main

import (
	"sync"
)

type ClassroomMonitor struct {
	students []string
	mutex    sync.RWMutex
	maxCap   int
}

func NewClassroomMonitor() *ClassroomMonitor {
	return &ClassroomMonitor{
		students: make([]string, 0, 50),
		maxCap:   50,
	}
}

func (cm *ClassroomMonitor) AddStudent(name string) bool {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()

	if len(cm.students) >= cm.maxCap {
		return false
	}

	cm.students = append(cm.students, name)
	return true
}

func (cm *ClassroomMonitor) RemoveStudent(name string) bool {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()

	for i, student := range cm.students {
		if student == name {
			cm.students = append(cm.students[:i], cm.students[i+1:]...)
			return true
		}
	}
	return false
}

func (cm *ClassroomMonitor) GetStudentCount() int {
	cm.mutex.RLock()
	defer cm.mutex.RUnlock()

	return len(cm.students)
}

func (cm *ClassroomMonitor) GenerateReport() []string {
	cm.mutex.RLock()
	defer cm.mutex.RUnlock()

	report := make([]string, len(cm.students))
	copy(report, cm.students)
	return report
}

func (cm *ClassroomMonitor) UpdateAttendanceAsync(updates chan string, removals chan string, done chan bool) {
	go func() {
		for {
			select {
			case student := <-updates:
				cm.AddStudent(student)
			case student := <-removals:
				cm.RemoveStudent(student)
			case <-done:
				return
			}
		}
	}()
}
