package main

import (
	"fmt"
	"sync"
)

type ClassroomMonitor struct {
	students    []string
	maxSize     int
	mutex       sync.Mutex
	subscribers []func([]string)
}

func NewClassroomMonitor(maxSize int) *ClassroomMonitor {
	if maxSize <= 0 {
		maxSize = 50
	}
	return &ClassroomMonitor{
		students:    make([]string, 0, maxSize),
		maxSize:     maxSize,
		subscribers: make([]func([]string), 0),
	}
}

func (cm *ClassroomMonitor) Push(studentName string) bool {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()

	if len(cm.students) >= cm.maxSize {
		return false
	}

	cm.students = append(cm.students, studentName)
	cm.notifySubscribers()
	return true
}

func (cm *ClassroomMonitor) Pop() (string, bool) {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()

	if len(cm.students) == 0 {
		return "", false
	}

	lastIdx := len(cm.students) - 1
	student := cm.students[lastIdx]
	cm.students = cm.students[:lastIdx]
	cm.notifySubscribers()
	return student, true
}

func (cm *ClassroomMonitor) GetCount() int {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()
	return len(cm.students)
}

func (cm *ClassroomMonitor) GetSnapshot() []string {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()

	snapshot := make([]string, len(cm.students))
	copy(snapshot, cm.students)
	return snapshot
}

func (cm *ClassroomMonitor) Subscribe(callback func([]string)) {
	cm.mutex.Lock()
	defer cm.mutex.Unlock()
	cm.subscribers = append(cm.subscribers, callback)
}

func (cm *ClassroomMonitor) notifySubscribers() {
	snapshot := cm.GetSnapshot()
	for _, subscriber := range cm.subscribers {
		go subscriber(snapshot)
	}
}
