        if self.timestamps.contains(&timestamp) {
            return Err(DocumentError::DuplicateTimestamp);
        }

        if self.versions.len() >= 100 {
            return Err(DocumentError::MaxCapacityExceeded);
        }

        let version = DocumentVersion { id, content, timestamp };
        self.versions.push(version);
        self.timestamps.insert(timestamp);
        Ok(())
    }

    fn add_version_insert(&mut self, index: usize, id: String, content: String, timestamp: u64) -> Result<(), DocumentError> {
        if self.timestamps.contains(&timestamp) {
            return Err(DocumentError::DuplicateTimestamp);
        }

        if self.versions.len() >= 100 {
            return Err(DocumentError::MaxCapacityExceeded);
        }

        let version = DocumentVersion { id, content, timestamp };
        self.versions.insert(index, version);
        self.timestamps.insert(timestamp);
        Ok(())
