use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Clone)]
struct DocumentVersion {
    id: String,
    content: String,
    timestamp: u64,
}

#[derive(Debug)]
enum DocumentError {
    DuplicateTimestamp,
    MaxCapacityExceeded,
}

struct DocumentTracker {
    versions: Vec<DocumentVersion>,
}

impl DocumentTracker {
    fn new() -> Self {
        Self {
            versions: Vec::new(),
        }
    }

    fn add_version(&mut self, id: String, content: String) -> Result<(), DocumentError> {
        if self.versions.len() >= 100 {
            return Err(DocumentError::MaxCapacityExceeded);
        }

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        if self.versions.iter().any(|v| v.timestamp == timestamp) {
            return Err(DocumentError::DuplicateTimestamp);
        }

        let version = DocumentVersion {
            id,
            content,
            timestamp,
        };

        self.versions.push(version);
