use std::collections::BTreeSet;

#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
pub struct DocumentVersion {
    pub timestamp: u64,
    pub content: String,
}

#[derive(Debug)]
pub enum DocumentError {
    CapacityExceeded,
    DuplicateTimestamp,
}

pub struct DocumentTracker {
    versions: Vec<DocumentVersion>,
    timestamps: BTreeSet<u64>,
}

impl DocumentTracker {
    pub fn new() -> Self {
        Self {
            versions: Vec::new(),
            timestamps: BTreeSet::new(),
        }
    }

    pub fn add_version(&mut self, content: String, timestamp: u64) -> Result<(), DocumentError> {
        if self.versions.len() >= 100 {
            return Err(DocumentError::CapacityExceeded);
        }

        if self.timestamps.contains(&timestamp) {
            return Err(DocumentError::DuplicateTimestamp);
        }

        let version = DocumentVersion { timestamp, content };

        let insert_pos = self.versions
            .binary_search(&version)
            .unwrap_or_else(|pos| pos);

        self.versions.insert(insert_pos, version);
        self.timestamps.insert(timestamp);

        Ok(())
    }

    pub fn get_versions(&self) -> &Vec<DocumentVersion> {
        &self.versions
    }
}
