type ReservationDetails struct {
	Date      time.Time
	TableNumber int
}

type ReservationSystem struct {
	reservations     map[string][]ReservationDetails
	waitlist         []waitlistEntry
	maxReservations  int
}

type waitlistEntry struct {
	CustomerName string
	Details      ReservationDetails
}

func NewReservationSystem() *ReservationSystem {
	return &ReservationSystem{
		reservations:    make(map[string][]ReservationDetails),
		waitlist:        []waitlistEntry{},
		maxReservations: 50,
	}
}

func (rs *ReservationSystem) AddReservation(customerName string, date time.Time, tableNumber int) error {
	// Check if table is already booked for that date
	for _, reservations := range rs.reservations {
		for _, r := range reservations {
			if r.TableNumber == tableNumber && r.Date.Year() == date.Year() && 
			   r.Date.Month() == date.Month() && r.Date.Day() == date.Day() {
				return errors.New("table already booked for this date")
			}
		}
	}

	details := ReservationDetails{
		Date:      date,
		TableNumber: tableNumber,
	}

	// Add to waitlist if at capacity
	totalReservations := 0
	for _, reservations := range rs.reservations {
		totalReservations += len(reservations)
	}

	if totalReservations >= rs.maxReservations {
		rs.waitlist = append(rs.waitlist, waitlistEntry{
			CustomerName: customerName,
			Details:      details,
		})
		return errors.New("reservation added to waitlist")
	}

	// Add reservation
	rs.reservations[customerName] = append(rs.reservations[customerName], details)
	return nil
}

func (rs *ReservationSystem) CancelReservation(customerName string, date time.Time, tableNumber int) error {
	reservations, exists := rs.reservations[customerName]
	if !exists {
		return errors.New("customer has no reservations")
	}

	for i, r := range reservations {
		if r.TableNumber == tableNumber && r.Date.Year() == date.Year() && 
		   r.Date.Month() == date.Month() && r.Date.Day() == date.Day() {
			// Remove this specific reservation
			reservations = append(reservations[:i], reservations[i+1:]...)

			// Update or delete the customer entry
			if len(reservations) == 0 {
				delete(rs.reservations, customerName)
			} else {
				rs.reservations[customerName] = reservations
			}

			// Process waitlist if available
			if len(rs.waitlist) > 0 {
				next := rs.waitlist[0]
				rs.waitlist = rs.waitlist[1:]

				// Add from waitlist
				if _, exists := rs.reservations[next.CustomerName]; exists {
					rs.reservations[next.CustomerName] = append(rs.reservations[next.CustomerName], next.Details)
				} else {
					rs.reservations[next.CustomerName] = []ReservationDetails{next.Details}
				}
			}

			return nil
		}
	}

	return errors.New("reservation not found")
}

func (rs *ReservationSystem) GetReservations(customerName string) ([]ReservationDetails, bool) {
	reservations, exists := rs.reservations[customerName]
	return reservations, exists
