package reservation

import (
	"errors"
	"time"
)

// Reservation represents booking details
type Reservation struct {
	Date      time.Time
	TableNum  int
	PartySize int
}

// ReservationSystem manages restaurant bookings
type ReservationSystem struct {
	reservations map[string][]Reservation
	waitlist     []WaitlistEntry
	maxCapacity  int
}

// WaitlistEntry represents a pending reservation
type WaitlistEntry struct {
	CustomerName string
	Details      Reservation
}

// NewReservationSystem creates a new reservation system
func NewReservationSystem() *ReservationSystem {
	return &ReservationSystem{
		reservations: make(map[string][]Reservation),
		waitlist:     []WaitlistEntry{},
		maxCapacity:  50,
	}
}

// AddReservation adds a new reservation or to waitlist if full
func (rs *ReservationSystem) AddReservation(customerName string, details Reservation) error {
	// Check if map is at capacity
	if len(rs.reservations) >= rs.maxCapacity && rs.reservations[customerName] == nil {
		// Add to waitlist
		rs.waitlist = append(rs.waitlist, WaitlistEntry{
			CustomerName: customerName,
			Details:      details,
		})
		return errors.New("reservation added to waitlist")
	}

	// Check for double booking
	if rs.isTableBooked(details.Date, details.TableNum) {
		return errors.New("table already booked for this date and time")
	}

	// Add or update reservation
	rs.reservations[customerName] = append(rs.reservations[customerName], details)
	return nil
}

// CancelReservation removes a reservation and processes waitlist
func (rs *ReservationSystem) CancelReservation(customerName string, date time.Time, tableNum int) error {
	reservations, exists := rs.reservations[customerName]
	if !exists {
		return errors.New("no reservations found for this customer")
	}

	// Find and remove the specific reservation
	for i, res := range reservations {
		if res.Date.Equal(date) && res.TableNum == tableNum {
			// Remove this reservation
			reservations = append(reservations[:i], reservations[i+1:]...)

			// If customer has no more reservations, delete the map entry
			if len(reservations) == 0 {
				delete(rs.reservations, customerName)
			} else {
				rs.reservations[customerName] = reservations
			}

			// Process waitlist if we have entries and room in the map
			rs.processWaitlist()
			return nil
		}
	}

	return errors.New("specific reservation not found")
}

// GetReservations retrieves all reservations for a customer
func (rs *ReservationSystem) GetReservations(customerName string) ([]Reservation, bool) {
	reservations, exists := rs.reservations[customerName]
	return reservations, exists
}

// processWaitlist moves waitlist entries to active reservations when possible
func (rs *ReservationSystem) processWaitlist() {
	for len(rs.waitlist) > 0 && len(rs.reservations) < rs.maxCapacity {
		// Get next waitlist entry
		entry := rs.waitlist[0]
		rs.waitlist = rs.waitlist[1:]

		// Verify table is still available
		if !rs.isTableBooked(entry.Details.Date, entry.Details.TableNum) {
			rs.reservations[entry.CustomerName] = append(
				rs.reservations[entry.CustomerName], 
				entry.Details,
			)
		}
	}
}

// isTableBooked checks if a table is already booked for a specific date
func (rs *ReservationSystem) isTableBooked(date time.Time, tableNum int) bool {
	for _, reservations := range rs.reservations {
		for _, res := range reservations {
			if res.Date.Equal(date) && res.TableNum == tableNum {
				return true
			}
		}
	}
	return false
}
