// InventoryControl manages product stock levels
func InventoryControl(initialProducts []Product) func(action string, product Product) []Product {
	inventory := make([]Product, len(initialProducts))
	copy(inventory, initialProducts)

	return func(action string, product Product) []Product {
		if action == "add" {
			// Add new product to inventory
			inventory = append(inventory, product)
		} else if action == "update" {
			// Update existing product stock
			updatedInventory := make([]Product, 0, len(inventory))
			for _, item := range inventory {
				if item.ID == product.ID {
					// Create updated product with new stock level
					updatedItem := Product{
						ID:    item.ID,
						Name:  item.Name,
						Stock: product.Stock,
					}
					updatedInventory = append(updatedInventory, updatedItem)
				} else {
					updatedInventory = append(updatedInventory, item)
				}
			}
			inventory = make([]Product, len(updatedInventory))
			copy(inventory, updatedInventory)
		}

		// Return a copy of the current inventory
		result := make([]Product, len(inventory))
		copy(result, inventory)
		return result
	}
}
