	return &InventoryManager{
		products: make([]Product, 0, 10),
		maxSize:  10,
	}
}

func (im *InventoryManager) AddProduct(id, name string, stock int) bool {
	if len(im.products) >= im.maxSize {
		// Remove the oldest product (FIFO)
		im.products = append(im.products[1:], Product{})
		im.products = im.products[:len(im.products)-1]
	}

	// Append the new product
	newProduct := Product{ID: id, Name: name, Stock: stock}
	im.products = append(im.products, newProduct)
	return true
}

func (im *InventoryManager) UpdateStock(id string, additionalStock int) bool {
	tempProducts := make([]Product, 0, im.maxSize)
	found := false

	// Process all products in FIFO order
	for _, product := range im.products {
		if product.ID == id {
			product.Stock += additionalStock
			found = true
		}
		tempProducts = append(tempProducts, product)
	}

	if found {
		// Copy back the updated products
		im.products = make([]Product, 0, im.maxSize)
		im.products = append(im.products, tempProducts...)
		return true
	}

	return false
}

func (im *InventoryManager) GetProducts() []Product {
	result := make([]Product, len(im.products))
	copy(result, im.products)
	return result
}
