	if len(im.products) >= im.maxSize {
		return false
	}

	im.products = append(im.products, product)
	return true
}

func (im *InventoryManager) UpdateStock(id string, newStock int) bool {
	if len(im.products) == 0 {
		return false
	}

	// Create a temporary queue for FIFO operations
	tempQueue := make([]Product, 0, im.maxSize)
	found := false

	// Process each product through the queue
	for len(im.products) > 0 {
		// Dequeue from front
		product := im.products[0]
		im.products = im.products[1:]

		// Update if matching ID
		if product.ID == id {
			product.Stock = newStock
			found = true
		}

		// Enqueue to temporary queue
		tempQueue = append(tempQueue, product)
	}

	// Copy back to original queue
	im.products = make([]Product, len(tempQueue))
	copy(im.products, tempQueue)

	return found
}

func (im *InventoryManager) GetProducts() []Product {
	result := make([]Product, len(im.products))
	copy(result, im.products)
	return result
