    const size_t MAX_TAGS = 1000;
    const size_t MAX_QUEUE_SIZE = 500;

public:
    void addTag(const std::string& tag) {
        if (tagSet.size() >= MAX_TAGS) {
            std::string oldestTag = tagQueue.front();
            tagQueue.pop();
            tagSet.erase(oldestTag);
        }

        tagSet.insert(tag);

        if (tagQueue.size() >= MAX_QUEUE_SIZE) {
            tagQueue.pop();
        }
        tagQueue.push(tag);
    }

    void removeTag(const std::string& tag) {
        if (tagSet.find(tag) != tagSet.end()) {
            tagSet.erase(tag);
        }
    }

    bool hasTag(const std::string& tag) const {
        return tagSet.find(tag) != tagSet.end();
    }

    size_t getTagCount() const {
        return tagSet.size();
    }
};
