#include <iostream>
#include <stack>
#include <string>
#include <sstream>

int evaluatePostfix(const std::string& expression) {
    std::stack<int> stack;
    std::istringstream iss(expression);
    std::string token;

    while (iss >> token) {
        // Check if token is a number
        if (isdigit(token[0]) || (token.size() > 1 && token[0] == '-' && isdigit(token[1]))) {
            stack.push(std::stoi(token));
        }
        // Token is an operator
        else if (token == "+" || token == "-" || token == "*" || token == "/") {
            // Check if stack has at least two operands
            if (stack.size() < 2) {
                throw std::runtime_error("Invalid expression: insufficient operands");
            }

            int operand2 = stack.top();
            stack.pop();
            int operand1 = stack.top();
            stack.pop();

            if (token == "+") {
                stack.push(operand1 + operand2);
            } else if (token == "-") {
                stack.push(operand1 - operand2);
            } else if (token == "*") {
                stack.push(operand1 * operand2);
            } else if (token == "/") {
                if (operand2 == 0) {
                    throw std::runtime_error("Division by zero");
                }
                stack.push(operand1 / operand2);
            }
        } else {
            throw std::runtime_error("Invalid symbol: " + token);
        }
    }

    // Check if there's exactly one result in the stack
    if (stack.size() != 1) {
        throw std::runtime_error("Invalid expression: too many operands");
    }

    return stack.top();
}

int main() {
    try {
        std::string expression;
        std::cout << "Enter postfix expression (with spaces between tokens): ";
        std::getline(std::cin, expression);
        int result = evaluatePostfix(expression);
        std::cout << "Result: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}
