            throw std::runtime_error("Stack overflow: maximum 10 elements exceeded");
        }

        if (token == "+" || token == "-" || token == "*" || token == "/") {
            if (stack.size() < 2) {
                return "Error: insufficient operands";
            }

            int b = stack.top(); stack.pop();
            int a = stack.top(); stack.pop();

            int result;
            if (token == "+") {
                result = a + b;
            } else if (token == "-") {
                result = a - b;
            } else if (token == "*") {
                result = a * b;
            } else if (token == "/") {
                if (b == 0) {
                    return "Error: division by zero";
                }
                result = a / b;
            }

            stack.push(result);
        } else {
            try {
                int num = std::stoi(token);
                stack.push(num);
            } catch (const std::exception&) {
                return "Error: invalid symbol";
            }
        }
    }

    if (stack.size() != 1) {
        return "Error: invalid expression";
    }

    return std::to_string(stack.top());
