use std::collections::{HashMap, VecDeque};
use std::time::{Instant, SystemTime};

struct InventoryManager {
    stock: HashMap<String, (u32, SystemTime)>,
    update_order: VecDeque<String>,
    capacity: usize,
}

impl InventoryManager {
    fn new(capacity: usize) -> Self {
        InventoryManager {
            stock: HashMap::new(),
            update_order: VecDeque::new(),
            capacity: capacity,
        }
    }

    fn update_stock(&mut self, product_id: &str, quantity_change: i32) -> Result<u32, &str> {
        let now = SystemTime::now();

        // Check if item exists
        let current_quantity = match self.stock.get(product_id) {
            Some((qty, _)) => *qty as i32,
            None => {
                // New item
                if quantity_change <= 0 {
                    return Err("Cannot add new item with zero or negative quantity");
                }

                // Check capacity before adding
                if self.stock.len() >= self.capacity {
                    // Remove least recently updated item
                    if let Some(oldest_id) = self.update_order.pop_front() {
                        self.stock.remove(&oldest_id);
                    }
                }

                0
            }
        };

        // Calculate new quantity
        let new_quantity = current_quantity + quantity_change;

        // Update tracking for this product
        if let Some(pos) = self.update_order.iter().position(|id| id == product_id) {
            self.update_order.remove(pos);
        }

        if new_quantity <= 0 {
            // Remove item if quantity is zero or negative
            self.stock.remove(product_id);
            Ok(0)
        } else {
            // Update item
            self.stock.insert(product_id.to_string(), (new_quantity as u32, now));
            self.update_order.push_back(product_id.to_string());
            Ok(new_quantity as u32)
        }
    }

    fn get_stock(&self, product_id: &str) -> Option<u32> {
        self.stock.get(product_id).map(|(qty, _)| *qty)
    }
}
