struct InventoryManager {
    stock: HashMap<String, (u32, Instant)>,
    max_capacity: usize,
}

impl InventoryManager {
    fn new(max_capacity: usize) -> Self {
        InventoryManager {
            stock: HashMap::new(),
            max_capacity: max_capacity,
        }
    }

    fn update_stock(&mut self, product_id: &str, quantity: i32) -> Result<u32, &'static str> {
        if self.stock.len() >= self.max_capacity && !self.stock.contains_key(product_id) && quantity > 0 {
            self.remove_least_recently_used();
        }

        let current_time = Instant::now();
        let current_quantity = match self.stock.get(product_id) {
            Some(&(qty, _)) => qty as i32,
            None => 0,
        };

        let new_quantity = current_quantity + quantity;

        if new_quantity <= 0 {
            self.stock.remove(product_id);
            return Ok(0);
        } else {
            self.stock.insert(product_id.to_string(), (new_quantity as u32, current_time));
            return Ok(new_quantity as u32);
        }
    }

    fn get_stock_level(&mut self, product_id: &str) -> u32 {
        if let Some(&(qty, _)) = self.stock.get(product_id) {
            let current_time = Instant::now();
            self.stock.insert(product_id.to_string(), (qty, current_time));
            qty
        } else {
            0
        }
    }

    fn remove_least_recently_used(&mut self) {
        if let Some((lru_key, _)) = self.stock.iter()
            .min_by_key(|(_, (_, timestamp))| timestamp) {
                let lru_key = lru_key.clone();
                self.stock.remove(&lru_key);
            }
    }
}

fn manage_inventory(product_id: &str, quantity: i32) -> Result<u32, &'static str> {
