public class BrowserHistory {
    private String[] stack;
    private int top;
    private final int MAX_SIZE = 10;

    public BrowserHistory() {
        stack = new String[MAX_SIZE];
        top = -1;
    }

    public void navigateToPage(String url) {
        if (top < MAX_SIZE - 1) {
            push(url);
            System.out.println("Navigated to: " + url);
        } else {
            System.out.println("History stack is full. Cannot navigate to: " + url);
        }
    }

    public void goBack() {
        if (top > 0) {
            pop();
            System.out.println("Navigated back to: " + peek());
        } else {
            System.out.println("No previous page in history");
        }
    }

    public void displayCurrentPage() {
        if (top >= 0) {
            System.out.println("Current page: " + peek());
        } else {
            System.out.println("No page in history");
        }
    }

    private void push(String url) {
        stack[++top] = url;
    }

    private String pop() {
        return stack[top--];
    }

    private String peek() {
        return stack[top];
    }
}
