import java.util.*;

public class ExamScheduler {

    // Exam class to store examination details
    static class Exam implements Comparable<Exam> {
        private String courseName;
        private Date examDate;
        private String location;

        public Exam(String courseName, Date examDate, String location) {
            this.courseName = courseName;
            this.examDate = examDate;
            this.location = location;
        }

        @Override
        public int compareTo(Exam other) {
            return this.examDate.compareTo(other.examDate);
        }

        @Override
        public String toString() {
            return "Course: " + courseName + ", Date: " + examDate + ", Location: " + location;
        }
    }

    private PriorityQueue<Exam> examQueue;

    public ExamScheduler() {
        examQueue = new PriorityQueue<>();
    }

    // Add a new exam to the schedule
    public void scheduleExam(String courseName, Date examDate, String location) {
        Exam newExam = new Exam(courseName, examDate, location);
        examQueue.offer(newExam);
    }

    // Retrieve and remove the earliest exam
    public Exam getNextExam() {
        if (examQueue.isEmpty()) {
            return null;
        }
        return examQueue.poll();
    }

    // Check if there are any exams scheduled
    public boolean hasExams() {
        return !examQueue.isEmpty();
    }

    // Get the total number of exams scheduled
    public int getTotalExams() {
        return examQueue.size();
    }

    // Peek at the next exam without removing it
    public Exam peekNextExam() {
        return examQueue.peek();
    }
}
