public class ExamSchedulingSystem {
    private PriorityQueue<Exam> examQueue;
    private static final int MAX_CAPACITY = 10;

    public ExamSchedulingSystem() {
        this.examQueue = new PriorityQueue<>(Comparator.comparing(Exam::getDate));
    }

    public boolean scheduleExam(String subject, LocalDate date, String hall) {
        if (examQueue.size() >= MAX_CAPACITY) {
            return false;
        }

        Exam newExam = new Exam(subject, date, hall);
        return examQueue.offer(newExam);
    }

    public Exam processNextExam() {
        if (examQueue.isEmpty()) {
            return null;
        }

        Exam processedExam = examQueue.poll();
        return processedExam;
    }

    public Exam checkNextExam() {
        if (examQueue.isEmpty()) {
            return null;
        }

        return examQueue.peek();
    }

    public Exam processAndCheckNext() {
        if (examQueue.isEmpty()) {
            return null;
        }

        Exam processedExam = examQueue.poll();

        if (!examQueue.isEmpty()) {
            Exam nextExam = examQueue.peek();
            return nextExam;
        }

        return null;
    }

    public boolean isEmpty() {
        return examQueue.isEmpty();
    }

    public int size() {
        return examQueue.size();
    }
}
