import java.util.*;
import java.util.concurrent.locks.ReentrantReadWriteLock;

public class InventorySystem {
    private static final int MAX_CAPACITY = 50;
    private final Set<Product> inventory;
    private final LinkedList<Product> accessOrder;
    private final ReentrantReadWriteLock lock;

    public InventorySystem() {
        this.inventory = new HashSet<>();
        this.accessOrder = new LinkedList<>();
        this.lock = new ReentrantReadWriteLock();
    }

    public boolean addProduct(Product product) {
        lock.writeLock().lock();
        try {
            if (inventory.contains(product)) {
                updateAccessOrder(product);
                return false;
            }

            if (inventory.size() >= MAX_CAPACITY) {
                Product leastRecentlyAccessed = accessOrder.removeFirst();
                inventory.remove(leastRecentlyAccessed);
            }

            boolean added = inventory.add(product);
            if (added) {
                accessOrder.addLast(product);
            }
            return added;
        } finally {
            lock.writeLock().unlock();
        }
    }

    public boolean removeProduct(Product product) {
        lock.writeLock().lock();
        try {
            boolean removed = inventory.remove(product);
            if (removed) {
                accessOrder.remove(product);
            }
            return removed;
        } finally {
            lock.writeLock().unlock();
        }
    }

    public boolean containsProduct(Product product) {
        lock.readLock().lock();
        try {
            boolean contains = inventory.contains(product);
            if (contains) {
                updateAccessOrder(product);
            }
            return contains;
        } finally {
            lock.readLock().unlock();
        }
    }

    public int getInventorySize() {
        lock.readLock().lock();
        try {
            return inventory.size();
        } finally {
            lock.readLock().unlock();
        }
    }

    private void updateAccessOrder(Product product) {
        accessOrder.remove(product);
        accessOrder.addLast(product);
    }

    public static class Product {
        private final String id;
        private final String name;

        public Product(String id, String name) {
            this.id = id;
            this.name = name;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Product product = (Product) o;
            return Objects.equals(id, product.id);
        }

        @Override
        public int hashCode() {
            return Objects.hash(id);
        }
    }
}
