struct FloorRequest {
    floor: u32,
    is_urgent: bool,
}

struct ElevatorScheduler {
    requests: Vec<FloorRequest>,
    capacity: usize,
}

impl ElevatorScheduler {
    fn new() -> Self {
        Self {
            requests: Vec::with_capacity(10),
            capacity: 10,
        }
    }

    fn add_request(&mut self, floor: u32, is_urgent: bool) -> Result<(), &'static str> {
        if self.requests.len() >= self.capacity {
            return Err("Elevator queue is full");
        }
        self.requests.push(FloorRequest { floor, is_urgent });
        Ok(())
    }

    fn get_next_floor(&mut self) -> Option<u32> {
        // Check for urgent requests first
        if let Some(urgent_index) = self.requests.iter().position(|req| req.is_urgent) {
            let urgent_request = self.requests.remove(urgent_index);
            return Some(urgent_request.floor);
        }

        // If no urgent requests, get the first request (FIFO)
        if !self.requests.is_empty() {
            let request = self.requests.remove(0);
            return Some(request.floor);
        }

        None
    }
}
