struct FloorRequest {
    floor: u32,
    is_urgent: bool,
}

struct ElevatorQueue {
    requests: Vec<FloorRequest>,
}

impl ElevatorQueue {
    fn new() -> Self {
        Self {
            requests: Vec::with_capacity(10),
        }
    }

    fn push(&mut self, floor: u32, is_urgent: bool) -> Result<(), &'static str> {
        if self.requests.len() >= 15 {
            return Err("Queue capacity exceeded");
        }

        self.requests.push(FloorRequest { floor, is_urgent });
        Ok(())
    }

    fn pop(&mut self) -> Option<FloorRequest> {
        // First check for any urgent requests
        if let Some(urgent_index) = self.requests.iter().position(|r| r.is_urgent) {
            // Remove and return the urgent request (maintaining FIFO for urgent requests)
            Some(self.requests.remove(urgent_index))
        } else {
            // If no urgent requests, pop from the front (FIFO)
            self.requests.pop_front()
        }
    }

    fn is_empty(&self) -> bool {
        self.requests.is_empty()
    }

    fn len(&self) -> usize {
        self.requests.len()
    }
}
