        if (eventId == null) {
            return false;
        }

        // Find and remove the event
        for (int i = 0; i < events.size(); i++) {
            if (events.get(i).getId().equals(eventId)) {
                events.remove(i);
                return true;
            }
        }

        return false; // Event not found
    }
}

