    private Vector<String> agendaItems;
    private List<MeetingUser> connectedUsers;
    private static final int MAX_AGENDA_ITEMS = 10;

    public OnlineMeetingPlatform() {
        this.agendaItems = new Vector<>();
        this.connectedUsers = new CopyOnWriteArrayList<>();
    }

    public synchronized boolean addAgendaItem(String item) {
        if (agendaItems.size() >= MAX_AGENDA_ITEMS) {
            return false;
        }

        boolean added = agendaItems.add(item);
        if (added) {
            notifyAllUsers();
        }
        return added;
    }

    public synchronized boolean removeAgendaItem(String item) {
        boolean removed = agendaItems.remove(item);
        if (removed) {
            notifyAllUsers();
        }
        return removed;
    }

    public synchronized boolean removeAgendaItem(int index) {
        if (index >= 0 && index < agendaItems.size()) {
            agendaItems.remove(index);
            notifyAllUsers();
            return true;
        }
        return false;
    }

    private void notifyAllUsers() {
        Vector<String> currentAgenda = new Vector<>(agendaItems);
        for (MeetingUser user : connectedUsers) {
            user.updateAgenda(currentAgenda);
        }
    }

    public void addUser(MeetingUser user) {
        connectedUsers.add(user);
        user.updateAgenda(new Vector<>(agendaItems));
    }

    public void removeUser(MeetingUser user) {
        connectedUsers.remove(user);
    }

    public Vector<String> getAgendaItems() {
        return new Vector<>(agendaItems);
    }

    public int getAgendaSize() {
        return agendaItems.size();
    }

    public int getMaxAgendaItems() {
        return MAX_AGENDA_ITEMS;
    }
}

