import java.util.Vector;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.function.Consumer;

public class MeetingAgendaManager {
    private final Vector<String> agendaItems = new Vector<>();
    private final CopyOnWriteArrayList<Consumer<Vector<String>>> observers = new CopyOnWriteArrayList<>();
    private static final int MAX_AGENDA_ITEMS = 10;

    public boolean addAgendaItem(String item) {
        if (agendaItems.size() >= MAX_AGENDA_ITEMS) {
            return false;
        }
        boolean result = agendaItems.add(item);
        if (result) {
            notifyObservers();
        }
        return result;
    }

    public boolean removeAgendaItem(String item) {
        boolean result = agendaItems.remove(item);
        if (result) {
            notifyObservers();
        }
        return result;
    }

    public boolean removeAgendaItemAt(int index) {
        if (index >= 0 && index < agendaItems.size()) {
            agendaItems.remove(index);
            notifyObservers();
            return true;
        }
        return false;
    }

    public boolean updateAgendaItem(int index, String newItem) {
        if (index >= 0 && index < agendaItems.size()) {
            agendaItems.set(index, newItem);
            notifyObservers();
            return true;
        }
        return false;
    }

    public Vector<String> getAgendaItems() {
        return new Vector<>(agendaItems);
    }

    public void registerObserver(Consumer<Vector<String>> observer) {
        observers.add(observer);
        observer.accept(getAgendaItems());
    }

    public void removeObserver(Consumer<Vector<String>> observer) {
        observers.remove(observer);
    }

    private void notifyObservers() {
        Vector<String> items = getAgendaItems();
        observers.forEach(observer -> observer.accept(items));
    }
}
