class ConferenceScheduler {
private:
    std::map<std::string, std::vector<std::string>> schedule;
    static const int MAX_EVENTS = 10;

    int getTotalEvents() const {
        int count = 0;
        for (const auto& timeslot : schedule) {
            count += timeslot.second.size();
        }
        return count;
    }

public:
    bool insert(const std::string& time, const std::string& eventName) {
        if (getTotalEvents() >= MAX_EVENTS) {
            return false;
        }
        schedule[time].push_back(eventName);
        return true;
    }

    bool erase(const std::string& time, const std::string& eventName) {
        auto it = schedule.find(time);
        if (it != schedule.end()) {
            auto& events = it->second;
            auto eventIt = std::find(events.begin(), events.end(), eventName);
            if (eventIt != events.end()) {
                events.erase(eventIt);
                if (events.empty()) {
                    schedule.erase(it);
                }
                return true;
            }
        }
        return false;
    }

    void clear() {
        schedule.clear();
    }

    const std::map<std::string, std::vector<std::string>>& getSchedule() const {
        return schedule;
    }
};
