class TaskStack {
private:
    std::string tasks[10];
    int topIndex;
    static const int MAX_SIZE = 10;

public:
    TaskStack() : topIndex(-1) {}

    bool push(const std::string& task) {
        if (topIndex >= MAX_SIZE - 1) {
            std::cerr << "Error: Stack is full. Cannot add task." << std::endl;
            return false;
        }
        tasks[++topIndex] = task;
        return true;
    }

    bool pop() {
        if (topIndex < 0) {
            std::cerr << "Error: Stack is empty. Cannot remove task." << std::endl;
            return false;
        }
        topIndex--;
        return true;
    }

    bool isEmpty() const {
        return topIndex < 0;
    }

    bool isFull() const {
        return topIndex >= MAX_SIZE - 1;
    }
};
