def event_registration_system():
    """
    Event registration system that manages attendees and their registration statuses
    using dictionary operations get and pop.
    """
    attendees = {}
    activity_log = []

    def register_attendee(name, details):
        """Register a new attendee with their details"""
        if attendees.get(name) is None:
            attendees[name] = details
            activity_log.append(f"Registered: {name}")
            return True
        else:
            activity_log.append(f"Registration failed - already exists: {name}")
            return False

    def is_registered(name):
        """Check if an attendee is registered using get method"""
        status = attendees.get(name)
        if status is not None:
            activity_log.append(f"Checked registration status: {name}")
        else:
            activity_log.append(f"Checked registration status for non-existent attendee: {name}")
        return status

    def withdraw_attendee(name):
        """Withdraw an attendee using pop method"""
        try:
            details = attendees.pop(name)
            activity_log.append(f"Withdrawn: {name}")
            return details
        except KeyError:
            activity_log.append(f"Withdrawal failed - not found: {name}")
            return None

    def get_activity_log():
        """Return the activity log"""
        return activity_log

    return {
        "register": register_attendee,
        "check": is_registered,
        "withdraw": withdraw_attendee,
        "activity_log": get_activity_log
    }
