            return status
        else:
            activity_log.append(f"Check performed: {name} not found")
            return None

    def remove_attendee(name):
        removed_status = attendees.pop(name, None)
        if removed_status is not None:
            activity_log.append(f"Removed: {name} with previous status '{removed_status}'")
            return removed_status
        else:
            activity_log.append(f"Removal failed: {name} not found")
            return None

    def get_activity_log():
        return activity_log.copy()

    def get_attendee_count():
        return len(attendees)

    return {
        'register': register_attendee,
        'check': check_attendee,
        'remove': remove_attendee,
