def queue_management_system():
    # Initialize a deque with maxlen of 10
    customer_queue = deque(maxlen=10)

    def add_customer(customer_id):
        if len(customer_queue) >= 10:
            raise ValueError("Queue is full. Cannot add more customers.")
        customer_queue.append(customer_id)
        return f"Customer {customer_id} added to the queue."

    def add_priority_customer(customer_id):
        if len(customer_queue) >= 10:
            raise ValueError("Queue is full. Cannot add more customers.")
        customer_queue.appendleft(customer_id)
        return f"Customer {customer_id} added to the front of the queue."

    def serve_customer():
        if not customer_queue:
            raise ValueError("Queue is empty. No customers to serve.")
        customer_id = customer_queue.popleft()
        return f"Now serving customer {customer_id}."

    def remove_customer(customer_id):
        if customer_id not in customer_queue:
            raise ValueError(f"Customer {customer_id} not found in the queue.")
        customer_queue.remove(customer_id)
        return f"Customer {customer_id} removed from the queue."

    def view_queue():
        return list(customer_queue)

    return {
        "add_customer": add_customer,
        "add_priority_customer": add_priority_customer,
        "serve_customer": serve_customer,
        "remove_customer": remove_customer,
        "view_queue": view_queue
