#include <queue>
#include <mutex>
#include <stdexcept>

struct Speaker {
    std::string name;
    double rating;

    Speaker(const std::string& n, double r) : name(n), rating(r) {}

    bool operator<(const Speaker& other) const {
        return rating < other.rating; // Max heap based on rating
    }
};

class ConferenceScheduler {
private:
    std::priority_queue<Speaker> speakers;
    std::priority_queue<Speaker, std::vector<Speaker>, std::greater<Speaker>> minHeap; // For tracking lowest rated
    mutable std::mutex queueMutex;
    static const size_t MAX_SPEAKERS = 20;

public:
    void push(const Speaker& speaker) {
        std::lock_guard<std::mutex> lock(queueMutex);

        if (speakers.size() < MAX_SPEAKERS) {
            speakers.push(speaker);
            minHeap.push(speaker);
        } else {
            // Check if new speaker has higher rating than lowest
            if (speaker.rating > minHeap.top().rating) {
                // Remove lowest rated speaker
                Speaker lowest = minHeap.top();
                minHeap.pop();

                // Rebuild priority queues without the lowest speaker
                std::vector<Speaker> temp;
                while (!speakers.empty()) {
                    Speaker current = speakers.top();
                    speakers.pop();
                    if (!(current.name == lowest.name && current.rating == lowest.rating)) {
                        temp.push_back(current);
                    }
                }

                // Add new speaker
                temp.push_back(speaker);

                // Rebuild both queues
                for (const auto& s : temp) {
                    speakers.push(s);
                    minHeap.push(s);
                }
            }
        }
    }

    Speaker pop() {
        std::lock_guard<std::mutex> lock(queueMutex);

        if (speakers.empty()) {
            throw std::runtime_error("No speakers available in the queue");
        }

        Speaker nextSpeaker = speakers.top();
        speakers.pop();

        // Remove from minHeap as well
        std::vector<Speaker> temp;
        while (!minHeap.empty()) {
            Speaker current = minHeap.top();
            minHeap.pop();
            if (!(current.name == nextSpeaker.name && current.rating == nextSpeaker.rating)) {
                temp.push_back(current);
            }
        }

        for (const auto& s : temp) {
            minHeap.push(s);
        }

        return nextSpeaker;
    }

    Speaker top() const {
        std::lock_guard<std::mutex> lock(queueMutex);

        if (speakers.empty()) {
            throw std::runtime_error("No speakers available in the queue");
        }

        return speakers.top();
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(queueMutex);
        return speakers.empty();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(queueMutex);
        return speakers.size();
    }
};
