import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class InventorySystem {
    private final Map<String, Product> inventory;
    private final int CAPACITY = 100;
    private final LinkedList<String> updateOrder;

    public InventorySystem() {
        inventory = new HashMap<>();
        updateOrder = new LinkedList<>();
    }

    public synchronized void addOrUpdateProduct(String productId, String name, int quantity, double price) {
        if (inventory.containsKey(productId)) {
            Product product = inventory.get(productId);
            product.setQuantity(quantity);
            product.setPrice(price);

            // Move to end of update order (most recently updated)
            updateOrder.remove(productId);
            updateOrder.add(productId);
        } else {
            // Check if capacity reached
            if (inventory.size() >= CAPACITY) {
                // Remove least recently updated item
                String oldestProductId = updateOrder.removeFirst();
                inventory.remove(oldestProductId);
            }

            // Add new product
            Product newProduct = new Product(productId, name, quantity, price);
            inventory.put(productId, newProduct);
            updateOrder.add(productId);
        }
    }

    public synchronized Product getProduct(String productId) {
        return inventory.get(productId);
    }

    public synchronized boolean removeProduct(String productId) {
        if (inventory.containsKey(productId)) {
            inventory.remove(productId);
            updateOrder.remove(productId);
            return true;
        }
        return false;
    }

    public synchronized int getInventorySize() {
        return inventory.size();
    }

    static class Product {
        private String id;
        private String name;
        private int quantity;
        private double price;

        public Product(String id, String name, int quantity, double price) {
            this.id = id;
            this.name = name;
            this.quantity = quantity;
            this.price = price;
        }

        public String getId() {
            return id;
        }

        public String getName() {
            return name;
        }

        public int getQuantity() {
            return quantity;
        }

        public void setQuantity(int quantity) {
            this.quantity = quantity;
        }

        public double getPrice() {
            return price;
        }

        public void setPrice(double price) {
            this.price = price;
        }
    }
}
