package main

import (
	"container/list"
	"errors"
)

type Task struct {
	ID          string
	Description string
	Priority    int
}

func ManageTasks(tasks *list.List, newTask Task, action string, position int) error {
	switch action {
	case "insert":
		if position < 0 {
			return errors.New("invalid position for insertion")
		}

		if position == 0 {
			tasks.PushFront(newTask)
			return nil
		}

		current := tasks.Front()
		currentPos := 0

		for current != nil && currentPos < position {
			current = current.Next()
			currentPos++
		}

		if current == nil {
			tasks.PushBack(newTask)
		} else {
			tasks.InsertBefore(newTask, current)
		}
		return nil

	case "remove":
		if position < 0 || tasks.Len() == 0 {
			return errors.New("invalid position for removal")
		}

		current := tasks.Front()
		currentPos := 0

		for current != nil && currentPos < position {
			current = current.Next()
			currentPos++
		}

		if current == nil {
			return errors.New("position exceeds list length")
		}

		tasks.Remove(current)
		return nil

	default:
		return errors.New("unknown action, please use 'insert' or 'remove'")
	}
}
