	}
}

func (ts *TaskStack) Push(task Task) {
	if len(ts.tasks) >= ts.maxCapacity {
		// Remove the oldest task (bottom of the stack)
		ts.tasks = ts.tasks[1:]
	}
	ts.tasks = append(ts.tasks, task)
}

func (ts *TaskStack) Pop() (Task, bool) {
	if len(ts.tasks) == 0 {
		return Task{}, false
	}

	lastIndex := len(ts.tasks) - 1
	task := ts.tasks[lastIndex]
	ts.tasks = ts.tasks[:lastIndex]
	return task, true
}

func (ts *TaskStack) Peek() (Task, bool) {
	if len(ts.tasks) == 0 {
		return Task{}, false
	}

	return ts.tasks[len(ts.tasks)-1], true
}

func (ts *TaskStack) Size() int {
	return len(ts.tasks)
}

func (ts *TaskStack) IsEmpty() bool {
	return len(ts.tasks) == 0
}
