func processStudentScores(scores []float64, newScores ...float64) ([]float64, float64, float64, float64, error) {
    const maxCapacity = 100

    // Add new scores while respecting capacity limit
    for _, score := range newScores {
        if len(scores) >= maxCapacity {
            return scores, 0, 0, 0, fmt.Errorf("cannot add more scores: maximum capacity of %d reached", maxCapacity)
        }
        scores = append(scores, score)
    }

    if len(scores) == 0 {
        return scores, 0, 0, 0, fmt.Errorf("no scores to process")
    }

    // Initialize with first score
    highest := scores[0]
    lowest := scores[0]
    sum := scores[0]

    // Process remaining scores
    for i := 1; i < len(scores); i++ {
        score := scores[i]
        sum += score

        if score > highest {
            highest = score
        }

        if score < lowest {
            lowest = score
        }
    }

    average := sum / float64(len(scores))

    return scores, highest, lowest, average, nil
}
