import java.util.*;

public class MaxNonConsecutiveSum {

    public static int maxNonConsecutiveSum(int[] arr) {
        if (arr == null || arr.length == 0) return 0;
        if (arr.length == 1) return Math.max(0, arr[0]);

        Map<Integer, Integer> cache = new HashMap<>();
        Stack<Integer> usedIndices = new Stack<>();

        return solve(arr, 0, cache, usedIndices);
    }

    private static int solve(int[] arr, int index, Map<Integer, Integer> cache, Stack<Integer> usedIndices) {
        if (index >= arr.length) return 0;

        if (cache.containsKey(index)) {
            return cache.get(index);
        }

        int exclude = solve(arr, index + 1, cache, usedIndices);

        usedIndices.push(index);
        int include = arr[index] + solve(arr, index + 2, cache, usedIndices);
        usedIndices.pop();

        int result = Math.max(include, exclude);

        if (cache.size() < 10) {
            cache.put(index, result);
        }

        if (result == include) {
            usedIndices.push(index);
        }

        return result;
    }
}
