public int maxSumNonAdjacent(int[] nums) {
    if (nums == null || nums.length == 0) return 0;
    if (nums.length == 1) return Math.max(nums[0], 0);

    HashMap<Integer, Integer> memo = new HashMap<>(10);
    Stack<Integer> usedIndices = new Stack<>();

    int result = maxSumHelper(nums, 0, memo, usedIndices);

    return result;
}

private int maxSumHelper(int[] nums, int index, HashMap<Integer, Integer> memo, Stack<Integer> usedIndices) {
    if (index >= nums.length) return 0;

    if (memo.containsKey(index)) return memo.get(index);

    // Skip current element
    int skip = maxSumHelper(nums, index + 1, memo, usedIndices);

    // Take current element
    int take = nums[index] + maxSumHelper(nums, index + 2, memo, usedIndices);

    if (take > skip) {
        if (usedIndices.size() < 5) {
            usedIndices.push(index);
        }
    }

    int maxSum = Math.max(skip, take);

    // Ensure map doesn't exceed 10 entries
    if (memo.size() < 10) {
        memo.put(index, maxSum);
    }

    return maxSum;
}
