        if (!following.containsKey(user)) {
            return new ArrayList<>();
        }

        Map<String, Integer> mutualConnectionCount = new HashMap<>();
        Set<String> userFollowing = following.get(user);

        // For each person the user follows
        for (String connection : userFollowing) {
            // Get who they follow
            if (following.containsKey(connection)) {
                Set<String> connectionFollowing = following.get(connection);
                for (String potentialFriend : connectionFollowing) {
                    // Don't suggest the user or people the user already follows
                    if (!potentialFriend.equals(user) && !userFollowing.contains(potentialFriend)) {
                        if (!mutualConnectionCount.containsKey(potentialFriend)) {
                            mutualConnectionCount.put(potentialFriend, 0);
                        }
