            return null;
        }

        String latestCommon = null;
        long latestTime = 0;

        for (String follower : followers1) {
            if (followers2.contains(follower)) {
                long followTime = getLatestFollowTime(follower, user1, user2);
                if (followTime > latestTime) {
                    latestTime = followTime;
                    latestCommon = follower;
