                for (int i = followEvents.size() - 1; i >= 0; i--) {
                    FollowEvent event = followEvents.get(i);
                    if (!event.isUnfollow && event.follower.equals(follower) && 
                        (event.followed.equals(user1) || event.followed.equals(user2)) && 
                        event.timestamp > latestTimestamp) {
                        latestCommonFollower = follower;
                        latestTimestamp = event.timestamp;
                        break;
                    }
                }
            }
