public static int maxSubArraySum(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    Stack<Integer> stack = new Stack<>();
    int currentSum = 0;
    int maxSum = Integer.MIN_VALUE;

    for (int num : nums) {
        stack.push(num);
        currentSum += num;

        maxSum = Math.max(maxSum, currentSum);

        if (currentSum < 0) {
            currentSum = 0;
            stack.clear();
        }
    }

    return maxSum;
}
