from typing import Dict, Optional, Any

class ThreadSafeReservationManager:
    def __init__(self):
        self.lock = threading.Lock()
        self.reservations: Dict[str, Dict[str, Any]] = {
            f"Guest_{i+1}": {
                "room_number": 100 + i,
                "check_in_date": f"2024-01-{i+1:02d}",
                "nights": random.randint(1, 7)
            }
            for i in range(10)
        }

    def check_availability(self, guest_name: str) -> Optional[Dict[str, Any]]:
        with self.lock:
            return self.reservations.get(guest_name)

    def check_in_guest(self, guest_name: str) -> Optional[Dict[str, Any]]:
        with self.lock:
            reservation = self.reservations.pop(guest_name, None)
            if reservation:
                # Add new reservation to maintain exactly 10
                new_guest_id = len([k for k in self.reservations.keys() if k.startswith("Guest_")]) + 1
                new_guest_name = f"Guest_{new_guest_id + 10}"
                self.reservations[new_guest_name] = {
                    "room_number": 100 + new_guest_id + 10,
                    "check_in_date": "2024-02-01",
                    "nights": random.randint(1, 7)
                }
            return reservation

    def get_reservation_count(self) -> int:
        with self.lock:
            return len(self.reservations)

def automate_guest_checkin():
    manager = ThreadSafeReservationManager()

    def check_availability_by_name(guest_name: str) -> Optional[Dict[str, Any]]:
        return manager.check_availability(guest_name)

    def process_checkin(guest_name: str) -> Optional[Dict[str, Any]]:
        return manager.check_in_guest(guest_name)

    return check_availability_by_name, process_checkin, manager
