import java.util.Collections;
import java.util.PriorityQueue;
import java.util.Comparator;
import java.time.LocalDateTime;

public class EventScheduler {

    private PriorityQueue<Event> eventQueue;

    public EventScheduler() {
        // Initialize with reverse order comparator to get most recent events first
        this.eventQueue = new PriorityQueue<>(Comparator.comparing(Event::getTimestamp).reversed());
    }

    public void addEvent(Event event) {
        eventQueue.offer(event);
    }

    public Event getMostRecentEvent() throws NoEventsRemainingException {
        if (eventQueue.isEmpty()) {
            throw new NoEventsRemainingException("Error: No events left in the queue");
        }
        return eventQueue.poll();
    }

    // Custom exception for empty queue
    public static class NoEventsRemainingException extends Exception {
        public NoEventsRemainingException(String message) {
            super(message);
        }
    }

    // Event class
    public static class Event {
        private String name;
        private LocalDateTime timestamp;

        public Event(String name, LocalDateTime timestamp) {
            this.name = name;
            this.timestamp = timestamp;
        }

        public String getName() {
            return name;
        }

        public LocalDateTime getTimestamp() {
            return timestamp;
        }

        @Override
        public String toString() {
            return name + " at " + timestamp;
        }
    }
}
