        // Initialize queue with reverse chronological order (most recent first)
        eventQueue = new PriorityQueue<>(MAX_QUEUE_SIZE, 
            Comparator.comparing(Event::getTimestamp).reversed());
    }

    public void addEvent(Event event) {
        eventQueue.offer(event);

        // Remove oldest event if queue exceeds maximum size
        if (eventQueue.size() > MAX_QUEUE_SIZE) {
            // Create temporary queue to find and remove oldest event
            PriorityQueue<Event> tempQueue = new PriorityQueue<>(
                Comparator.comparing(Event::getTimestamp));
            tempQueue.addAll(eventQueue);
            Event oldest = tempQueue.poll();
            eventQueue.remove(oldest);
        }
    }

    public Event getMostRecentEvent() {
        if (eventQueue.isEmpty()) {
            throw new IllegalStateException("No events available in the queue");
        }
        return eventQueue.poll();
    }

    public static class Event {
        private String name;
        private long timestamp;

        public Event(String name, long timestamp) {
            this.name = name;
            this.timestamp = timestamp;
        }

        public String getName() {
            return name;
        }

        public long getTimestamp() {
            return timestamp;
        }
    }
}
