import java.util.Comparator;
import java.util.PriorityQueue;

public class EventScheduler {
    private final int MAX_SIZE = 10;
    private PriorityQueue<Event> eventQueue;

    public EventScheduler() {
        // Using reverse order to get most recent events first
        eventQueue = new PriorityQueue<>(MAX_SIZE, Comparator.comparing(Event::getTimestamp).reversed());
    }

    public void addEvent(Event event) {
        eventQueue.offer(event);
        if (eventQueue.size() > MAX_SIZE) {
            // Find and remove the oldest event (lowest priority)
            Event oldest = findOldestEvent();
            eventQueue.remove(oldest);
        }
    }

    public Event getRecentEvent() {
        if (eventQueue.isEmpty()) {
            throw new IllegalStateException("No events available in the queue");
        }
        return eventQueue.poll();
    }

    public Event peekRecentEvent() {
        if (eventQueue.isEmpty()) {
            throw new IllegalStateException("No events available in the queue");
        }
        return eventQueue.peek();
    }

    private Event findOldestEvent() {
        Event oldest = null;
        for (Event event : eventQueue) {
            if (oldest == null || event.getTimestamp() < oldest.getTimestamp()) {
                oldest = event;
            }
        }
        return oldest;
    }

    public static class Event {
        private long timestamp;
        private String description;

        public Event(long timestamp, String description) {
            this.timestamp = timestamp;
            this.description = description;
        }

        public long getTimestamp() {
            return timestamp;
        }

        public String getDescription() {
            return description;
        }
    }
}
