import java.util.*;
import java.util.concurrent.locks.ReentrantLock;

public class EventScheduler {
    private final PriorityQueue<Event> eventQueue;
    private final ReentrantLock lock;
    private static final int MAX_CAPACITY = 10;

    public EventScheduler() {
        this.eventQueue = new PriorityQueue<>(Collections.reverseOrder());
        this.lock = new ReentrantLock();
    }

    public static class Event implements Comparable<Event> {
        private final String name;
        private final long timestamp;

        public Event(String name) {
            this.name = name;
            this.timestamp = System.currentTimeMillis();
        }

        @Override
        public int compareTo(Event other) {
            return Long.compare(this.timestamp, other.timestamp);
        }

        public String getName() {
            return name;
        }

        public long getTimestamp() {
            return timestamp;
        }

        @Override
        public String toString() {
            return "Event{name='" + name + "', timestamp=" + timestamp + "}";
        }
    }

    public void offer(Event event) {
        lock.lock();
        try {
            if (eventQueue.size() >= MAX_CAPACITY) {
                Event oldest = Collections.min(eventQueue);
                eventQueue.remove(oldest);
            }
            eventQueue.offer(event);
        } finally {
            lock.unlock();
        }
    }

    public Event poll() {
        lock.lock();
        try {
            Event event = eventQueue.poll();
            if (event == null) {
                throw new RuntimeException("No events are left in the queue");
            }
            return event;
        } finally {
            lock.unlock();
        }
    }

    public Event peek() {
        lock.lock();
        try {
            Event event = eventQueue.peek();
            if (event == null) {
                throw new RuntimeException("No events are left in the queue");
            }
            return event;
        } finally {
            lock.unlock();
        }
    }

    public int size() {
        lock.lock();
        try {
            return eventQueue.size();
        } finally {
            lock.unlock();
        }
    }
}
