        if (patientStack.size() >= 30) {
            std::cout << "Queue is full. Cannot add more patients." << std::endl;
            return;
        }
        patientStack.push(patientID);
        std::cout << "Patient " << patientID << " added to queue." << std::endl;
    }
    else if (operation == 's' || operation == 'S') { // Serve patient
        if (patientStack.empty()) {
            std::cout << "No patients in queue." << std::endl;
            return;
        }
        int servedPatient = patientStack.top();
        patientStack.pop();
        std::cout << "Patient " << servedPatient << " served." << std::endl;
    }
