        this.activeSessions = new HashSet<>();
    }

    public boolean addSession(String sessionId) {
        if (activeSessions.size() >= MAX_CAPACITY) {
            System.out.println("[" + LocalDateTime.now().format(formatter) + "] Failed to add session " + sessionId + " - Maximum capacity reached");
            return false;
        }

        boolean added = activeSessions.add(sessionId);
        if (added) {
            System.out.println("[" + LocalDateTime.now().format(formatter) + "] Session added: " + sessionId);
        } else {
            System.out.println("[" + LocalDateTime.now().format(formatter) + "] Session " + sessionId + " already exists");
        }
        return added;
    }

    public boolean removeSession(String sessionId) {
        boolean removed = activeSessions.remove(sessionId);
        if (removed) {
            System.out.println("[" + LocalDateTime.now().format(formatter) + "] Session removed: " + sessionId);
        } else {
            System.out.println("[" + LocalDateTime.now().format(formatter) + "] Session " + sessionId + " not found");
        }
        return removed;
    }

    public int getActiveSessionCount() {
        return activeSessions.size();
    }

    public boolean isSessionActive(String sessionId) {
        return activeSessions.contains(sessionId);
