import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.HashSet;
import java.util.Set;
import java.util.logging.Logger;
import java.util.logging.Level;

public class SessionManager {
    private static final int MAX_SESSIONS = 500;
    private static final Logger LOGGER = Logger.getLogger(SessionManager.class.getName());
    private Set<String> activeSessions = new HashSet<>();
    private DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    public boolean addSession(String sessionId) {
        LOGGER.info("Attempting to add session: " + sessionId);

        if (activeSessions.size() >= MAX_SESSIONS) {
            LOGGER.warning("Session limit reached. Cannot add session: " + sessionId);
            return false;
        }

        if (activeSessions.contains(sessionId)) {
            LOGGER.info("Session already exists: " + sessionId);
            return false;
        }

        boolean added = activeSessions.add(sessionId);
        String timestamp = LocalDateTime.now().format(formatter);
        LOGGER.log(Level.INFO, "Session added at {0}: {1}", new Object[]{timestamp, sessionId});
        return added;
    }

    public boolean removeSession(String sessionId) {
        LOGGER.info("Attempting to remove session: " + sessionId);

        boolean removed = activeSessions.remove(sessionId);
        if (removed) {
            String timestamp = LocalDateTime.now().format(formatter);
            LOGGER.log(Level.INFO, "Session removed at {0}: {1}", new Object[]{timestamp, sessionId});
        } else {
            LOGGER.warning("Session not found for removal: " + sessionId);
        }
        return removed;
    }
}
