use std::collections::BTreeMap;

#[derive(Debug, Clone)]
struct Student {
    name: String,
    age: u32,
    grade: String,
}

struct StudentRoster {
    students: BTreeMap<u32, Student>,
    insertion_order: Vec<u32>,
}

impl StudentRoster {
    fn new() -> Self {
        Self {
            students: BTreeMap::new(),
            insertion_order: Vec::new(),
        }
    }

    fn add_student(&mut self, id: u32, student: Student) {
        if self.students.len() >= 50 {
            if let Some(&oldest_id) = self.insertion_order.first() {
                self.students.remove(&oldest_id);
                self.insertion_order.retain(|&x| x != oldest_id);
            }
        }

        if !self.students.contains_key(&id) {
            self.insertion_order.push(id);
        } else {
            self.insertion_order.retain(|&x| x != id);
            self.insertion_order.push(id);
        }

        self.students.insert(id, student);
    }

    fn remove_student(&mut self, id: u32) -> Result<Student, String> {
        if !self.students.contains_key(&id) {
            return Err(format!("Student with ID {} does not exist", id));
        }

        self.insertion_order.retain(|&x| x != id);
        Ok(self.students.remove(&id).unwrap())
    }

    fn contains_student(&self, id: u32) -> bool {
        self.students.contains_key(&id)
    }

    fn get_student_count(&self) -> usize {
        self.students.len()
    }
}
