use std::collections::HashSet;
use std::time::{SystemTime, UNIX_EPOCH};

pub struct UserAuthManager {
    authorized_users: HashSet<u64>,
    user_last_login: std::collections::HashMap<u64, u64>,
    max_capacity: usize,
}

impl UserAuthManager {
    pub fn new() -> Self {
        Self {
            authorized_users: HashSet::new(),
            user_last_login: std::collections::HashMap::new(),
            max_capacity: 100,
        }
    }

    pub fn register_user(&mut self, user_id: u64) -> bool {
        if self.authorized_users.len() >= self.max_capacity {
            return false;
        }

        let current_time = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        self.user_last_login.insert(user_id, current_time);
        self.authorized_users.insert(user_id)
    }

    pub fn is_authorized(&self, user_id: &u64) -> bool {
        self.authorized_users.contains(user_id)
    }

    pub fn current_capacity(&self) -> usize {
        self.authorized_users.len()
    }

    pub fn remove_user(&mut self, user_id: &u64) -> bool {
        self.user_last_login.remove(user_id);
        self.authorized_users.remove(user_id)
    }

    pub fn update_login(&mut self, user_id: u64) {
        if self.authorized_users.contains(&user_id) {
            let current_time = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs();
            self.user_last_login.insert(user_id, current_time);
        }
    }

    pub fn clear_inactive_users(&mut self) {
        let current_time = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        let thirty_days_seconds = 30 * 24 * 60 * 60;

        let inactive_users: Vec<u64> = self.user_last_login
            .iter()
            .filter(|(_, &last_login)| current_time - last_login > thirty_days_seconds)
            .map(|(&user_id, _)| user_id)
            .collect();

        for user_id in inactive_users {
            self.remove_user(&user_id);
        }
    }
}
