    private TreeMap<String, Book> bookInventory;
    private static final int MAX_CAPACITY = 500;

    public LibraryInventory() {
        bookInventory = new TreeMap<>();
    }

    public boolean addBook(String isbn, Book book) {
        if (isbn == null || book == null) {
            return false;
        }

        if (bookInventory.size() >= MAX_CAPACITY) {
            return false;
        }

        bookInventory.put(isbn, book);
        return true;
    }

    public boolean removeBook(String isbn) {
        if (isbn == null) {
            return false;
        }

        Book removedBook = bookInventory.remove(isbn);
        return removedBook != null;
    }

    public class Book {
        private String title;
        private String author;

        public Book(String title, String author) {
            this.title = title;
            this.author = author;
        }

        // Getters and setters
    }
