        """Add a new task to the system."""
        tasks[task_id] = description
        return f"Task {task_id} added."

    def lower_priority(task_id):
        """Move a task to the end (lowest priority)."""
        if task_id in tasks:
            tasks.move_to_end(task_id)
            return f"Task {task_id} priority lowered."
        return f"Task {task_id} not found."

    def remove_least_urgent():
        """Remove and return the least urgent task."""
        if tasks:
            task_id, description = tasks.popitem()
            return task_id, description
        return None

    def get_all_tasks():
        """Return all tasks in current priority order."""
        return dict(tasks)

    return add_task, lower_priority, remove_least_urgent, get_all_tasks
