use std::collections::BTreeMap;
use std::sync::{Arc, Mutex};

pub fn count_color_frequency(colors: Vec<String>) -> Result<Arc<Mutex<BTreeMap<String, u32>>>, String> {
    if colors.len() > 2500 {
        return Err("Input size exceeds maximum limit of 2500 elements".to_string());
    }

    let color_map = Arc::new(Mutex::new(BTreeMap::new()));

    for color in colors {
        let normalized_color = color.to_lowercase();

        let mut map = color_map.lock().unwrap();

        if map.len() >= 100 && !map.contains_key(&normalized_color) {
            return Err("BTreeMap size limit of 100 items exceeded".to_string());
        }

        let current_count = map.get(&normalized_color).unwrap_or(&0);
        map.insert(normalized_color, current_count + 1);
    }

    Ok(color_map)
}
