class AccountStack {
private:
    std::vector<std::shared_ptr<Account>> accounts;
    static const size_t MAX_SIZE = 300;

public:
    void push(std::shared_ptr<Account> account) {
        if (!account) {
            throw std::invalid_argument("Cannot push null account");
        }
        if (accounts.size() >= MAX_SIZE) {
            throw std::overflow_error("Account stack is full");
        }
        accounts.push_back(account);
        Logger::log("Added account " + std::to_string(account->getAccountNumber()) + " to stack");
    }

    std::shared_ptr<Account> pop() {
        if (accounts.empty()) {
            throw std::underflow_error("Account stack is empty");
        }
        auto account = accounts.back();
        accounts.pop_back();
        Logger::log("Removed account " + std::to_string(account->getAccountNumber()) + " from stack");
        return account;
    }

    std::shared_ptr<Account> top() const {
        if (accounts.empty()) {
            return nullptr;
        }
        return accounts.back();
    }

    bool empty() const {
        return accounts.empty();
    }

    size_t size() const {
        return accounts.size();
    }

    std::shared_ptr<Account> findAccount(int accountNumber) {
        for (auto& account : accounts) {
            if (account && account->getAccountNumber() == accountNumber) {
                return account;
            }
        }
        return nullptr;
    }
};

class BankManager {
private:
    AccountStack accountStack;
    int nextAccountNumber;

public:
    BankManager() : nextAccountNumber(1001) {}

    void createSavingsAccount(const std::string& name, double initialBalance, double interestRate) {
        try {
            auto account = std::make_shared<SavingsAccount>(nextAccountNumber++, name, initialBalance, interestRate);
            accountStack.push(account);
            Logger::log("Created savings account for " + name);
        } catch (const std::exception& e) {
            std::cerr << "Error creating savings account: " << e.what() << std::endl;
        }
    }

    void createCheckingAccount(const std::string& name, double initialBalance, double monthlyFee) {
        try {
            auto account = std::make_shared<CheckingAccount>(nextAccountNumber++, name, initialBalance, monthlyFee);
            accountStack.push(account);
            Logger::log("Created checking account for " + name);
        } catch (const std::exception& e) {
            std::cerr << "Error creating checking account: " << e.what() << std::endl;
        }
    }

    void createJointAccount(const std::string& name1, const std::string& name2, double initialBalance, double interestRate) {
        try {
            auto account = std::make_shared<JointAccount>(nextAccountNumber++, name1, name2, initialBalance, interestRate);
            accountStack.push(account);
            Logger::log("Created joint account for " + name1 + " and " + name2);
        } catch (const std::exception& e) {
            std::cerr << "Error creating joint account: " << e.what() << std::endl;
        }
    }

    void deposit(int accountNumber, double amount) {
        try {
            auto account = accountStack.findAccount(accountNumber);
            if (!account) {
                throw std::runtime_error("Account not found");
            }
            account->deposit(amount);
        } catch (const std::exception& e) {
            std::cerr << "Error during deposit: " << e.what() << std::endl;
        }
    }

    void withdraw(int accountNumber, double amount) {
        try {
            auto account = accountStack.findAccount(accountNumber);
            if (!account) {
                throw std::runtime_error("Account not found");
            }
            account->withdraw(amount);
        } catch (const std::exception& e) {
            std::cerr << "Error during withdrawal: " << e.what() << std::endl;
        }
    }

    void displayAccount(int accountNumber) {
        auto account = accountStack.findAccount(accountNumber);
        if (account) {
            account->displayInfo();
            std::cout << "Interest: $" << std::fixed << std::setprecision(2) 
                      << account->calculateInterest() << std::endl;
        } else {
            std::cout << "Account not found." << std::endl;
        }
    }

    void displayAllAccounts() {
        std::cout << "\n=== All Accounts ===" << std::endl;
        AccountStack tempStack = accountStack;
        std::vector<std::shared_ptr<Account>> allAccounts;

        while (!tempStack.empty()) {
            allAccounts.push_back(tempStack.pop());
        }

        for (auto it = allAccounts.rbegin(); it != allAccounts.rend(); ++it) {
            if (*it) {
                (*it)->displayInfo();
                std::cout << "Interest: $" << std::fixed << std::setprecision(2) 
                          << (*it)->calculateInterest() << std::endl;
                std::cout << "------------------------" << std::endl;
            }
        }
    }

    size_t getAccountCount() const {
        return accountStack.size();
    }
};

int main() {
    BankManager bank;

    try {
        // Create different types of accounts
        bank.createSavingsAccount("John Doe", 1000.0, 2.5);
        bank.createCheckingAccount("Jane Smith", 500.0, 10.0);
        bank.createJointAccount("Bob Johnson", "Alice Johnson", 2000.0, 3.0);

        // Perform operations
        bank.deposit(1001, 250.0);
        bank.withdraw(1001, 100.0);
        bank.deposit(1002, 300.0);

        // Try illegal operation
        bank.withdraw(1002, 1000.0); // Should fail - insufficient funds

        // Display accounts
        bank.displayAllAccounts();

        std::cout << "\nTotal accounts: " << bank.getAccountCount() << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Unexpected error in main: " << e.what() << std::endl;
    }

    return 0;
}
