class OverdraftException : public std::runtime_error {
public:
    OverdraftException(const std::string& message) : std::runtime_error(message) {}
};

class InsufficientFundsException : public std::runtime_error {
public:
    InsufficientFundsException(const std::string& message) : std::runtime_error(message) {}
};

class Account {
protected:
    std::string accountNumber;
    double balance;
    static Logger logger;

public:
    Account(const std::string& accNum, double initialBalance) 
        : accountNumber(accNum), balance(initialBalance) {
        logger.log("Account created: " + accountNumber + " with balance: $" + std::to_string(balance));
    }

    virtual ~Account() = default;

    virtual double calculateInterest() = 0;
    virtual void withdraw(double amount) = 0;
    virtual void deposit(double amount) {
        if (amount <= 0) {
            throw std::invalid_argument("Deposit amount must be positive");
        }
        balance += amount;
        logger.log("Deposit: $" + std::to_string(amount) + " to account " + accountNumber);
    }

    virtual std::string getAccountType() const = 0;

    double getBalance() const { return balance; }
    std::string getAccountNumber() const { return accountNumber; }
};

Logger Account::logger;

class SavingsAccount : public Account {
private:
    static constexpr double INTEREST_RATE = 0.025;

public:
    SavingsAccount(const std::string& accNum, double initialBalance) 
        : Account(accNum, initialBalance) {}

    double calculateInterest() override {
        double interest = balance * INTEREST_RATE;
        logger.log("Interest calculated for savings account " + accountNumber + ": $" + std::to_string(interest));
        return interest;
    }

    void withdraw(double amount) override {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (amount > balance) {
            throw InsufficientFundsException("Insufficient funds in savings account " + accountNumber);
        }
        balance -= amount;
        logger.log("Withdrawal: $" + std::to_string(amount) + " from savings account " + accountNumber);
    }

    std::string getAccountType() const override {
        return "Savings";
    }
};

class CheckingAccount : public Account {
private:
    static constexpr double INTEREST_RATE = 0.01;
    static constexpr double OVERDRAFT_LIMIT = 500.0;

public:
    CheckingAccount(const std::string& accNum, double initialBalance) 
        : Account(accNum, initialBalance) {}

    double calculateInterest() override {
        double interest = balance * INTEREST_RATE;
        logger.log("Interest calculated for checking account " + accountNumber + ": $" + std::to_string(interest));
        return interest;
    }

    void withdraw(double amount) override {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (balance - amount < -OVERDRAFT_LIMIT) {
            throw OverdraftException("Overdraft limit exceeded for checking account " + accountNumber);
        }
        balance -= amount;
        logger.log("Withdrawal: $" + std::to_string(amount) + " from checking account " + accountNumber);

        if (balance < 0) {
            logger.log("Account " + accountNumber + " is now overdrawn by $" + std::to_string(-balance));
        }
    }

    std::string getAccountType() const override {
        return "Checking";
    }
};

class JointAccount : public Account {
private:
    static constexpr double INTEREST_RATE = 0.015;
    std::string secondaryHolder;

public:
    JointAccount(const std::string& accNum, double initialBalance, const std::string& secondHolder) 
        : Account(accNum, initialBalance), secondaryHolder(secondHolder) {
        logger.log("Joint account created with secondary holder: " + secondaryHolder);
    }

    double calculateInterest() override {
        double interest = balance * INTEREST_RATE;
        logger.log("Interest calculated for joint account " + accountNumber + ": $" + std::to_string(interest));
        return interest;
    }

    void withdraw(double amount) override {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (amount > balance) {
            throw InsufficientFundsException("Insufficient funds in joint account " + accountNumber);
        }
        balance -= amount;
        logger.log("Withdrawal: $" + std::to_string(amount) + " from joint account " + accountNumber);
    }

    std::string getAccountType() const override {
        return "Joint";
    }

    std::string getSecondaryHolder() const { return secondaryHolder; }
};

class BankAccountStack {
private:
    std::stack<std::shared_ptr<Account>> accountStack;
    static constexpr size_t MAX_CAPACITY = 300;
    static Logger logger;

public:
    void push(std::shared_ptr<Account> account) {
        if (account == nullptr) {
            throw std::invalid_argument("Cannot push null account pointer");
        }

        if (accountStack.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Account stack has reached maximum capacity of " + std::to_string(MAX_CAPACITY));
        }

        accountStack.push(account);
        logger.log("Account pushed to stack: " + account->getAccountNumber() + 
                  " (" + account->getAccountType() + ")");
    }

    std::shared_ptr<Account> pop() {
        if (accountStack.empty()) {
            throw std::underflow_error("Cannot pop from empty account stack");
        }

        auto account = accountStack.top();
        accountStack.pop();

        if (account != nullptr) {
            logger.log("Account popped from stack: " + account->getAccountNumber() + 
                      " (" + account->getAccountType() + ")");
        }

        return account;
    }

    size_t size() const {
        return accountStack.size();
    }

    bool empty() const {
        return accountStack.empty();
    }

    bool full() const {
        return accountStack.size() >= MAX_CAPACITY;
    }
};

