        auto joint = std::make_shared<JointAccount>("JNT001", 2000.0, "Jane Doe");

        bankStack.push(savings);
        bankStack.push(checking);
        bankStack.push(joint);

        while (!bankStack.empty()) {
            auto account = bankStack.pop();

            if (account != nullptr) {
