class AccountStack {
private:
    std::stack<std::shared_ptr<Account>> accounts;
    mutable std::mutex stackMutex;
    static constexpr size_t MAX_ACCOUNTS = 300;

public:
    void push(std::shared_ptr<Account> account) {
        if (!account) {
            throw std::invalid_argument("Cannot push null account pointer");
        }

        std::lock_guard<std::mutex> lock(stackMutex);
        if (accounts.size() >= MAX_ACCOUNTS) {
            Logger::log("Attempt to exceed maximum account limit of " + std::to_string(MAX_ACCOUNTS));
            throw StackFullException();
        }

        accounts.push(account);
        Logger::log("Account " + std::to_string(account->getId()) + " pushed to stack. Stack size: " + 
                   std::to_string(accounts.size()));
    }

    std::shared_ptr<Account> pop() {
        std::lock_guard<std::mutex> lock(stackMutex);
        if (accounts.empty()) {
            Logger::log("Attempt to pop from empty account stack");
            return nullptr;
        }

        auto account = accounts.top();
        accounts.pop();
        Logger::log("Account " + std::to_string(account->getId()) + " popped from stack. Stack size: " + 
                   std::to_string(accounts.size()));
        return account;
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(stackMutex);
        return accounts.size();
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(stackMutex);
        return accounts.empty();
    }

    void saveToFile(const std::string& filename) const {
        std::lock_guard<std::mutex> lock(stackMutex);
        std::ofstream file(filename);
        if (!file.is_open()) {
            throw std::runtime_error("Cannot open file for writing: " + filename);
        }

        std::stack<std::shared_ptr<Account>> tempStack = accounts;
        std::vector<std::string> accountData;

        while (!tempStack.empty()) {
            auto account = tempStack.top();
            tempStack.pop();
            if (account) {
                accountData.push_back(account->serialize());
            }
        }

        for (auto it = accountData.rbegin(); it != accountData.rend(); ++it) {
            file << *it << std::endl;
        }

        file.close();
        Logger::log("Account stack saved to file: " + filename + " (" + std::to_string(accounts.size()) + " accounts)");
    }

    void loadFromFile(const std::string& filename) {
        std::ifstream file(filename);
        if (!file.is_open()) {
            Logger::log("Cannot open file for reading: " + filename + " (file may not exist)");
            return;
        }

        std::lock_guard<std::mutex> lock(stackMutex);
        std::string line;
        while (std::getline(file, line) && accounts.size() < MAX_ACCOUNTS) {
            size_t pos1 = line.find(',');
            size_t pos2 = line.find(',', pos1 + 1);
            size_t pos3 = line.find(',', pos2 + 1);

            if (pos1 != std::string::npos && pos2 != std::string::npos) {
                std::string type = line.substr(0, pos1);
                int id = std::stoi(line.substr(pos1 + 1, pos2 - pos1 - 1));
                double balance = std::stod(line.substr(pos2 + 1, pos3 - pos2 - 1));

                std::shared_ptr<Account> account;
                if (type == "SAVINGS") {
                    account = std::make_shared<SavingsAccount>(id, balance);
                } else if (type == "CHECKING") {
                    account = std::make_shared<CheckingAccount>(id, balance);
                } else if (type == "JOINT" && pos3 != std::string::npos) {
                    std::string secondOwner = line.substr(pos3 + 1);
                    account = std::make_shared<JointAccount>(id, balance, secondOwner);
                }

                if (account) {
                    accounts.push(account);
                }
            }
        }

        file.close();
        Logger::log("Account stack loaded from file: " + filename + " (" + std::to_string(accounts.size()) + " accounts)");
    }
};

class BankManager {
private:
    AccountStack accountStack;
    std::mutex managerMutex;

public:
    BankManager() {
        Logger::init();
        accountStack.loadFromFile("accounts.dat");
    }

    ~BankManager() {
        try {
            accountStack.saveToFile("accounts.dat");
        } catch (const std::exception& e) {
            Logger::log("Error saving accounts on exit: " + std::string(e.what()));
        }
        Logger::close();
    }

    void createSavingsAccount(int id, double initialBalance) {
        try {
            auto account = std::make_shared<SavingsAccount>(id, initialBalance);
            accountStack.push(account);
        } catch (const std::exception& e) {
            Logger::log("Failed to create savings account: " + std::string(e.what()));
            throw;
        }
    }

    void createCheckingAccount(int id, double initialBalance) {
        try {
            auto account = std::make_shared<CheckingAccount>(id, initialBalance);
            accountStack.push(account);
        } catch (const std::exception& e) {
            Logger::log("Failed to create checking account: " + std::string(e.what()));
            throw;
        }
    }

    void createJointAccount(int id, double initialBalance, const std::string& secondOwner) {
        try {
            auto account = std::make_shared<JointAccount>(id, initialBalance, secondOwner);
            accountStack.push(account);
        } catch (const std::exception& e) {
            Logger::log("Failed to create joint account: " + std::string(e.what()));
            throw;
        }
    }

    std::shared_ptr<Account> removeLastAccount() {
        return accountStack.pop();
    }

    void performOperation(std::shared_ptr<Account> account, const std::string& operation, double amount = 0) {
        if (!account) {
            Logger::log("Null pointer detected in performOperation");
            throw std::invalid_argument("Account pointer is null");
        }

        try {
            if (operation == "deposit") {
                account->deposit(amount);
            } else if (operation == "withdraw") {
                account->withdraw(amount);
            } else if (operation == "interest") {
                double interest = account->calculateInterest();
                Logger::log("Interest calculated for account " + std::to_string(account->getId()) + 
                           ": $" + std::to_string(interest));
            }
        } catch (const std::exception& e) {
            Logger::log("Operation failed on account " + std::to_string(account->getId()) + 
                       ": " + std::string(e.what()));
            throw;
        }
    }

    size_t getAccountCount() const {
        return accountStack.size();
    }

    void saveAccounts() {
        accountStack.saveToFile("accounts.dat");
    }
};

int main() {
    try {
        BankManager bank;

        // Create various account types
        bank.createSavingsAccount(1001, 1000.0);
        bank.createCheckingAccount(1002, 500.0);
        bank.createJointAccount(1003, 2000.0, "Jane Doe");

        // Simulate concurrent operations
        std::vector<std::thread> threads;

        // Thread 1: Create more accounts
        threads.emplace_back([&bank]() {
            try {
                for (int i = 1004; i <= 1010; ++i) {
                    bank.createSavingsAccount(i, 100.0 * i);
                    std::this_thread::sleep_for(std::chrono::milliseconds(10));
                }
            } catch (const std::exception& e) {
                std::cerr << "Thread 1 error: " << e.what() << std::endl;
            }
        });

        // Thread 2: Perform operations on accounts
        threads.emplace_back([&bank]() {
            try {
                std::this_thread::sleep_for(std::chrono::milliseconds(50));
                auto account = bank.removeLastAccount();
                if (account) {
                    bank.performOperation(account, "deposit", 250.0);
                    bank.performOperation(account, "withdraw", 100.0);
                    bank.performOperation(account, "interest");
                }
            } catch (const std::exception& e) {
                std::cerr << "Thread 2 error: " << e.what() << std::endl;
            }
        });

        // Wait for all threads to complete
        for (auto& thread : threads) {
            thread.join();
        }

        std::cout << "Bank simulation completed. Total accounts: " << bank.getAccountCount() << std::endl;
        std::cout << "Check bank_log.txt for detailed operation logs." << std::endl;

        // Manually save before exit (destructor will also save)
        bank.saveAccounts();

    } catch (const std::exception& e) {
        std::cerr << "Bank simulation error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
