        std::lock_guard<std::mutex> lock(manager_mutex);
        if (!accounts.empty()) {
            int removed_id = accounts.back()->getId();
            accounts.pop_back();
            Logger::log("Account removed from bank system: ID " + std::to_string(removed_id));
        }
