            Logger::log("No existing data file found: " + filename);
            return;
        }

        std::lock_guard<std::mutex> lock(manager_mutex);
        accounts.clear();

        size_t count;
        file >> count;
        file.ignore();

        std::string line;
        while (std::getline(file, line) && accounts.size() < MAX_ACCOUNTS) {
            size_t pos1 = line.find(',');
            size_t pos2 = line.find(',', pos1 + 1);
            size_t pos3 = line.find(',', pos2 + 1);

            if (pos1 == std::string::npos || pos2 == std::string::npos) continue;

            std::string type = line.substr(0, pos1);
            int id = std::stoi(line.substr(pos1 + 1, pos2 - pos1 - 1));

            if (type == "JOINT") {
                size_t pos4 = line.find(',', pos3 + 1);
                if (pos4 == std::string::npos) continue;

                std::string holder1 = line.substr(pos2 + 1, pos3 - pos2 - 1);
                std::string holder2 = line.substr(pos3 + 1, pos4 - pos3 - 1);
                double balance = std::stod(line.substr(pos4 + 1));

                accounts.push_back(std::make_shared<JointAccount>(id, holder1, holder2, balance));
            } else {
                std::string holder = line.substr(pos2 + 1, pos3 - pos2 - 1);
                double balance = std::stod(line.substr(pos3 + 1));

                if (type == "SAVINGS") {
                    accounts.push_back(std::make_shared<SavingsAccount>(id, holder, balance));
                } else if (type == "CHECKING") {
                    accounts.push_back(std::make_shared<CheckingAccount>(id, holder, balance));
                }
            }
        }
        file.close();
        Logger::log("Bank data loaded from file: " + filename);
    }

    size_t getAccountCount() const {
        std::lock_guard<std::mutex> lock(manager_mutex);
        return accounts.size();
    }

    void displayAllAccounts() {
        std::lock_guard<std::mutex> lock(manager_mutex);
        std::cout << "\n=== Bank Account Summary ===" << std::endl;
        for (const auto& account : accounts) {
            if (account) {
                std::cout << "ID: " << account->getId() 
                         << ", Type: " << account->getAccountType()
                         << ", Holder: " << account->getHolder()
                         << ", Balance: $" << account->getBalance()
                         << ", Interest: $" << account->calculateInterest() << std::endl;
            }
        }
        std::cout << "Total Accounts: " << accounts.size() << "/" << MAX_ACCOUNTS << std::endl;
    }
};

int main() {
    Logger::init();
    BankManager bank;

    try {
        // Load existing data
        bank.loadFromFile("bank_data.txt");

        // Create sample accounts
        auto savings = std::make_shared<SavingsAccount>(1001, "John Doe", 1000.0);
        auto checking = std::make_shared<CheckingAccount>(1002, "Jane Smith", 500.0);
        auto joint = std::make_shared<JointAccount>(1003, "Bob Johnson", "Alice Johnson", 2000.0);

