	cs.clients[conn] = username
	cs.clientsMux.Unlock()
}

func (cs *ChatServer) removeClient(conn net.Conn) {
	cs.clientsMux.Lock()
	delete(cs.clients, conn)
	cs.clientsMux.Unlock()
}

func (cs *ChatServer) sendMessage(msg Message) {
	select {
	case cs.messages <- msg:
	default:
		select {
		case <-cs.messages:
			cs.messages <- msg
		default:
		}
	}
}

func (cs *ChatServer) broadcastMessages() {
	for msg := range cs.messages {
		cs.clientsMux.RLock()
		for conn := range cs.clients {
			go func(c net.Conn) {
				fmt.Fprintf(c, "[%s] %s: %s\n", 
					msg.Time.Format("15:04:05"), msg.Username, msg.Content)
			}(conn)
		}
		cs.clientsMux.RUnlock()
	}
}

func (cs *ChatServer) handleClient(conn net.Conn) {
	defer conn.Close()

	fmt.Fprint(conn, "Enter username: ")
	buffer := make([]byte, 1024)
	n, err := conn.Read(buffer)
	if err != nil {
