	}

	username := strings.TrimSpace(string(buffer[:n]))
	cs.addClient(conn, username)
	defer cs.removeClient(conn)

	fmt.Fprintf(conn, "Welcome %s! Start chatting...\n", username)

	for {
		n, err := conn.Read(buffer)
		if err != nil {
			break
		}

