package main

import (
	"bufio"
	"fmt"
	"log"
	"net"
	"strings"
	"sync"
	"time"
)

type Message struct {
	Username  string
	Content   string
	Timestamp time.Time
}

type ChatServer struct {
	clients     map[net.Conn]string
	clientsMux  sync.RWMutex
	messages    chan Message
	broadcast   chan Message
	register    chan net.Conn
	unregister  chan net.Conn
}

func NewChatServer() *ChatServer {
	return &ChatServer{
		clients:    make(map[net.Conn]string),
		messages:   make(chan Message, 200),
		broadcast:  make(chan Message),
		register:   make(chan net.Conn),
		unregister: make(chan net.Conn),
	}
}

func (cs *ChatServer) run() {
	for {
		select {
		case client := <-cs.register:
			cs.clientsMux.Lock()
			cs.clients[client] = ""
			cs.clientsMux.Unlock()
			fmt.Printf("Client connected: %s\n", client.RemoteAddr())

		case client := <-cs.unregister:
			cs.clientsMux.Lock()
			if username, ok := cs.clients[client]; ok {
				delete(cs.clients, client)
				client.Close()
				fmt.Printf("Client disconnected: %s (%s)\n", client.RemoteAddr(), username)
			}
			cs.clientsMux.Unlock()

		case message := <-cs.broadcast:
			select {
			case cs.messages <- message:
				cs.broadcastToClients(message)
			default:
				fmt.Println("Message channel full, dropping message")
			}
		}
	}
}

func (cs *ChatServer) broadcastToClients(message Message) {
	cs.clientsMux.RLock()
	defer cs.clientsMux.RUnlock()

	formattedMessage := fmt.Sprintf("[%s] %s: %s\n",
		message.Timestamp.Format("15:04:05"),
		message.Username,
		message.Content)

	for client := range cs.clients {
		_, err := client.Write([]byte(formattedMessage))
		if err != nil {
			client.Close()
			delete(cs.clients, client)
		}
	}
}

func (cs *ChatServer) handleClient(conn net.Conn) {
	defer func() {
		cs.unregister <- conn
	}()

	cs.register <- conn
	scanner := bufio.NewScanner(conn)

	conn.Write([]byte("Enter your username: "))
	if scanner.Scan() {
		username := strings.TrimSpace(scanner.Text())
		if username == "" {
			username = "Anonymous"
		}

		cs.clientsMux.Lock()
		cs.clients[conn] = username
		cs.clientsMux.Unlock()

		conn.Write([]byte(fmt.Sprintf("Welcome %s! Start typing messages.\n", username)))

		for scanner.Scan() {
			text := strings.TrimSpace(scanner.Text())
			if text == "" {
				continue
			}

			if text == "/quit" {
				break
			}

			message := Message{
				Username:  username,
				Content:   text,
				Timestamp: time.Now(),
			}

			cs.broadcast <- message
		}
	}
}

func (cs *ChatServer) getRecentMessages() []Message {
	var messages []Message

	for {
		select {
		case msg := <-cs.messages:
			messages = append(messages, msg)
		default:
			for _, msg := range messages {
				cs.messages <- msg
			}
			return messages
		}
	}
}

func main() {
	server := NewChatServer()
	go server.run()

	listener, err := net.Listen("tcp", ":8080")
	if err != nil {
		log.Fatal("Error starting server:", err)
	}
	defer listener.Close()

	fmt.Println("Chat server started on :8080")

	for {
		conn, err := listener.Accept()
		if err != nil {
			log.Printf("Error accepting connection: %v", err)
			continue
		}

		go server.handleClient(conn)
	}
}
