use std::collections::BTreeSet;

struct UniqueNumberFilter {
    numbers: BTreeSet<i32>,
    max_capacity: usize,
}

impl UniqueNumberFilter {
    fn new() -> Self {
        Self {
            numbers: BTreeSet::new(),
            max_capacity: 10000,
        }
    }

    fn insert(&mut self, number: i32) -> bool {
        if self.numbers.len() >= self.max_capacity {
            return false;
        }
        self.numbers.insert(number)
    }

    fn contains(&self, number: &i32) -> bool {
        self.numbers.contains(number)
    }

    fn remove(&mut self, number: &i32) -> bool {
        self.numbers.remove(number)
    }

    fn len(&self) -> usize {
        self.numbers.len()
    }

    fn get_sorted_numbers(&self) -> Vec<i32> {
        self.numbers.iter().cloned().collect()
    }
}

fn main() {
    let input_numbers = vec![5, 2, 8, 2, 1, 9, 5, 3, 7, 1, 4, 6];
    let mut filter = UniqueNumberFilter::new();

    for number in input_numbers {
        filter.insert(number);
    }

    println!("Unique numbers in sorted order: {:?}", filter.get_sorted_numbers());
    println!("Contains 5: {}", filter.contains(&5));
    println!("Contains 10: {}", filter.contains(&10));

    filter.remove(&5);
    println!("After removing 5: {:?}", filter.get_sorted_numbers());
