import operator

class LimitedCache:
    def __init__(self, max_size=1000):
        self.cache = defaultdict(lambda: None)
        self.access_order = []
        self.max_size = max_size

    def get(self, key):
        if key in self.cache and self.cache[key] is not None:
            self.access_order.remove(key)
            self.access_order.append(key)
            return self.cache[key]
        return None

    def set(self, key, value):
        if key in self.cache and self.cache[key] is not None:
            self.access_order.remove(key)
        elif len(self.access_order) >= self.max_size:
            oldest = self.access_order.pop(0)
            del self.cache[oldest]

        self.cache[key] = value
        self.access_order.append(key)

class StackBasedEvaluator:
    def __init__(self):
        self.cache = LimitedCache(1000)
        self.operators = {'+': operator.add, '-': operator.sub, '*': operator.mul, '/': operator.truediv}
        self.precedence = {'+': 1, '-': 1, '*': 2, '/': 2}

    def push(self, stack, item):
        stack.append(item)

    def pop(self, stack):
        return stack.pop() if stack else None

    def tokenize(self, expression):
        tokens = []
        i = 0
        while i < len(expression):
            if expression[i].isspace():
                i += 1
            elif expression[i].isdigit() or expression[i] == '.':
                num = ''
                while i < len(expression) and (expression[i].isdigit() or expression[i] == '.'):
                    num += expression[i]
                    i += 1
                tokens.append(float(num))
            else:
                tokens.append(expression[i])
                i += 1
        return tokens

    def infix_to_postfix(self, tokens):
        output = []
        operator_stack = []

        for token in tokens:
            if isinstance(token, (int, float)):
                self.push(output, token)
            elif token == '(':
                self.push(operator_stack, token)
            elif token == ')':
                while operator_stack and operator_stack[-1] != '(':
                    self.push(output, self.pop(operator_stack))
                self.pop(operator_stack)
            elif token in self.operators:
                while (operator_stack and 
                       operator_stack[-1] != '(' and
                       operator_stack[-1] in self.precedence and
                       self.precedence[operator_stack[-1]] >= self.precedence[token]):
                    self.push(output, self.pop(operator_stack))
                self.push(operator_stack, token)

        while operator_stack:
            self.push(output, self.pop(operator_stack))

        return output

    def evaluate_postfix(self, postfix):
        stack = []

        for token in postfix:
            if isinstance(token, (int, float)):
                self.push(stack, token)
            elif token in self.operators:
                b = self.pop(stack)
                a = self.pop(stack)
                result = self.operators[token](a, b)
                self.push(stack, result)

        return self.pop(stack)

    def evaluate(self, expression):
        cached_result = self.cache.get(expression)
        if cached_result is not None:
            return cached_result

        tokens = self.tokenize(expression)
        postfix = self.infix_to_postfix(tokens)
        result = self.evaluate_postfix(postfix)

        self.cache.set(expression, result)
        return result

def evaluate_expression(expression):
    evaluator = StackBasedEvaluator()
    return evaluator.evaluate(expression)
