            return false;
        }
        return sessions.replace(sessionId, System.currentTimeMillis()) != null;
    }

    // Operation 4: Check if session exists
    public boolean sessionExists(String sessionId) {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return false;
        }
        return sessions.containsKey(sessionId);
    }

