    }

    // Operation 6: Get active session count
    public int getActiveSessionCount() {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return -1;
        }
        return sessions.size();
    }

    // Operation 7: Clear all sessions
    public boolean clearAllSessions() {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return false;
        }
        sessions.clear();
        return true;
    }

    // Operation 8: Get all session IDs
    public java.util.Set<String> getAllSessionIds() {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return null;
        }
        return sessions.keySet();
    }

    // Operation 9: Check if session is expired
    public boolean isSessionExpired(String sessionId) {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return false;
        }
        Long timestamp = sessions.get(sessionId);
        if (timestamp == null) return true;
        return (System.currentTimeMillis() - timestamp) > TimeUnit.MINUTES.toMillis(SESSION_TIMEOUT_MINUTES);
    }

    // Operation 10: Remove expired sessions
    public int removeExpiredSessions() {
        if (operationCount.incrementAndGet() > MAX_OPERATIONS) {
            operationCount.decrementAndGet();
            return -1;
        }
        long currentTime = System.currentTimeMillis();
        long timeoutMillis = TimeUnit.MINUTES.toMillis(SESSION_TIMEOUT_MINUTES);
        int removedCount = 0;

        sessions.entrySet().removeIf(entry -> {
            boolean expired = (currentTime - entry.getValue()) > timeoutMillis;
            if (expired) removedCount++;
            return expired;
        });

        return removedCount;
    }

    public void resetOperationCount() {
        operationCount.set(0);
    }

    public void shutdown() {
        scheduler.shutdown();
    }
