        if (sessions.size() >= MAX_ACTIVE_SESSIONS || sessions.size() >= MAX_CAPACITY) {
            return false;
        }
        Long result = sessions.put(sessionId, System.currentTimeMillis());
        operationCount.incrementAndGet();
        return result == null;
    }

    public boolean removeSession(String sessionId) {
        checkOperationLimit();
        Long result = sessions.remove(sessionId);
        operationCount.incrementAndGet();
        return result != null;
    }

