        Long timestamp = sessions.get(sessionId);
        operationCount.incrementAndGet();
        if (timestamp == null) return false;
        return (System.currentTimeMillis() - timestamp) <= TimeUnit.MINUTES.toMillis(SESSION_TIMEOUT_MINUTES);
