    private static final int MAX_ACTIVE_SESSIONS = 10;
    private final ConcurrentHashMap<String, SessionData> sessions;
    private final AtomicInteger activeSessionCount;

    public SessionManager() {
        this.sessions = new ConcurrentHashMap<>(MAX_CAPACITY);
        this.activeSessionCount = new AtomicInteger(0);
    }

    private static class SessionData {
        private final String sessionId;
        private LocalDateTime createdAt;
        private LocalDateTime lastAccessedAt;
        private boolean isActive;
        private String userId;
        private ConcurrentHashMap<String, Object> attributes;

        public SessionData(String sessionId, String userId) {
            this.sessionId = sessionId;
            this.userId = userId;
            this.createdAt = LocalDateTime.now();
            this.lastAccessedAt = LocalDateTime.now();
            this.isActive = true;
            this.attributes = new ConcurrentHashMap<>();
        }
    }

    // Operation 1: Create session
    public boolean createSession(String sessionId, String userId) {
        if (activeSessionCount.get() >= MAX_ACTIVE_SESSIONS || sessions.size() >= MAX_CAPACITY) {
            return false;
        }
        SessionData session = new SessionData(sessionId, userId);
        SessionData existing = sessions.putIfAbsent(sessionId, session);
        if (existing == null) {
            activeSessionCount.incrementAndGet();
            return true;
        }
        return false;
    }

    // Operation 2: Read session
    public SessionData readSession(String sessionId) {
        return sessions.get(sessionId);
    }

    // Operation 3: Update session timestamp
    public boolean updateSessionTimestamp(String sessionId) {
        return sessions.computeIfPresent(sessionId, (key, session) -> {
            session.lastAccessedAt = LocalDateTime.now();
            return session;
        }) != null;
    }

    // Operation 4: Delete session
    public boolean deleteSession(String sessionId) {
        SessionData removed = sessions.remove(sessionId);
        if (removed != null && removed.isActive) {
            activeSessionCount.decrementAndGet();
            return true;
        }
        return false;
    }

    // Operation 5: Check session existence
    public boolean sessionExists(String sessionId) {
        return sessions.containsKey(sessionId);
    }

    // Operation 6: Get session count
    public int getSessionCount() {
        return sessions.size();
    }

    // Operation 7: Get active session count
    public int getActiveSessionCount() {
        return activeSessionCount.get();
    }

    // Operation 8: Expire session
    public boolean expireSession(String sessionId) {
        return sessions.computeIfPresent(sessionId, (key, session) -> {
            if (session.isActive) {
                session.isActive = false;
                activeSessionCount.decrementAndGet();
            }
            return session;
        }) != null;
    }

    // Operation 9: Validate session
    public boolean validateSession(String sessionId, int timeoutMinutes) {
        SessionData session = sessions.get(sessionId);
        if (session == null || !session.isActive) {
            return false;
        }
        return ChronoUnit.MINUTES.between(session.lastAccessedAt, LocalDateTime.now()) <= timeoutMinutes;
    }

    // Operation 10: Clear all sessions
    public void clearAllSessions() {
        sessions.clear();
        activeSessionCount.set(0);
    }

