    // Operation 11: Set session attribute
    public boolean setSessionAttribute(String sessionId, String key, Object value) {
        return sessions.computeIfPresent(sessionId, (id, session) -> {
            session.attributes.put(key, value);
            return session;
        }) != null;
    }

    // Operation 12: Get session attribute
    public Object getSessionAttribute(String sessionId, String key) {
        SessionData session = sessions.get(sessionId);
        return session != null ? session.attributes.get(key) : null;
    }

    // Operation 13: Remove session attribute
    public boolean removeSessionAttribute(String sessionId, String key) {
