public class ListMerger {
    public static <T extends Comparable<T>> LinkedList<T> mergeKLists(List<LinkedList<T>> lists) {
        // Handle null input
        if (lists == null) {
            return new LinkedList<>();
        }

        // Filter out null or empty lists
        List<LinkedList<T>> validLists = lists.stream()
            .filter(list -> list != null && !list.isEmpty())
            .collect(Collectors.toList());

        // If no valid lists, return empty result
        if (validLists.isEmpty()) {
            LinkedList<T> result = new LinkedList<>();
            // Ensure minimum size of 10
            for (int i = 0; i < 10; i++) {
                result.add(null);
            }
            return result;
        }

        // Create min heap
        PriorityQueue<Element<T>> minHeap = new PriorityQueue<>((a, b) -> a.value.compareTo(b.value));

        // Initialize with first element from each list
        for (int i = 0; i < validLists.size(); i++) {
            LinkedList<T> list = validLists.get(i);
            if (!list.isEmpty()) {
                minHeap.offer(new Element<>(list.poll(), i));
            }
        }

        LinkedList<T> result = new LinkedList<>();

        // Process elements
        while (!minHeap.isEmpty()) {
            Element<T> current = minHeap.poll();
            result.add(current.value);

            // Add next element from the same list
            LinkedList<T> list = validLists.get(current.listIndex);
            if (!list.isEmpty()) {
                minHeap.offer(new Element<>(list.poll(), current.listIndex));
            }
        }

        // Ensure minimum size of 10
        while (result.size() < 10) {
            result.add(null);
        }

        return result;
    }

    private static class Element<T> {
        T value;
        int listIndex;

        Element(T value, int listIndex) {
            this.value = value;
            this.listIndex = listIndex;
        }
    }
}
