package main

import (
	"errors"
	"fmt"
)

type GradeRecord struct {
	StudentName string
	Grade       int
}

type GradeStack struct {
	records []GradeRecord
	maxSize int
}

func NewGradeStack(maxSize int) *GradeStack {
	return &GradeStack{
		records: make([]GradeRecord, 0),
		maxSize: maxSize,
	}
}

func (s *GradeStack) Push(name string, grade int) error {
	if name == "" {
		return errors.New("student name cannot be empty")
	}
	if grade < 0 || grade > 100 {
		return errors.New("grade must be between 0 and 100")
	}
	if len(s.records) >= s.maxSize {
		return errors.New("stack is full")
	}

	// Check for duplicate at the top
	if len(s.records) > 0 && s.records[len(s.records)-1].StudentName == name {
		return errors.New("student already exists at the top of the stack")
	}

	s.records = append(s.records, GradeRecord{StudentName: name, Grade: grade})
	return nil
}

func (s *GradeStack) UpdateTop(name string, grade int) error {
	if len(s.records) == 0 {
		return errors.New("stack is empty")
	}
	if grade < 0 || grade > 100 {
		return errors.New("grade must be between 0 and 100")
	}

	top := &s.records[len(s.records)-1]
	if top.StudentName != name {
		return errors.New("student name does not match top record")
	}

	top.Grade = grade
	return nil
}

func (s *GradeStack) Pop() (GradeRecord, error) {
	if len(s.records) == 0 {
		return GradeRecord{}, errors.New("stack is empty")
	}

	top := s.records[len(s.records)-1]
	s.records = s.records[:len(s.records)-1]
	return top, nil
}

func (s *GradeStack) ViewAllGrades() []GradeRecord {
	result := make([]GradeRecord, len(s.records))
	copy(result, s.records)
	return result
}

func main() {
	stack := NewGradeStack(2000)

	// Example usage
	_ = stack.Push("Alice", 95)
	_ = stack.Push("Bob", 87)
	_ = stack.Push("Charlie", 76)

	_ = stack.UpdateTop("Charlie", 80)

	grades := stack.ViewAllGrades()
	for i, record := range grades {
		fmt.Printf("%d. %s: %d\n", i+1, record.StudentName, record.Grade)
	}

	popped, _ := stack.Pop()
	fmt.Printf("Popped: %s with grade %d\n", popped.StudentName, popped.Grade)
}
