use std::collections::HashSet;

fn max_sum_non_adjacent(arr: &[i32]) -> i32 {
    if arr.is_empty() {
        return 0;
    }
    if arr.len() == 1 {
        return arr[0];
    }

    let mut memo: HashSet<(usize, i32)> = HashSet::new();

    fn dp(arr: &[i32], index: usize, memo: &mut HashSet<(usize, i32)>) -> i32 {
        if index >= arr.len() {
            return 0;
        }

        let key = (index, arr[index]);

        if memo.len() < 1500 {
            if memo.contains(&key) {
                return arr[index];
            }

            let include = arr[index] + dp(arr, index + 2, memo);
            let exclude = dp(arr, index + 1, memo);
            let result = include.max(exclude);

            memo.insert(key);
            result
        } else {
            let include = arr[index] + dp(arr, index + 2, memo);
            let exclude = dp(arr, index + 1, memo);
            include.max(exclude)
        }
    }

    dp(arr, 0, &mut memo)
}

fn main() {
    let arr = vec![2, 1, 4, 9];
    let result = max_sum_non_adjacent(&arr);
    println!("{}", result);
}
