// Main reservation system class
class ReservationSystem {
private:
    std::unordered_map<std::string, Airline> airlines;
    std::unordered_map<int, Reservation> reservations;

public:
    bool addAirline(const Airline& airline) {
        if (airlines.find(airline.getCode()) != airlines.end()) {
            return false;
        }
        airlines[airline.getCode()] = airline;
        return true;
    }

    Airline* getAirline(const std::string& airlineCode) {
        auto it = airlines.find(airlineCode);
        if (it != airlines.end()) {
            return &(it->second);
        }
        return nullptr;
    }

    int makeReservation(const std::string& passengerName, 
                        const std::string& airlineCode, 
                        const std::string& flightNumber) {
        // Check if airline exists
        Airline* airline = getAirline(airlineCode);
        if (!airline) {
            throw std::runtime_error("Airline not found");
        }

        // Check if flight exists
        Flight* flight = airline->getFlight(flightNumber);
        if (!flight) {
            throw std::runtime_error("Flight not found");
        }

        // Check if seats are available
        if (flight->getAvailableSeats() <= 0) {
            throw std::runtime_error("No available seats on this flight");
        }

        // Create reservation
        Reservation reservation(passengerName, airlineCode, flightNumber);
        int reservationId = reservation.getReservationId();

        // Add reservation to flight
        if (!flight->addReservation(reservationId)) {
            throw std::runtime_error("Failed to add reservation to flight");
        }

        // Store reservation
        reservations[reservationId] = reservation;
        return reservationId;
    }

    bool cancelReservation(int reservationId) {
        auto it = reservations.find(reservationId);
        if (it == reservations.end() || !it->second.getIsActive()) {
            return false;
        }

        Reservation& reservation = it->second;
        Airline* airline = getAirline(reservation.getAirlineCode());
        if (!airline) {
            return false;
        }

        Flight* flight = airline->getFlight(reservation.getFlightNumber());
        if (!flight) {
            return false;
        }

        if (flight->cancelReservation(reservationId)) {
            reservation.cancel();
            return true;
        }
        return false;
    }

    void displayReservation(int reservationId) const {
        auto it = reservations.find(reservationId);
        if (it != reservations.end()) {
            it->second.displayReservation();
        } else {
            std::cout << "Reservation not found\n";
        }
    }

    void displayAllAirlines() const {
        std::cout << "Available Airlines:\n";
        for (const auto& pair : airlines) {
            std::cout << pair.second.getName() << " (" << pair.second.getCode() << ")\n";
        }
    }
};

int main() {
    ReservationSystem system;

    try {
        // Add airlines
        system.addAirline(Airline("American Airlines", "AA"));
        system.addAirline(Airline("Delta Air Lines", "DL"));
        system.addAirline(Airline("United Airlines", "UA"));

        // Add flights to airlines
        Airline* aa = system.getAirline("AA");
        aa->addFlight(Flight("AA101", "New York", "Los Angeles", "08:00", "11:30", 150));
        aa->addFlight(Flight("AA102", "Los Angeles", "New York", "14:00", "22:30", 150));

        Airline* dl = system.getAirline("DL");
        dl->addFlight(Flight("DL201", "Atlanta", "Miami", "09:15", "11:00", 120));
        dl->addFlight(Flight("DL202", "Miami", "Atlanta", "12:30", "14:15", 120));

        Airline* ua = system.getAirline("UA");
        ua->addFlight(Flight("UA301", "Chicago", "Denver", "10:45", "12:30", 180));
        ua->addFlight(Flight("UA302", "Denver", "Chicago", "15:00", "18:45", 180));

        // Display all airlines
        system.displayAllAirlines();

        // Display flights for an airline
        std::cout << "\nFlights for American Airlines:\n";
        aa->displayFlights();

        // Make reservations
        int res1 = system.makeReservation("John Doe", "AA", "AA101");
        int res2 = system.makeReservation("Jane Smith", "DL", "DL201");
        int res3 = system.makeReservation("Mike Johnson", "UA", "UA301");

        // Display reservations
        std::cout << "\nReservation Details:\n";
        system.displayReservation(res1);
        std::cout << "-------------------\n";
        system.displayReservation(res2);
        std::cout << "-------------------\n";
        system.displayReservation(res3);

        // Cancel a reservation
        std::cout << "\nCancelling reservation " << res2 << "...\n";
        if (system.cancelReservation(res2)) {
            std::cout << "Reservation cancelled successfully\n";
        } else {
            std::cout << "Failed to cancel reservation\n";
        }

        // Display updated reservation
        std::cout << "\nUpdated Reservation Details:\n";
        system.displayReservation(res2);

        // Try to book on a full flight (simulated)
        Flight* flight = aa->getFlight("AA101");
        for (int i = 0; i < flight->getAvailableSeats(); i++) {
            system.makeReservation("Passenger " + std::to_string(i), "AA", "AA101");
        }

        try {
            // This should throw an exception for overbooking
            system.makeReservation("Overflow Passenger", "AA", "AA101");
        } catch (const std::runtime_error& e) {
            std::cout << "\nError: " << e.what() << "\n";
        }

    } catch (const std::exception& e) {
        std::cerr << "Exception: " << e.what() << "\n";
        return 1;
    }

    return 0;
}
