    std::string flightNumber;
    std::string departure;
    std::string destination;
    std::string departureTime;
    int totalSeats;
    int bookedSeats;

public:
    Flight(const std::string& flightNum, const std::string& dep, const std::string& dest, 
           const std::string& depTime, int seats)
        : flightNumber(flightNum), departure(dep), destination(dest), 
          departureTime(depTime), totalSeats(seats), bookedSeats(0) {}

    std::string getFlightNumber() const { return flightNumber; }
    int getAvailableSeats() const { return totalSeats - bookedSeats; }

    bool bookSeat() {
        if (bookedSeats < totalSeats) {
            bookedSeats++;
            return true;
        }
        return false;
    }

    bool cancelSeat() {
        if (bookedSeats > 0) {
            bookedSeats--;
            return true;
        }
        return false;
    }
};

class Reservation {
private:
    std::string reservationId;
    std::string passengerName;
    std::string airlineName;
    std::string flightNumber;

public:
    Reservation(const std::string& id, const std::string& name, 
                const std::string& airline, const std::string& flight)
        : reservationId(id), passengerName(name), airlineName(airline), flightNumber(flight) {}

    std::string getReservationId() const { return reservationId; }
    std::string getAirlineName() const { return airlineName; }
    std::string getFlightNumber() const { return flightNumber; }
};

class ReservationSystem {
private:
    std::unordered_map<std::string, std::vector<Flight>> airlines;
    std::unordered_map<std::string, Reservation> reservations;

public:
    void addAirline(const std::string& airlineName) {
        if (airlines.find(airlineName) == airlines.end()) {
            airlines[airlineName] = std::vector<Flight>();
        }
    }

    void addFlight(const std::string& airlineName, const Flight& flight) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::invalid_argument("Airline does not exist");
        }

        if (airlines[airlineName].size() >= 300) {
            throw std::overflow_error("Maximum flight limit reached for this airline");
        }

        airlines[airlineName].push_back(flight);
    }

    std::string addReservation(const std::string& passengerName, 
                             const std::string& airlineName, 
                             const std::string& flightNumber) {
        if (airlines.find(airlineName) == airlines.end()) {
            throw std::invalid_argument("Airline does not exist");
        }

        Flight* flight = nullptr;
        for (auto& f : airlines[airlineName]) {
            if (f.getFlightNumber() == flightNumber) {
                flight = &f;
                break;
            }
        }

        if (!flight) {
            throw std::invalid_argument("Flight does not exist");
        }

        if (!flight->bookSeat()) {
            throw std::runtime_error("Flight is fully booked");
        }

        std::string reservationId = generateReservationId();
        reservations[reservationId] = Reservation(reservationId, passengerName, airlineName, flightNumber);

        return reservationId;
    }

    bool checkReservation(const std::string& reservationId) {
        return reservations.find(reservationId) != reservations.end();
    }

    void removeReservation(const std::string& reservationId) {
        if (reservations.find(reservationId) == reservations.end()) {
            throw std::invalid_argument("Reservation does not exist");
        }

        Reservation& reservation = reservations[reservationId];
        std::string airlineName = reservation.getAirlineName();
        std::string flightNumber = reservation.getFlightNumber();

        for (auto& flight : airlines[airlineName]) {
            if (flight.getFlightNumber() == flightNumber) {
                flight.cancelSeat();
                break;
            }
        }

        reservations.erase(reservationId);
    }

private:
    std::string generateReservationId() {
        static int counter = 1000;
        return "RES" + std::to_string(++counter);
    }
};

