class Flight {
private:
    std::string flightNumber;
    std::string origin;
    std::string destination;
    int totalSeats;
    int reservedSeats;

public:
    Flight(const std::string& flightNo, const std::string& from, const std::string& to, int seats)
        : flightNumber(flightNo), origin(from), destination(to), totalSeats(seats), reservedSeats(0) {}

    std::string getFlightNumber() const { return flightNumber; }
    std::string getOrigin() const { return origin; }
    std::string getDestination() const { return destination; }
    int getTotalSeats() const { return totalSeats; }
    int getReservedSeats() const { return reservedSeats; }
    int getAvailableSeats() const { return totalSeats - reservedSeats; }

    bool reserveSeat() {
        if (reservedSeats >= totalSeats) {
            return false; // Overbooking attempt
        }
        reservedSeats++;
        return true;
    }

    bool cancelSeat() {
        if (reservedSeats <= 0) {
            return false; // Invalid cancellation
        }
        reservedSeats--;
        return true;
    }
};

class FlightList {
private:
    std::vector<Flight> flights;
    const size_t MAX_FLIGHTS = 300;

public:
    // Append a flight to the list
    bool append(const Flight& flight) {
        if (flights.size() >= MAX_FLIGHTS) {
            return false; // Cannot exceed max flights
        }
        flights.push_back(flight);
        return true;
    }

    // Clear all flights
    void clear() {
        flights.clear();
    }

    // Accessor for flight data
    const Flight* getFlight(const std::string& flightNumber) const {
        for (const auto& flight : flights) {
            if (flight.getFlightNumber() == flightNumber) {
                return &flight;
            }
        }
        return nullptr;
    }

    // Non-const version for reservation operations
    Flight* getFlightForReservation(const std::string& flightNumber) {
        for (auto& flight : flights) {
            if (flight.getFlightNumber() == flightNumber) {
                return &flight;
            }
        }
        return nullptr;
    }
};

class Reservation {
private:
    std::string reservationId;
    std::string passengerName;
    std::string airlineName;
    std::string flightNumber;

public:
    Reservation(const std::string& id, const std::string& passenger, 
                const std::string& airline, const std::string& flight)
        : reservationId(id), passengerName(passenger), 
          airlineName(airline), flightNumber(flight) {}

    std::string getReservationId() const { return reservationId; }
    std::string getPassengerName() const { return passengerName; }
    std::string getAirlineName() const { return airlineName; }
    std::string getFlightNumber() const { return flightNumber; }
};

class ReservationSystem {
private:
    std::unordered_map<std::string, FlightList> airlines;
    std::vector<Reservation> reservations;

public:
    // Add a new airline
    void addAirline(const std::string& airlineName) {
        airlines[airlineName] = FlightList();
    }

    // Add a flight to an airline
    bool addFlight(const std::string& airlineName, const Flight& flight) {
        if (airlines.find(airlineName) == airlines.end()) {
            return false; // Airline not found
        }
        return airlines[airlineName].append(flight);
    }

    // Add a reservation
    bool addReservation(const std::string& reservationId, const std::string& passengerName, 
                         const std::string& airlineName, const std::string& flightNumber) {
        try {
            if (airlines.find(airlineName) == airlines.end()) {
                throw std::runtime_error("Airline not found");
            }

            Flight* flight = airlines[airlineName].getFlightForReservation(flightNumber);
            if (!flight) {
                throw std::runtime_error("Flight not found");
            }

            if (!flight->reserveSeat()) {
                throw std::runtime_error("No available seats");
            }

            reservations.push_back(Reservation(reservationId, passengerName, airlineName, flightNumber));
            return true;
        }
        catch (const std::exception& e) {
            return false;
        }
    }

    // Check if a reservation exists
    bool checkReservation(const std::string& reservationId) const {
        for (const auto& reservation : reservations) {
            if (reservation.getReservationId() == reservationId) {
                return true;
            }
        }
        return false;
    }

    // Remove a reservation
    bool removeReservation(const std::string& reservationId) {
        for (auto it = reservations.begin(); it != reservations.end(); ++it) {
            if (it->getReservationId() == reservationId) {
                const std::string& airlineName = it->getAirlineName();
                const std::string& flightNumber = it->getFlightNumber();

                Flight* flight = airlines.at(airlineName).getFlightForReservation(flightNumber);
                if (flight) {
                    flight->cancelSeat();
                }

                reservations.erase(it);
                return true;
            }
        }
        return false;
    }

    // Clear all flights for an airline
    void clearFlights(const std::string& airlineName) {
        if (airlines.find(airlineName) != airlines.end()) {
            airlines[airlineName].clear();
        }
    }
};

int main() {
    ReservationSystem system;

    // Add airlines
    system.addAirline("Delta");
    system.addAirline("United");

    // Add flights
    system.addFlight("Delta", Flight("DL123", "NYC", "LAX", 200));
    system.addFlight("Delta", Flight("DL456", "LAX", "CHI", 180));
    system.addFlight("United", Flight("UA789", "DFW", "SEA", 220));

    // Make reservations
    system.addReservation("R1001", "John Doe", "Delta", "DL123");
    system.addReservation("R1002", "Jane Smith", "United", "UA789");

    // Check and remove reservations
    if (system.checkReservation("R1001")) {
        system.removeReservation("R1001");
    }

    return 0;
}
