impl TaskManager {
    fn new(file_path: &str) -> Self {
        let mut manager = TaskManager {
            tasks: VecDeque::with_capacity(50),
            file_path: file_path.to_string(),
        };
        manager.load_tasks();
        manager
    }

    fn add_task(&mut self, description: &str, priority: bool) {
        if self.tasks.len() >= 50 {
            println!("Task limit reached. Remove some tasks first.");
            return;
        }

        let task = Task {
            description: description.to_string(),
            completed: false,
            priority,
        };

        if priority {
            self.tasks.push_front(task);
        } else {
            self.tasks.push_front(task);
        }
    }

    fn remove_task(&mut self) -> Option<Task> {
        self.tasks.pop_back()
    }

    fn view_tasks(&self) {
        if self.tasks.is_empty() {
            println!("No tasks available.");
            return;
        }

        for (i, task) in self.tasks.iter().enumerate() {
            let status = if task.completed { "✓" } else { "✗" };
            let priority = if task.priority { "[HIGH]" } else { "[NORMAL]" };
            println!("{}: {} {} {}", i + 1, status, priority, task.description);
        }
    }

    fn mark_completed(&mut self, index: usize) {
        if index < self.tasks.len() {
            if let Some(task) = self.tasks.get_mut(index) {
                task.completed = true;
            }
        } else {
            println!("Invalid task index.");
        }
    }

    fn prioritize_task(&mut self, index: usize) {
        if index < self.tasks.len() {
            if let Some(task) = self.tasks.remove(index) {
                let mut prioritized_task = task;
                prioritized_task.priority = true;
                self.tasks.push_front(prioritized_task);
            }
        } else {
            println!("Invalid task index.");
        }
    }

    fn save_tasks(&self) {
        let mut file = OpenOptions::new()
            .write(true)
            .create(true)
            .truncate(true)
            .open(&self.file_path)
            .expect("Failed to open file for writing");

        for task in &self.tasks {
            let line = format!(
                "{},{},{}\n",
                task.description, task.completed, task.priority
            );
            file.write_all(line.as_bytes())
                .expect("Failed to write to file");
        }
    }

    fn load_tasks(&mut self) {
        let path = Path::new(&self.file_path);
        if !path.exists() {
            return;
        }

        let file = File::open(path).expect("Failed to open tasks file");
        let reader = BufReader::new(file);

        for line in reader.lines() {
            if let Ok(line) = line {
                let parts: Vec<&str> = line.split(',').collect();
                if parts.len() == 3 {
                    let description = parts[0].to_string();
                    let completed = parts[1].parse::<bool>().unwrap_or(false);
                    let priority = parts[2].parse::<bool>().unwrap_or(false);

                    let task = Task {
                        description,
                        completed,
                        priority,
                    };

                    self.tasks.push_back(task);
                }
            }
        }
    }
