            max_size: 30,
        };
        manager.load_tasks();
        manager
    }

    fn add_task(&mut self, description: String, priority: bool) {
        let task = Task::new(description, priority);

        if priority {
            self.tasks.push_front(task);
        } else {
            self.tasks.push_back(task);
        }

        if self.tasks.len() > self.max_size {
            self.tasks.pop_back();
        }
    }

    fn remove_last_task(&mut self) -> Option<Task> {
        self.tasks.pop_back()
    }

    fn view_tasks(&self) {
        if self.tasks.is_empty() {
            println!("No tasks available.");
            return;
        }

        for (index, task) in self.tasks.iter().enumerate() {
            let status = if task.completed { "✓" } else { "○" };
            let priority_marker = if task.priority { "[HIGH]" } else { "[NORMAL]" };
            println!("{}: {} {} {}", index + 1, status, priority_marker, task.description);
        }
    }

    fn complete_task(&mut self, index: usize) -> bool {
        if index > 0 && index <= self.tasks.len() {
            if let Some(task) = self.tasks.get_mut(index - 1) {
                task.completed = true;
                return true;
            }
        }
        false
    }

    fn prioritize_task(&mut self, index: usize) -> bool {
        if index > 0 && index <= self.tasks.len() {
            if let Some(mut task) = self.tasks.remove(index - 1) {
                task.priority = true;
                self.tasks.push_front(task);
                return true;
            }
        }
        false
    }

    fn save_tasks(&self) {
        if let Ok(serialized) = serde_json::to_string(&self.tasks) {
            let _ = fs::write("tasks.json", serialized);
        }
