    std::vector<std::vector<int>> grid;
    std::vector<std::vector<int>> dp;
    std::unordered_set<std::string> visited;

    std::string encodePosition(int r, int c) {
        return std::to_string(r) + "," + std::to_string(c);
    }

    bool isValid(int r, int c) {
        return r >= 0 && r < rows && c >= 0 && c < cols;
    }

public:
    RidesharingPathfinder(std::vector<std::vector<int>>& streetMap) {
        grid = streetMap;
        rows = grid.size();
        cols = grid[0].size();
        dp.assign(rows, std::vector<int>(cols, INT_MAX));
    }

    int findShortestPath(int startR, int startC, int endR, int endC) {
        visited.clear();
        dp[startR][startC] = grid[startR][startC];

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (i == startR && j == startC) continue;

                std::string currentPos = encodePosition(i, j);
                if (visited.find(currentPos) != visited.end()) continue;

                int minCost = INT_MAX;

                if (i > 0 && dp[i-1][j] != INT_MAX) {
                    minCost = std::min(minCost, dp[i-1][j] + grid[i][j]);
                }
                if (j > 0 && dp[i][j-1] != INT_MAX) {
                    minCost = std::min(minCost, dp[i][j-1] + grid[i][j]);
                }

                if (minCost != INT_MAX) {
                    dp[i][j] = minCost;
                    visited.insert(currentPos);
                }
            }
        }

        return dp[endR][endC] == INT_MAX ? -1 : dp[endR][endC];
    }

    void printPath() {
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (dp[i][j] == INT_MAX) {
                    std::cout << "INF ";
                } else {
                    std::cout << dp[i][j] << " ";
                }
            }
            std::cout << std::endl;
        }
    }
};

int main() {
    std::vector<std::vector<int>> streetMap = {
        {1, 3, 1, 5},
        {2, 1, 4, 2},
        {5, 3, 2, 1},
        {1, 2, 1, 4}
    };

    RidesharingPathfinder pathfinder(streetMap);

    int startR = 0, startC = 0;
    int endR = 3, endC = 3;

    int shortestDistance = pathfinder.findShortestPath(startR, startC, endR, endC);

    std::cout << "Shortest path distance: " << shortestDistance << std::endl;
    std::cout << "DP table:" << std::endl;
    pathfinder.printPath();

    return 0;
}
