#include <iostream>
#include <vector>
#include <unordered_set>
#include <queue>
#include <utility>
#include <limits>
#include <functional>

struct Intersection {
    int row, col, distance;

    Intersection(int r, int c, int d) : row(r), col(c), distance(d) {}

    bool operator==(const Intersection& other) const {
        return row == other.row && col == other.col;
    }
};

struct IntersectionHash {
    size_t operator()(const Intersection& intersection) const {
        return std::hash<int>()(intersection.row) ^ std::hash<int>()(intersection.col);
    }
};

int shortestPath(const std::vector<std::vector<int>>& grid, 
                 const std::pair<int, int>& start, 
                 const std::pair<int, int>& end) {
    int rows = grid.size();
    int cols = grid[0].size();

    std::vector<std::vector<int>> distance(rows, std::vector<int>(cols, std::numeric_limits<int>::max()));
    distance[start.first][start.second] = 0;

    std::unordered_set<Intersection, IntersectionHash> visited;
    std::priority_queue<Intersection, std::vector<Intersection>, 
                        std::function<bool(const Intersection&, const Intersection&)>> pq(
        [](const Intersection& a, const Intersection& b) {
            return a.distance > b.distance;
        }
    );

    pq.push(Intersection(start.first, start.second, 0));

    int dx[] = {-1, 0, 1, 0};
    int dy[] = {0, 1, 0, -1};

    while (!pq.empty()) {
        Intersection current = pq.top();
        pq.pop();

        if (current.row == end.first && current.col == end.second) {
            return current.distance;
        }

        if (visited.find(current) != visited.end()) {
            continue;
        }

        visited.insert(current);

        // Memory management: limit visited set size
        if (visited.size() > 500) {
            std::vector<Intersection> toKeep;
            for (const auto& intersection : visited) {
                if (intersection.distance <= current.distance + 100) {
                    toKeep.push_back(intersection);
                }
            }

            visited.clear();
            for (const auto& intersection : toKeep) {
                visited.insert(intersection);
            }
        }

        for (int i = 0; i < 4; i++) {
            int newRow = current.row + dx[i];
            int newCol = current.col + dy[i];

            if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols && grid[newRow][newCol] != -1) {
                int newDistance = current.distance + grid[newRow][newCol];

                if (newDistance < distance[newRow][newCol]) {
                    distance[newRow][newCol] = newDistance;
                    pq.push(Intersection(newRow, newCol, newDistance));
                }
            }
        }
    }

    return -1; // No path found
}

int main() {
    // Example grid where each cell represents the cost to traverse
    // -1 represents obstacles/blocked streets
    std::vector<std::vector<int>> cityGrid = {
        {1, 3, 1, 2, 9},
        {7, -1, 9, 2, 1},
        {1, 1, -1, 1, 3},
        {2, -1, 4, 1, 2},
        {5, 2, 1, 3, 1}
    };

    std::pair<int, int> start = {0, 0};
    std::pair<int, int> end = {4, 4};

    int result = shortestPath(cityGrid, start, end);

    if (result != -1) {
        std::cout << "Shortest path cost: " << result << std::endl;
    } else {
        std::cout << "No path exists" << std::endl;
    }

    return 0;
}
