#include <iostream>
#include <vector>
#include <unordered_set>
#include <queue>
#include <climits>

class RidesharingPathFinder {
private:
    int rows, cols;
    std::vector<std::vector<int>> grid;
    std::vector<std::vector<int>> dist;
    std::unordered_set<int> visited;

    int encodePosition(int r, int c) {
        return r * cols + c;
    }

    std::pair<int, int> decodePosition(int encoded) {
        return {encoded / cols, encoded % cols};
    }

    void manageSetSize() {
        if (visited.size() > 500) {
            visited.clear();
        }
    }

public:
    RidesharingPathFinder(int r, int c) : rows(r), cols(c) {
        grid.resize(rows, std::vector<int>(cols, 1));
        dist.resize(rows, std::vector<int>(cols, INT_MAX));
    }

    void setObstacle(int r, int c) {
        if (r >= 0 && r < rows && c >= 0 && c < cols) {
            grid[r][c] = 0;
        }
    }

    int findShortestPath(int startR, int startC, int endR, int endC) {
        if (startR < 0 || startR >= rows || startC < 0 || startC >= cols ||
            endR < 0 || endR >= rows || endC < 0 || endC >= cols ||
            grid[startR][startC] == 0 || grid[endR][endC] == 0) {
            return -1;
        }

        visited.clear();
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                dist[i][j] = INT_MAX;
            }
        }

        std::priority_queue<std::pair<int, std::pair<int, int>>, 
                           std::vector<std::pair<int, std::pair<int, int>>>,
                           std::greater<>> pq;

        dist[startR][startC] = 0;
        pq.push({0, {startR, startC}});

        int directions[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

        while (!pq.empty()) {
            auto current = pq.top();
            pq.pop();

            int currentDist = current.first;
            int r = current.second.first;
            int c = current.second.second;

            if (r == endR && c == endC) {
                return currentDist;
            }

            int encoded = encodePosition(r, c);
            if (visited.find(encoded) != visited.end()) {
                continue;
            }

            visited.insert(encoded);
            manageSetSize();

            for (int i = 0; i < 4; i++) {
                int newR = r + directions[i][0];
                int newC = c + directions[i][1];

                if (newR >= 0 && newR < rows && newC >= 0 && newC < cols && 
                    grid[newR][newC] == 1) {

                    int newEncoded = encodePosition(newR, newC);
                    if (visited.find(newEncoded) == visited.end()) {
                        int newDist = currentDist + 1;
                        if (newDist < dist[newR][newC]) {
                            dist[newR][newC] = newDist;
                            pq.push({newDist, {newR, newC}});
                        }
                    }
                }
            }
        }

        return -1;
    }
};

int main() {
    RidesharingPathFinder pathFinder(1000, 1000);

    pathFinder.setObstacle(1, 1);
    pathFinder.setObstacle(2, 2);
    pathFinder.setObstacle(3, 3);

    int shortestPath = pathFinder.findShortestPath(0, 0, 999, 999);

    if (shortestPath != -1) {
        std::cout << "Shortest path length: " << shortestPath << std::endl;
    } else {
        std::cout << "No path found" << std::endl;
    }

    return 0;
}
