```go
package main

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"
	"time"
)

const (
	MaxTemperatureEntries = 1000
	MaxBufferSize         = 64 * 1024 // 64KB buffer limit
)

type TemperatureReading struct {
	SensorID    string    `json:"sensor_id"`
	Temperature float64   `json:"temperature"`
	Timestamp   time.Time `json:"timestamp"`
}

type TemperatureProcessor struct {
	buffer      *bytes.Buffer
	readings    []TemperatureReading
	windowSize  int
	logger      *log.Logger
}

func NewTemperatureProcessor(windowSize int) *TemperatureProcessor {
	return &TemperatureProcessor{
		buffer:     bytes.NewBuffer(make([]byte, 0, MaxBufferSize)),
		readings:   make([]TemperatureReading, 0, MaxTemperatureEntries),
		windowSize: windowSize,
		logger:     log.New(os.Stdout, "[TEMP_PROCESSOR] ", log.LstdFlags|log.Lshortfile),
	}
}

func (tp *TemperatureProcessor) ProcessTemperatureStream(input string) error {
	if strings.TrimSpace(input) == "" {
		tp.logger.Printf("WARNING: Empty input data received")
		return fmt.Errorf("empty input data")
	}

	// Check buffer size before writing
	if tp.buffer.Len()+len(input) > MaxBufferSize {
		tp.logger.Printf("ERROR: Buffer overflow detected. Current size: %d, Input size: %d", 
			tp.buffer.Len(), len(input))
		return fmt.Errorf("buffer overflow: would exceed maximum buffer size")
	}

	// Write to buffer
	_, err := tp.buffer.WriteString(input)
	if err != nil {
		tp.logger.Printf("ERROR: Failed to write to buffer: %v", err)
		return fmt.Errorf("buffer write error: %v", err)
	}

	tp.logger.Printf("INFO: Data written to buffer. Buffer size: %d bytes", tp.buffer.Len())

	// Process buffer content
	return tp.processBufferContent()
}

func (tp *TemperatureProcessor) processBufferContent() error {
	scanner := bufio.NewScanner(tp.buffer)

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}

		reading, err := tp.parseTemperatureReading(line)
		if err != nil {
			tp.logger.Printf("WARNING: Failed to parse reading: %v", err)
			continue
		}

		if err := tp.addReading(reading); err != nil {
			tp.logger.Printf("ERROR: Failed to add reading: %v", err)
			return err
		}
	}

	if err := scanner.Err(); err != nil {
		tp.logger.Printf("ERROR: Scanner error: %v", err)
		return fmt.Errorf("scanner error: %v", err)
	}

	// Clear buffer after processing
	tp.buffer.Reset()
	tp.logger.Printf("DEBUG: Buffer cleared after processing")

	return nil
}

func (tp *TemperatureProcessor) parseTemperatureReading(line string) (TemperatureReading, error) {
	var reading TemperatureReading

	// Try JSON format first
	if err := json.Unmarshal([]byte(line), &reading); err == nil {
		return reading, nil
	}

	// Try CSV format: sensor_id,temperature,timestamp
	parts := strings.Split(line, ",")
	if len(parts) != 3 {
		return reading, fmt.Errorf("invalid format: expected 3 comma-separated values")
	}

	reading.SensorID = strings.TrimSpace(parts[0])

	temp, err := strconv.ParseFloat(strings.TrimSpace(parts[1]), 64)
	if err != nil {
		return reading, fmt.Errorf("invalid temperature value: %v", err)
	}
	reading.Temperature = temp

	timestamp, err := time.Parse(time.RFC3339, strings.TrimSpace(parts[2]))
	if err != nil {
		// Try alternative format
		timestamp, err = time.Parse("2006-01-02 15:04:05", strings.TrimSpace(parts[2]))
		if err != nil {
			reading.Timestamp = time.Now()
		} else {
			reading.Timestamp = timestamp
		}
	} else {
		reading.Timestamp = timestamp
	}

	return reading, nil
}

func (tp *TemperatureProcessor) addReading(reading TemperatureReading) error {
	if len(tp.readings) >= MaxTemperatureEntries {
		tp.logger.Printf("WARNING: Maximum temperature entries reached (%d). Removing oldest entry.", 
			MaxTemperatureEntries)
		tp.readings = tp.readings[1:]
	}

	tp.readings = append(tp.readings, reading)
	tp.logger.Printf("INFO: Added reading from sensor %s: %.2f°C", 
		reading.SensorID, reading.Temperature)

	return nil
}

func (tp *TemperatureProcessor) ComputeMovingAverage() (map[string]float64, error) {
	if len(tp.readings) == 0 {
		tp.logger.Printf("WARNING: No temperature readings available for moving average calculation")
		return nil, fmt.Errorf("no temperature readings available")
	}

	sensorAverages := make(map[string]float64)
	sensorCounts := make(map[string]int)
	sensorSums := make(map[string]float64)

	windowStart := 0
	if len(tp.readings) > tp.windowSize {
		windowStart = len(tp.readings) - tp.windowSize
	}

	for i := windowStart; i < len(tp.readings); i++ {
		reading := tp.readings[i]
		sensorSums[reading.SensorID] += reading.Temperature
		sensorCounts[reading.SensorID]++
	}

	for sensorID, sum := range sensorSums {
		count := sensorCounts[sensorID]
		if count > 0 {
			sensorAverages[sensorID] = sum / float64(count)
			tp.logger.Printf("INFO: Moving average for sensor %s: %.2f°C (window: %d readings)", 
				sensorID, sensorAverages[sensorID], count)
		}
	}

	tp.logger.Printf("INFO: Computed moving averages for %d sensors", len(sensorAverages))
	return sensorAverages, nil
}

func (tp *TemperatureProcessor) GetBufferStats() (int, int) {
	return tp.buffer.Len(), tp.buffer.Cap()
}

func (tp *TemperatureProcessor) GetReadingCount() int {
	return len(tp.readings)
}

func main() {
	processor := NewTemperatureProcessor(10) // 10-reading moving window

	// Sample temperature data
	sampleData := []string{
		`{"sensor_id":"TEMP001","temperature":23.5,"timestamp":"2024-01-01T10:00:00Z"}`,
		`{"sensor_id":"TEMP002","temperature":24.1,"timestamp":"2024-01-01T10:01:00Z"}`,
		`TEMP001,25.3,2024-01-01T10:02:00Z`,
		`TEMP003,22.8,2024-01-01T10:03:00Z`,
		`{"sensor_id":"TEMP001","temperature":26.0,"timestamp":"2024-01-01T10:04:00Z"}`,
	}

	// Process sample data
	for _, data := range sampleData {
		if err := processor.ProcessTemperatureStream(data); err != nil {
			log.Printf("Error processing data: %v", err)
			continue
		}
	}

	// Compute and display moving averages
	averages, err := processor.ComputeMovingAverage()
	if err != nil {
		log.Printf("Error computing moving averages: %v", err)
		return
	}

	fmt.Println("\nMoving Averages by Sensor:")
	for sensorID, avg := range averages {
		fmt.Printf("Sensor %s: %.2f°C\n", sensorID, avg)
	}

	// Display buffer and reading statistics
	bufferLen, bufferCap := processor.GetBufferStats()
	fmt.Printf("\nBuffer Stats - Used: %d bytes, Capacity: %d bytes\n", bufferLen, bufferCap)
	fmt.Printf("Total Readings: %d\n", processor.GetReadingCount())
