package main

import (
	"errors"
	"fmt"
	"log"
	"os"
)

// Buffer represents a circular buffer for temperature data
type Buffer struct {
	data     []float64
	size     int
	capacity int
	head     int
	tail     int
	count    int
}

// NewBuffer creates a new buffer with specified capacity
func NewBuffer(capacity int) *Buffer {
	return &Buffer{
		data:     make([]float64, capacity),
		capacity: capacity,
		head:     0,
		tail:     0,
		count:    0,
	}
}

// Push adds a temperature value to the buffer
func (b *Buffer) Push(value float64) error {
	if b.count == b.capacity {
		return errors.New("buffer overflow: cannot add more data")
	}

	b.data[b.tail] = value
	b.tail = (b.tail + 1) % b.capacity
	b.count++
	return nil
}

// Pop removes and returns the oldest temperature value from the buffer
func (b *Buffer) Pop() (float64, error) {
	if b.count == 0 {
		return 0, errors.New("buffer underflow: no data to remove")
	}

	value := b.data[b.head]
	b.head = (b.head + 1) % b.capacity
	b.count--
	return value, nil
}

// IsEmpty checks if the buffer is empty
func (b *Buffer) IsEmpty() bool {
	return b.count == 0
}

// IsFull checks if the buffer is full
func (b *Buffer) IsFull() bool {
	return b.count == b.capacity
}

// Size returns the current number of elements in the buffer
func (b *Buffer) Size() int {
	return b.count
}

// TemperatureSensor represents a temperature sensor
type TemperatureSensor struct {
	ID   string
	Data []float64
}

// TemperatureProcessor processes temperature data and computes moving averages
type TemperatureProcessor struct {
	buffer     *Buffer
	windowSize int
	logger     *log.Logger
}

// NewTemperatureProcessor creates a new temperature processor
func NewTemperatureProcessor(bufferCapacity, windowSize int) *TemperatureProcessor {
	logger := log.New(os.Stdout, "[TEMP_PROCESSOR] ", log.LstdFlags|log.Lshortfile)

	return &TemperatureProcessor{
		buffer:     NewBuffer(bufferCapacity),
		windowSize: windowSize,
		logger:     logger,
	}
}

// ProcessTemperatureData processes temperature data from multiple sensors
func (tp *TemperatureProcessor) ProcessTemperatureData(sensors []TemperatureSensor) error {
	tp.logger.Printf("INFO: Starting temperature data processing for %d sensors", len(sensors))

	if len(sensors) == 0 {
		tp.logger.Println("WARN: No sensors provided for processing")
		return errors.New("no sensors provided")
	}

	totalEntries := 0
	for _, sensor := range sensors {
		totalEntries += len(sensor.Data)
	}

	if totalEntries == 0 {
		tp.logger.Println("WARN: No temperature data found in any sensor")
		return errors.New("no temperature data found")
	}

	if totalEntries > 1000 {
		tp.logger.Printf("ERROR: Too many temperature entries (%d). Maximum allowed is 1000", totalEntries)
		return errors.New("temperature entries exceed maximum limit of 1000")
	}

	tp.logger.Printf("INFO: Processing %d total temperature entries", totalEntries)

	for _, sensor := range sensors {
		tp.logger.Printf("INFO: Processing sensor %s with %d readings", sensor.ID, len(sensor.Data))

		if len(sensor.Data) == 0 {
			tp.logger.Printf("WARN: Sensor %s has no data, skipping", sensor.ID)
			continue
		}

		for i, temp := range sensor.Data {
			if err := tp.addTemperature(temp); err != nil {
				tp.logger.Printf("ERROR: Failed to add temperature %.2f from sensor %s at index %d: %v", 
					temp, sensor.ID, i, err)
				return err
			}

			if tp.buffer.Size() >= tp.windowSize {
				avg, err := tp.computeMovingAverage()
				if err != nil {
					tp.logger.Printf("ERROR: Failed to compute moving average: %v", err)
					return err
				}
				tp.logger.Printf("INFO: Moving average (window size %d): %.2f°C", tp.windowSize, avg)
			}
		}
	}

	tp.logger.Println("INFO: Temperature data processing completed successfully")
	return nil
}

// addTemperature adds a temperature reading to the buffer
func (tp *TemperatureProcessor) addTemperature(temp float64) error {
	if tp.buffer.IsFull() {
		tp.logger.Printf("DEBUG: Buffer is full, removing oldest entry")
		_, err := tp.buffer.Pop()
		if err != nil {
			return fmt.Errorf("failed to remove oldest entry: %v", err)
		}
	}

	err := tp.buffer.Push(temp)
	if err != nil {
		return fmt.Errorf("failed to add temperature: %v", err)
	}

	tp.logger.Printf("DEBUG: Added temperature %.2f°C to buffer (size: %d)", temp, tp.buffer.Size())
	return nil
}

// computeMovingAverage computes the moving average of temperatures in the buffer
func (tp *TemperatureProcessor) computeMovingAverage() (float64, error) {
	if tp.buffer.IsEmpty() {
		return 0, errors.New("cannot compute average: buffer is empty")
	}

	if tp.buffer.Size() < tp.windowSize {
		return 0, errors.New("insufficient data for moving average calculation")
	}

	// Create a temporary slice to store values for average calculation
	values := make([]float64, tp.windowSize)
	tempBuffer := NewBuffer(tp.buffer.capacity)

	// Copy values from original buffer to temporary buffer and values slice
	for i := 0; i < tp.windowSize; i++ {
		val, err := tp.buffer.Pop()
		if err != nil {
			return 0, fmt.Errorf("failed to read from buffer: %v", err)
		}
		values[i] = val
		tempBuffer.Push(val)
	}

	// Restore original buffer
	for i := 0; i < tp.windowSize; i++ {
		val, _ := tempBuffer.Pop()
		tp.buffer.Push(val)
	}

	// Calculate average
	sum := 0.0
	for _, val := range values {
		sum += val
	}

	average := sum / float64(tp.windowSize)
	tp.logger.Printf("DEBUG: Computed moving average: %.2f°C from %d values", average, tp.windowSize)

	return average, nil
}

func main() {
	// Create temperature processor with buffer capacity of 1000 and window size of 5
	processor := NewTemperatureProcessor(1000, 5)

	// Sample temperature data from multiple sensors
	sensors := []TemperatureSensor{
		{
			ID:   "SENSOR_001",
			Data: []float64{20.5, 21.0, 20.8, 21.2, 20.9, 21.1, 20.7},
		},
		{
			ID:   "SENSOR_002",
			Data: []float64{19.8, 20.1, 19.9, 20.3, 20.0, 19.7, 20.2},
		},
		{
			ID:   "SENSOR_003",
			Data: []float64{22.1, 22.3, 22.0, 21.8, 22.2, 21.9, 22.4},
		},
	}

	// Process temperature data
	if err := processor.ProcessTemperatureData(sensors); err != nil {
		log.Fatalf("FATAL: Temperature processing failed: %v", err)
	}

	fmt.Println("Temperature data processing completed successfully!")
}
