package main

import (
	"fmt"
	"log"
	"math"
	"os"
)

// Buffer represents a circular buffer with fixed capacity
type Buffer struct {
	data     []float64
	capacity int
	size     int
	head     int
	tail     int
}

// NewBuffer creates a new buffer with specified capacity
func NewBuffer(capacity int) *Buffer {
	return &Buffer{
		data:     make([]float64, capacity),
		capacity: capacity,
		size:     0,
		head:     0,
		tail:     0,
	}
}

// Push adds a new item to the buffer
func (b *Buffer) Push(value float64) {
	if b.size == b.capacity {
		// Buffer is full, remove oldest item
		log.Printf("WARNING: Buffer at maximum capacity (%d), discarding oldest value: %.2f", b.capacity, b.data[b.tail])
		b.tail = (b.tail + 1) % b.capacity
	} else {
		b.size++
	}

	b.data[b.head] = value
	b.head = (b.head + 1) % b.capacity

	if b.size >= 18 {
		log.Printf("WARNING: Buffer approaching maximum capacity. Current size: %d/%d", b.size, b.capacity)
	}
}

// Pop removes and returns the oldest item from the buffer
func (b *Buffer) Pop() (float64, error) {
	if b.size == 0 {
		return 0, fmt.Errorf("buffer is empty")
	}

	value := b.data[b.tail]
	b.tail = (b.tail + 1) % b.capacity
	b.size--

	return value, nil
}

// IsEmpty checks if the buffer is empty
func (b *Buffer) IsEmpty() bool {
	return b.size == 0
}

// Size returns the current size of the buffer
func (b *Buffer) Size() int {
	return b.size
}

// GetMovingAverage calculates the moving average of all items in the buffer
func (b *Buffer) GetMovingAverage() (float64, error) {
	if b.size == 0 {
		return 0, fmt.Errorf("cannot calculate average of empty buffer")
	}

	sum := 0.0
	for i := 0; i < b.size; i++ {
		index := (b.tail + i) % b.capacity
		sum += b.data[index]
	}

	return sum / float64(b.size), nil
}

// TemperatureProcessor handles temperature data processing
type TemperatureProcessor struct {
	buffer *Buffer
	logger *log.Logger
}

// NewTemperatureProcessor creates a new temperature processor
func NewTemperatureProcessor() *TemperatureProcessor {
	logger := log.New(os.Stdout, "[TEMP_PROCESSOR] ", log.LstdFlags|log.Lshortfile)

	return &TemperatureProcessor{
		buffer: NewBuffer(20),
		logger: logger,
	}
}

// ProcessTemperature processes a single temperature reading
func (tp *TemperatureProcessor) ProcessTemperature(temp float64) error {
	// Validate temperature data
	if math.IsNaN(temp) || math.IsInf(temp, 0) {
		tp.logger.Printf("ERROR: Invalid temperature value: %v", temp)
		return fmt.Errorf("invalid temperature value: %v", temp)
	}

	// Reasonable temperature range check (-100°C to 200°C)
	if temp < -100 || temp > 200 {
		tp.logger.Printf("WARNING: Temperature value outside normal range: %.2f°C", temp)
	}

	tp.logger.Printf("INFO: Processing temperature: %.2f°C", temp)

	// Add temperature to buffer
	tp.buffer.Push(temp)

	// Calculate and log moving average
	avg, err := tp.buffer.GetMovingAverage()
	if err != nil {
		tp.logger.Printf("ERROR: Failed to calculate moving average: %v", err)
		return err
	}

	tp.logger.Printf("INFO: Current moving average: %.2f°C (buffer size: %d)", avg, tp.buffer.Size())

	return nil
}

// ProcessTemperatureStream processes multiple temperature readings
func (tp *TemperatureProcessor) ProcessTemperatureStream(temperatures []float64) error {
	if len(temperatures) == 0 {
		tp.logger.Printf("WARNING: Empty temperature data provided")
		return fmt.Errorf("empty temperature data")
	}

	if len(temperatures) > 1000 {
		tp.logger.Printf("WARNING: Temperature data exceeds maximum limit of 1000 entries. Processing first 1000 entries.")
		temperatures = temperatures[:1000]
	}

	tp.logger.Printf("INFO: Starting to process %d temperature readings", len(temperatures))

	successCount := 0
	errorCount := 0

	for i, temp := range temperatures {
		err := tp.ProcessTemperature(temp)
		if err != nil {
			tp.logger.Printf("ERROR: Failed to process temperature at index %d: %v", i, err)
			errorCount++
		} else {
			successCount++
		}
	}

	tp.logger.Printf("INFO: Processing complete. Success: %d, Errors: %d", successCount, errorCount)

	if errorCount > 0 {
		return fmt.Errorf("encountered %d errors during processing", errorCount)
	}

	return nil
}

// GetCurrentAverage returns the current moving average
func (tp *TemperatureProcessor) GetCurrentAverage() (float64, error) {
	if tp.buffer.IsEmpty() {
		return 0, fmt.Errorf("no temperature data available")
	}

	return tp.buffer.GetMovingAverage()
}

// GetBufferStatus returns current buffer status
func (tp *TemperatureProcessor) GetBufferStatus() (int, int) {
	return tp.buffer.Size(), tp.buffer.capacity
}

func main() {
	// Create temperature processor
	processor := NewTemperatureProcessor()

	// Sample temperature data (simulating sensor readings)
	temperatureData := []float64{
		20.5, 21.0, 20.8, 22.1, 21.5, 23.0, 22.8, 21.9, 20.7, 21.3,
		22.5, 23.1, 22.9, 21.8, 20.9, 21.7, 22.3, 23.5, 22.7, 21.4,
		20.6, 21.2, 22.0, 23.2, 22.6, 21.1, 20.3, 21.9, 22.4, 23.0,
	}

	log.Println("Starting temperature data processing application...")

	// Process the temperature stream
	err := processor.ProcessTemperatureStream(temperatureData)
	if err != nil {
		log.Printf("Processing completed with errors: %v", err)
	}

	// Get final statistics
	avg, err := processor.GetCurrentAverage()
	if err != nil {
		log.Printf("ERROR: Could not get final average: %v", err)
	} else {
		size, capacity := processor.GetBufferStatus()
		log.Printf("Final moving average: %.2f°C (based on %d/%d readings)", avg, size, capacity)
	}

	// Demonstrate buffer overflow handling
	log.Println("\nDemonstrating buffer overflow handling...")
	additionalData := make([]float64, 25)
	for i := range additionalData {
		additionalData[i] = 25.0 + float64(i)*0.1
	}

	err = processor.ProcessTemperatureStream(additionalData)
	if err != nil {
		log.Printf("Additional processing completed with errors: %v", err)
	}

	// Final status
	avg, _ = processor.GetCurrentAverage()
	size, capacity := processor.GetBufferStatus()
	log.Printf("Final state - Average: %.2f°C, Buffer: %d/%d", avg, size, capacity)
}
