int maxSubarraySum(const std::vector<int>& arr) {
    if (arr.empty()) {
        return 0;
    }

    std::stack<int> dpStack;
    const int STACK_LIMIT = 50;

    int maxSum = arr[0];
    int currentSum = arr[0];
    dpStack.push(currentSum);

    for (int i = 1; i < arr.size(); i++) {
        if (dpStack.size() >= STACK_LIMIT) {
            dpStack.pop();
        }

        currentSum = std::max(arr[i], currentSum + arr[i]);
        dpStack.push(currentSum);

        maxSum = std::max(maxSum, dpStack.top());
    }

    return maxSum;
}
