package main

import (
	"fmt"
	"sync"
)

type FibonacciCalculator struct {
	cache sync.Map
	size  int64
	mu    sync.Mutex
}

func NewFibonacciCalculator() *FibonacciCalculator {
	return &FibonacciCalculator{}
}

func (fc *FibonacciCalculator) evictOldest() {
	fc.mu.Lock()
	defer fc.mu.Unlock()

	if fc.size <= 500 {
		return
	}

	minKey := int64(-1)
	fc.cache.Range(func(key, value interface{}) bool {
		k := key.(int64)
		if minKey == -1 || k < minKey {
			minKey = k
		}
		return true
	})

	if minKey != -1 {
		fc.cache.Delete(minKey)
		fc.size--
	}
}

func (fc *FibonacciCalculator) Fibonacci(n int64) int64 {
	if n <= 1 {
		return n
	}

	if value, ok := fc.cache.Load(n); ok {
		return value.(int64)
	}

	result := fc.Fibonacci(n-1) + fc.Fibonacci(n-2)

	if fc.size >= 500 {
		fc.evictOldest()
	}

	if _, loaded := fc.cache.LoadOrStore(n, result); !loaded {
		fc.mu.Lock()
		fc.size++
		fc.mu.Unlock()
	}

	return result
}

