package main

import (
	"fmt"
	"sync"
)

func main() {
	fib := NewFibonacciCalculator(500)
	for i := 0; i < 1000; i++ {
		fmt.Printf("Fibonacci(%d) = %d\n", i, fib.Calculate(i))
	}
}

type FibonacciCalculator struct {
	cache    sync.Map
	capacity int
	count    int
	mu       sync.Mutex
}

func NewFibonacciCalculator(capacity int) *FibonacciCalculator {
	return &FibonacciCalculator{
		capacity: capacity,
	}
}

func (f *FibonacciCalculator) Calculate(n int) uint64 {
	// Base cases
	if n <= 1 {
		return uint64(n)
	}

	// Check if result is in cache
	if val, ok := f.cache.Load(n); ok {
		return val.(uint64)
	}

	// Calculate result
	result := f.Calculate(n-1) + f.Calculate(n-2)

	// Store in cache with capacity control
	f.mu.Lock()
	defer f.mu.Unlock()

	if f.count < f.capacity {
		f.cache.LoadOrStore(n, result)
		f.count++
	} else {
		// Evict oldest entries by recalculating without storing
		// This effectively maintains the most recent 500 entries
		f.cache.LoadOrStore(n, result)
		// No need to delete as we're just overwriting existing entries
	}

	return result
}
