std::vector<int> mergeKSortedArrays(const std::vector<std::vector<int>>& arrays) {
    // Define a custom comparator for our priority queue
    struct CompareElements {
        bool operator()(const std::pair<int, std::pair<int, int>>& a, 
                        const std::pair<int, std::pair<int, int>>& b) {
            return a.first > b.first;
        }
    };

    // Priority queue to store elements as: {value, {array_index, element_index}}
    std::priority_queue<std::pair<int, std::pair<int, int>>, 
                        std::vector<std::pair<int, std::pair<int, int>>>, 
                        CompareElements> minHeap;

    // Calculate total size to pre-allocate result vector
    int totalSize = 0;
    for (const auto& arr : arrays) {
        totalSize += arr.size();
    }

    // Ensure we don't exceed the size limit
    if (totalSize > 10000) {
        return {}; // Return empty vector if size exceeds limit
    }

    std::vector<int> result;
    result.reserve(totalSize);

    // Initialize priority queue with first element from each array
    for (int i = 0; i < arrays.size(); i++) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], {i, 0}});
        }
    }

    // Process all elements
    while (!minHeap.empty()) {
        auto current = minHeap.top();
        minHeap.pop();

        int value = current.first;
        int arrayIndex = current.second.first;
        int elementIndex = current.second.second;

        result.push_back(value);

        // Add next element from the same array if available
        if (elementIndex + 1 < arrays[arrayIndex].size()) {
            minHeap.push({arrays[arrayIndex][elementIndex + 1], 
                         {arrayIndex, elementIndex + 1}});
        }
    }

    return result;
}
