import java.util.*;
import java.util.concurrent.TimeUnit;

public class TaskProcessor {
    private static final int MAX_CAPACITY = 100;
    private PriorityQueue<Task> taskQueue;

    public TaskProcessor() {
        this.taskQueue = new PriorityQueue<>(MAX_CAPACITY, 
            (t1, t2) -> Integer.compare(t2.priority, t1.priority));
    }

    public void add(Task task) throws IllegalStateException {
        if (taskQueue.size() >= MAX_CAPACITY) {
            throw new IllegalStateException("Queue capacity exceeded");
        }
        taskQueue.offer(task);
    }

    public Task poll() throws NoSuchElementException {
        if (taskQueue.isEmpty()) {
            throw new NoSuchElementException("Queue is empty");
        }
        return taskQueue.poll();
    }

    public Task peek() throws NoSuchElementException {
        if (taskQueue.isEmpty()) {
            throw new NoSuchElementException("Queue is empty");
        }
        return taskQueue.peek();
    }

    public void clear() {
        taskQueue.clear();
    }

    public long executeAllTasks() throws NoSuchElementException {
        if (taskQueue.isEmpty()) {
            throw new NoSuchElementException("No tasks to execute");
        }

        long totalTime = 0;
        long startTime = System.currentTimeMillis();

        while (!taskQueue.isEmpty()) {
            Task task = taskQueue.poll();
            try {
                TimeUnit.MILLISECONDS.sleep(task.duration);
                totalTime += task.duration;
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }

        return totalTime;
    }

    static class Task {
        int priority;
        long duration;

        public Task(int priority, long duration) {
            this.priority = priority;
            this.duration = duration;
        }
    }
}
