func kadaneMaxSubarray(arr []int) int {
	maxSoFar := math.MinInt32
	maxEndingHere := 0

	for i := 0; i < len(arr); i++ {
		maxEndingHere = maxEndingHere + arr[i]
		if maxSoFar < maxEndingHere {
			maxSoFar = maxEndingHere
		}
		if maxEndingHere < 0 {
			maxEndingHere = 0
		}
	}

	// Special case: if all elements are negative
	if maxSoFar < 0 {
		maxSoFar = arr[0]
		for i := 1; i < len(arr); i++ {
			if arr[i] > maxSoFar {
				maxSoFar = arr[i]
			}
		}
	}

	return maxSoFar
}

