// Product class to encapsulate product details
class Product {
private:
    std::string name;
    double price;
    std::string genre;
    int stock;
    double discountPercent;

public:
    Product() : name(""), price(0.0), genre(""), stock(0), discountPercent(0.0) {}

    Product(std::string n, double p, std::string g, int s, double d = 0.0) : 
        name(n), price(p), genre(g), stock(s), discountPercent(d) {}

    std::string getName() const { return name; }
    double getPrice() const { return price; }
    std::string getGenre() const { return genre; }
    int getStock() const { return stock; }
    double getDiscountPercent() const { return discountPercent; }

    void setDiscountPercent(double d) { discountPercent = d; }
    void decreaseStock(int amount = 1) { stock -= amount; }

    double getDiscountedPrice() const {
        return price * (1.0 - discountPercent / 100.0);
    }
};

// Cart item class
class CartItem {
private:
    Product product;
    int quantity;

public:
    CartItem(Product p, int q) : product(p), quantity(q) {}

    Product getProduct() const { return product; }
    int getQuantity() const { return quantity; }
    void increaseQuantity(int amount = 1) { quantity += amount; }

    double getTotalPrice() const {
        return product.getDiscountedPrice() * quantity;
    }
};

// Custom sorting comparators
struct PriceComparator {
    bool operator()(const Product& p1, const Product& p2) const {
        return p1.getPrice() < p2.getPrice();
    }
};

struct GenreComparator {
    bool operator()(const Product& p1, const Product& p2) const {
        return p1.getGenre() < p2.getGenre();
    }
};

// Bookstore checkout system
class BookstoreCheckout {
private:
    std::map<int, Product> productCatalog; // Limited to 500 entries
    std::vector<CartItem> cart;
    double totalDiscount;

    // Custom sorting implementation for product catalog
    std::vector<Product> sortCatalog(bool byPrice = true) {
        std::vector<Product> sortedProducts;

        for (const auto& pair : productCatalog) {
            sortedProducts.push_back(pair.second);
        }

        // Simple insertion sort algorithm
        for (size_t i = 1; i < sortedProducts.size(); ++i) {
            Product key = sortedProducts[i];
            int j = i - 1;

            if (byPrice) {
                while (j >= 0 && sortedProducts[j].getPrice() > key.getPrice()) {
                    sortedProducts[j + 1] = sortedProducts[j];
                    j--;
                }
            } else {
                while (j >= 0 && sortedProducts[j].getGenre() > key.getGenre()) {
                    sortedProducts[j + 1] = sortedProducts[j];
                    j--;
                }
            }

            sortedProducts[j + 1] = key;
        }

        return sortedProducts;
    }

public:
    BookstoreCheckout() : totalDiscount(0.0) {}

    // Add product to catalog
    bool addProduct(int id, const Product& product) {
        if (productCatalog.size() >= 500) {
            return false; // Catalog is full
        }

        productCatalog[id] = product;
        return true;
    }

    // Add item to cart
    bool addToCart(int productId, int quantity = 1) {
        auto it = productCatalog.find(productId);
        if (it == productCatalog.end() || it->second.getStock() < quantity) {
            return false; // Product not found or insufficient stock
        }

        // Check if product already in cart
        for (auto& item : cart) {
            if (item.getProduct().getName() == it->second.getName()) {
                item.increaseQuantity(quantity);
                it->second.decreaseStock(quantity);
                return true;
            }
        }

        // Add new item to cart
        cart.emplace_back(it->second, quantity);
        it->second.decreaseStock(quantity);
        return true;
    }

    // Apply discount to a specific product
    void applyProductDiscount(int productId, double discountPercent) {
        auto it = productCatalog.find(productId);
        if (it != productCatalog.end()) {
            it->second.setDiscountPercent(discountPercent);

            // Update discount for items in cart
            for (auto& item : cart) {
                if (item.getProduct().getName() == it->second.getName()) {
                    Product updatedProduct = item.getProduct();
                    updatedProduct.setDiscountPercent(discountPercent);
                    cart[&item - &cart[0]] = CartItem(updatedProduct, item.getQuantity());
                }
            }
        }
    }

    // Apply overall cart discount
    void applyTotalDiscount(double discountPercent) {
        totalDiscount = discountPercent;
    }

    // Calculate total price
    double calculateTotal() const {
        double total = 0.0;
        for (const auto& item : cart) {
            total += item.getTotalPrice();
        }
        return total * (1.0 - totalDiscount / 100.0);
    }

    // Display products sorted by price or genre
    void displaySortedProducts(bool byPrice = true) {
        std::vector<Product> sorted = sortCatalog(byPrice);

        std::cout << "\nSorted Products by " << (byPrice ? "Price" : "Genre") << ":\n";
        std::cout << std::left << std::setw(30) << "Name" 
                 << std::setw(10) << "Price" 
                 << std::setw(15) << "Genre" 
                 << std::setw(10) << "Stock" << std::endl;
        std::cout << std::string(65, '-') << std::endl;

        for (const auto& product : sorted) {
            std::cout << std::left << std::setw(30) << product.getName() 
                     << "$" << std::setw(9) << std::fixed << std::setprecision(2) << product.getPrice() 
                     << std::setw(15) << product.getGenre() 
                     << std::setw(10) << product.getStock() << std::endl;
        }
    }

    // Display cart contents
    void displayCart() const {
        std::cout << "\nShopping Cart:\n";
        std::cout << std::left << std::setw(30) << "Product" 
                 << std::setw(10) << "Price" 
