    std::string name;
    std::string genre;
    Category category;
    double price;
};

class ProductCatalog {
private:
    std::map<std::string, Product> products;
    const size_t MAX_ENTRIES = 500;

public:
    bool insert(const Product& product) {
        if (products.size() >= MAX_ENTRIES) {
            return false;
        }
        products[product.id] = product;
        return true;
    }

    Product* getProduct(const std::string& id) {
        auto it = products.find(id);
        if (it != products.end()) {
            return &(it->second);
        }
        return nullptr;
    }

    std::vector<Product> getAllProducts() const {
        std::vector<Product> result;
        for (const auto& pair : products) {
            result.push_back(pair.second);
        }
        return result;
    }

    void customSort(std::vector<Product>& productList, SortType sortType) {
        if (sortType == SortType::ByPrice) {
            for (size_t i = 0; i < productList.size() - 1; i++) {
                for (size_t j = 0; j < productList.size() - i - 1; j++) {
                    if (productList[j].price > productList[j + 1].price) {
                        std::swap(productList[j], productList[j + 1]);
                    }
                }
            }
        } else if (sortType == SortType::ByGenre) {
            for (size_t i = 0; i < productList.size() - 1; i++) {
                for (size_t j = 0; j < productList.size() - i - 1; j++) {
                    if (productList[j].genre > productList[j + 1].genre) {
                        std::swap(productList[j], productList[j + 1]);
                    }
                }
            }
        }
    }
};

class CheckoutSystem {
private:
    struct CartItem {
        Product* product;
        int quantity;
    };

    std::vector<CartItem> cart;
    ProductCatalog& catalog;

public:
    CheckoutSystem(ProductCatalog& catalog) : catalog(catalog) {}

    void addToCart(const std::string& productId, int quantity) {
        Product* product = catalog.getProduct(productId);
        if (product) {
            for (auto& item : cart) {
                if (item.product->id == productId) {
                    item.quantity += quantity;
                    return;
                }
            }
            cart.push_back({product, quantity});
        }
    }

    void removeFromCart(const std::string& productId) {
        auto it = std::remove_if(cart.begin(), cart.end(),
            [&productId](const CartItem& item) {
                return item.product->id == productId;
            });
        cart.erase(it, cart.end());
    }

    double calculateItemDiscount(const CartItem& item) const {
        double discount = 0.0;

        // Category-based discounts
        if (item.product->category == Category::Book) {
            if (item.quantity >= 3) discount += 0.10; // 10% off for 3+ books
        } else if (item.product->category == Category::Magazine) {
            if (item.quantity >= 2) discount += 0.05; // 5% off for 2+ magazines
        }

        // Price-based discounts
        if (item.product->price >= 50.0) discount += 0.05; // 5% off for items $50+

        return discount;
    }

    double calculateTotal() const {
        double subtotal = 0.0;
        double totalDiscount = 0.0;

        for (const auto& item : cart) {
            double itemTotal = item.product->price * item.quantity;
            double itemDiscount = calculateItemDiscount(item) * itemTotal;

            subtotal += itemTotal;
            totalDiscount += itemDiscount;
        }

        // Additional total-based discount
        if (subtotal >= 100.0) {
            totalDiscount += subtotal * 0.05; // 5% off orders over $100
        }

        return subtotal - totalDiscount;
    }

    void displayReceipt() const {
