        std::cout << std::string(60, '-') << std::endl;

        double subtotal = 0.0;
        double totalDiscount = 0.0;

        for (const auto& item : cart) {
            double itemTotal = item.product->price * item.quantity;
            double itemDiscount = calculateItemDiscount(item) * itemTotal;

            std::cout << std::left << std::setw(30) << item.product->name 
                      << std::setw(10) << item.quantity
                      << "$" << std::setw(9) << std::fixed << std::setprecision(2) << item.product->price
                      << "$" << std::setw(9) << std::fixed << std::setprecision(2) << itemTotal << std::endl;

            if (itemDiscount > 0) {
                std::cout << std::left << std::setw(40) << "  Discount:" 
                          << "-$" << std::setw(8) << std::fixed << std::setprecision(2) << itemDiscount << std::endl;
            }

            subtotal += itemTotal;
            totalDiscount += itemDiscount;
        }

        std::cout << std::string(60, '-') << std::endl;
        std::cout << std::left << std::setw(40) << "Subtotal:" 
                  << "$" << std::setw(9) << std::fixed << std::setprecision(2) << subtotal << std::endl;

        // Order total discount
        double orderDiscount = 0.0;
        if (subtotal >= 100.0) {
            orderDiscount = subtotal * 0.05;
            std::cout << std::left << std::setw(40) << "Order Discount (5%):" 
