class Product {
public:
    std::string id;
    std::string name;
    std::string genre;
    double price;
    int quantity;

    Product(std::string id, std::string name, std::string genre, double price, int quantity)
        : id(id), name(name), genre(genre), price(price), quantity(quantity) {}
};

class ProductMap {
private:
    std::stack<Product> productStack;
    std::vector<Product> products;
    static const int MAX_ENTRIES = 500;

public:
    bool insert(const Product& product) {
        if (products.size() >= MAX_ENTRIES) {
            return false;
        }
        productStack.push(product);
        products.push_back(product);
        return true;
    }

    Product* retrieve(const std::string& id) {
        for (auto& product : products) {
            if (product.id == id) {
                return &product;
            }
        }
        return nullptr;
    }

    void push(const Product& product) {
        if (products.size() < MAX_ENTRIES) {
            productStack.push(product);
            products.push_back(product);
        }
    }

    void pop() {
        if (!productStack.empty() && !products.empty()) {
            productStack.pop();
            products.pop_back();
        }
    }

    std::vector<Product>& getAllProducts() {
        return products;
    }

    int size() const {
        return products.size();
    }
};

class CheckoutSystem {
private:
    ProductMap catalog;
    std::vector<std::pair<Product*, int>> cart;

public:
    void addProductToCatalog(const Product& product) {
        catalog.insert(product);
    }

    void addToCart(const std::string& productId, int quantity) {
        Product* product = catalog.retrieve(productId);
        if (product && product->quantity >= quantity) {
            cart.push_back(std::make_pair(product, quantity));
            product->quantity -= quantity;
        }
    }

    double calculateItemDiscount(const Product& product, int quantity) {
        if (quantity >= 5) {
            return product.price * quantity * 0.15;
        } else if (quantity >= 3) {
            return product.price * quantity * 0.10;
        }
        return 0.0;
    }

    double calculateTotalDiscount(double subtotal) {
        if (subtotal >= 100.0) {
            return subtotal * 0.20;
        } else if (subtotal >= 50.0) {
            return subtotal * 0.10;
        }
        return 0.0;
    }

    double calculateTotal() {
        double subtotal = 0.0;
        double totalItemDiscounts = 0.0;

        for (const auto& item : cart) {
            double itemTotal = item.first->price * item.second;
            double itemDiscount = calculateItemDiscount(*item.first, item.second);
            subtotal += itemTotal;
            totalItemDiscounts += itemDiscount;
        }

        double afterItemDiscounts = subtotal - totalItemDiscounts;
        double totalDiscount = calculateTotalDiscount(subtotal);

        return afterItemDiscounts - totalDiscount;
    }

    void sortCatalogByPrice(bool ascending = true) {
        std::vector<Product>& products = catalog.getAllProducts();
        if (ascending) {
            std::sort(products.begin(), products.end(), 
                [](const Product& a, const Product& b) {
                    return a.price < b.price;
                });
        } else {
            std::sort(products.begin(), products.end(), 
                [](const Product& a, const Product& b) {
                    return a.price > b.price;
                });
        }
    }

    void sortCatalogByGenre() {
        std::vector<Product>& products = catalog.getAllProducts();
        std::sort(products.begin(), products.end(), 
            [](const Product& a, const Product& b) {
                return a.genre < b.genre;
            });
    }

    void displayCart() {
        std::cout << "Cart Contents:\n";
        for (const auto& item : cart) {
            std::cout << item.first->name << " x" << item.second 
                      << " - $" << item.first->price * item.second << std::endl;
        }
        std::cout << "Total: $" << calculateTotal() << std::endl;
    }

    void displayCatalog() {
        std::vector<Product>& products = catalog.getAllProducts();
        std::cout << "Product Catalog:\n";
        for (const auto& product : products) {
            std::cout << product.id << ": " << product.name 
                      << " (" << product.genre << ") - $" << product.price 
                      << " [Stock: " << product.quantity << "]\n";
        }
    }

    void clearCart() {
        cart.clear();
    }
};

int main() {
    CheckoutSystem bookstore;

    bookstore.addProductToCatalog(Product("B001", "The Great Gatsby", "Fiction", 12.99, 10));
    bookstore.addProductToCatalog(Product("B002", "Data Structures", "Computer Science", 45.50, 5));
    bookstore.addProductToCatalog(Product("B003", "Mystery Novel", "Mystery", 8.99, 15));
    bookstore.addProductToCatalog(Product("B004", "History of Art", "Art", 35.00, 8));
    bookstore.addProductToCatalog(Product("B005", "Programming Guide", "Computer Science", 55.99, 12));

    std::cout << "=== Bookstore Checkout System ===\n\n";

    bookstore.displayCatalog();
