    std::string category;

    Product() = default;
    Product(const std::string& id, const std::string& title, const std::string& genre, 
            double price, int quantity, const std::string& category)
        : id(id), title(title), genre(genre), price(price), quantity(quantity), category(category) {}
};

class BookstoreCheckout {
private:
    std::map<std::string, Product> productCatalog;
    std::stack<Product> productStack;
    std::vector<std::pair<Product, int>> cart;

    static const int MAX_CATALOG_SIZE = 500;
    static const int MAX_STACK_SIZE = 150;

public:
    bool addProductToCatalog(const Product& product) {
        if (productCatalog.size() >= MAX_CATALOG_SIZE) {
            return false;
        }
        productCatalog[product.id] = product;
        return true;
    }

    bool pushToStack(const Product& product) {
        if (productStack.size() >= MAX_STACK_SIZE) {
            return false;
        }
        productStack.push(product);
        return true;
    }

    bool popFromStack() {
        if (productStack.empty()) {
            return false;
        }
        productStack.pop();
        return true;
    }

    Product getTopFromStack() {
        if (!productStack.empty()) {
            return productStack.top();
        }
        return Product();
    }

    void addToCart(const std::string& productId, int quantity) {
        auto it = productCatalog.find(productId);
        if (it != productCatalog.end() && it->second.quantity >= quantity) {
            cart.push_back({it->second, quantity});
            it->second.quantity -= quantity;
        }
    }

    double calculateItemDiscount(const Product& product, int quantity) {
        double discount = 0.0;
        if (product.category == "Fiction" && quantity >= 3) {
            discount = 0.15;
        } else if (product.category == "Non-Fiction" && quantity >= 2) {
            discount = 0.10;
        } else if (product.category == "Textbook" && quantity >= 1) {
            discount = 0.05;
        }
        return discount;
    }

    double calculateTotalDiscount(double subtotal) {
        if (subtotal > 100.0) {
            return 0.20;
        } else if (subtotal > 50.0) {
            return 0.10;
        }
        return 0.0;
    }

    double calculateTotal() {
        double subtotal = 0.0;

        for (const auto& item : cart) {
            double itemDiscount = calculateItemDiscount(item.first, item.second);
            double itemTotal = item.first.price * item.second * (1.0 - itemDiscount);
            subtotal += itemTotal;
        }

        double totalDiscount = calculateTotalDiscount(subtotal);
        return subtotal * (1.0 - totalDiscount);
    }

    void sortCatalogByPrice(bool ascending = true) {
        std::vector<std::pair<std::string, Product>> temp(productCatalog.begin(), productCatalog.end());

        std::sort(temp.begin(), temp.end(), [ascending](const auto& a, const auto& b) {
            return ascending ? a.second.price < b.second.price : a.second.price > b.second.price;
        });

        productCatalog.clear();
        for (const auto& item : temp) {
            productCatalog[item.first] = item.second;
        }
    }

    void sortCatalogByGenre() {
        std::vector<std::pair<std::string, Product>> temp(productCatalog.begin(), productCatalog.end());

        std::sort(temp.begin(), temp.end(), [](const auto& a, const auto& b) {
            return a.second.genre < b.second.genre;
        });

        productCatalog.clear();
        for (const auto& item : temp) {
            productCatalog[item.first] = item.second;
        }
    }

    void displayCatalog() {
        for (const auto& item : productCatalog) {
            const Product& p = item.second;
            std::cout << "ID: " << p.id << ", Title: " << p.title 
                      << ", Genre: " << p.genre << ", Price: $" << std::fixed << std::setprecision(2) << p.price
                      << ", Quantity: " << p.quantity << ", Category: " << p.category << std::endl;
        }
    }

    void displayCart() {
        std::cout << "\n--- Cart Contents ---" << std::endl;
        double total = 0.0;

        for (const auto& item : cart) {
            double itemDiscount = calculateItemDiscount(item.first, item.second);
            double itemTotal = item.first.price * item.second * (1.0 - itemDiscount);
            total += itemTotal;

            std::cout << item.first.title << " x" << item.second 
                      << " - $" << std::fixed << std::setprecision(2) << itemTotal;
            if (itemDiscount > 0) {
                std::cout << " (Discount: " << (itemDiscount * 100) << "%)";
            }
            std::cout << std::endl;
        }

        double totalDiscount = calculateTotalDiscount(total);
        double finalTotal = total * (1.0 - totalDiscount);

        std::cout << "Subtotal: $" << std::fixed << std::setprecision(2) << total << std::endl;
        if (totalDiscount > 0) {
            std::cout << "Total Discount: " << (totalDiscount * 100) << "%" << std::endl;
        }
        std::cout << "Final Total: $" << std::fixed << std::setprecision(2) << finalTotal << std::endl;
    }

    void clearCart() {
        cart.clear();
    }

    int getCatalogSize() const {
        return productCatalog.size();
    }

    int getStackSize() const {
        return productStack.size();
    }
};

int main() {
    BookstoreCheckout checkout;

    // Add products to catalog
    checkout.addProductToCatalog(Product("001", "The Great Gatsby", "Classic", 12.99, 10, "Fiction"));
    checkout.addProductToCatalog(Product("002", "Data Structures", "Computer Science", 89.99, 5, "Textbook"));
