// Structure to keep track of elements in the min-heap
struct HeapNode {
    int value;
    int arrayIndex;
    int elementIndex;

    // Custom comparison operator for min-heap
    bool operator>(const HeapNode& other) const {
        return value > other.value;
    }
};

// Function to merge the sorted arrays
std::vector<int> mergeSortedArrays(const std::vector<std::vector<int>>& arrays) {
    std::vector<int> result;

    // Create a min-heap using priority_queue with custom comparison
    std::priority_queue<HeapNode, std::vector<HeapNode>, std::greater<HeapNode>> minHeap;

    // Insert the first element from each array into the min-heap
    for (int i = 0; i < arrays.size(); i++) {
        if (!arrays[i].empty()) {
            minHeap.push({arrays[i][0], i, 0});
        }
    }

    // Process the min-heap
    while (!minHeap.empty()) {
        // Extract the minimum element
        HeapNode node = minHeap.top();
        minHeap.pop();

        // Add the minimum element to the result
        result.push_back(node.value);

        // If there are more elements in the array, add the next element to the heap
        if (node.elementIndex + 1 < arrays[node.arrayIndex].size()) {
            minHeap.push({
                arrays[node.arrayIndex][node.elementIndex + 1],
                node.arrayIndex,
                node.elementIndex + 1
            });
        }
    }

    return result;
}

