struct Element {
    int value;
    int arrayIndex;
    int elementIndex;

    bool operator>(const Element& other) const {
        return value > other.value;
    }
};

class ArrayMerger {
private:
    std::priority_queue<Element, std::vector<Element>, std::greater<Element>> minHeap;
    std::vector<std::vector<int>> arrays;
    std::vector<int> result;

public:
    void addArray(const std::vector<int>& arr) {
        if (arrays.size() >= 10) {
            std::cerr << "Error: Maximum 10 arrays allowed" << std::endl;
            return;
        }
        if (arr.size() > 200) {
            std::cerr << "Error: Array size exceeds 200 elements" << std::endl;
            return;
        }
        arrays.push_back(arr);
    }

    void merge() {
        // Initialize heap with first element from each array
        for (int i = 0; i < arrays.size(); i++) {
            if (!arrays[i].empty()) {
                minHeap.push({arrays[i][0], i, 0});
            }
        }

        // Merge process
        while (!minHeap.empty()) {
            Element current = minHeap.top();
            minHeap.pop();

            result.push_back(current.value);

            // Add next element from the same array if available
            if (current.elementIndex + 1 < arrays[current.arrayIndex].size()) {
                minHeap.push({
                    arrays[current.arrayIndex][current.elementIndex + 1],
                    current.arrayIndex,
                    current.elementIndex + 1
                });
            }
        }
    }

    void outputToConsole() {
        for (int i = 0; i < result.size(); i++) {
            std::cout << result[i];
            if (i < result.size() - 1) std::cout << " ";
        }
        std::cout << std::endl;
    }

