private:
    std::deque<Employee> employees;
    const size_t MAX_CAPACITY = 800;

public:
    bool addEmployee(const Employee& employee) {
        if (employees.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Employee deque has reached maximum capacity");
        }
        employees.push_back(employee);
        return true;
    }

    void sortByAge() {
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), 
            [](const Employee& a, const Employee& b) {
                return a.getAge() < b.getAge();
            });
    }

    void sortByName() {
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), 
            [](const Employee& a, const Employee& b) {
                return a.getName() < b.getName();
            });
    }

    const std::deque<Employee>& getEmployees() const {
        return employees;
    }

    size_t getCount() const {
        return employees.size();
    }
};

