class Employee {
private:
    std::string name;
    int age;

public:
    Employee(const std::string& name, int age) : name(name), age(age) {
        if (name.empty()) {
            throw std::invalid_argument("Employee name cannot be empty");
        }
        if (age < 0 || age > 150) {
            throw std::invalid_argument("Employee age must be between 0 and 150");
        }
    }

    const std::string& getName() const { return name; }
    int getAge() const { return age; }

    void setName(const std::string& newName) {
        if (newName.empty()) {
            throw std::invalid_argument("Employee name cannot be empty");
        }
        name = newName;
    }

    void setAge(int newAge) {
        if (newAge < 0 || newAge > 150) {
            throw std::invalid_argument("Employee age must be between 0 and 150");
        }
        age = newAge;
    }
};

class EmployeeManager {
private:
    std::deque<Employee> employees;
    static const size_t MAX_CAPACITY = 800;

public:
    void addEmployee(const Employee& emp) {
        if (employees.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Cannot add employee: deque capacity exceeded");
        }
        employees.push_back(emp);
    }

    void removeLastEmployee() {
        if (employees.empty()) {
            throw std::underflow_error("Cannot remove employee: deque is empty");
        }
        employees.pop_back();
    }

    static bool compareByAge(const Employee& a, const Employee& b) {
        return a.getAge() < b.getAge();
    }

    static bool compareByName(const Employee& a, const Employee& b) {
        return a.getName() < b.getName();
    }

    static bool compareByAgeAndName(const Employee& a, const Employee& b) {
        if (a.getAge() != b.getAge()) {
            return a.getAge() < b.getAge();
        }
        return a.getName() < b.getName();
    }

    void sortByAge() {
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), compareByAge);
    }

    void sortByName() {
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), compareByName);
    }

    void sortByAgeAndName() {
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), compareByAgeAndName);
    }

    void printEmployees() const {
        if (employees.empty()) {
            std::cout << "No employees to display.\n";
            return;
        }
        for (const auto& emp : employees) {
            std::cout << "Name: " << emp.getName() << ", Age: " << emp.getAge() << std::endl;
        }
    }

    size_t size() const {
        return employees.size();
    }

    bool empty() const {
        return employees.empty();
    }
};

