        return e1.getName() < e2.getName();
    }
};

class ThreadSafeEmployeeDeque {
private:
    std::deque<Employee> employees;
    std::mutex mutex;
    const size_t MAX_CAPACITY = 800;

public:
    void push_back(const Employee& employee) {
        std::lock_guard<std::mutex> lock(mutex);
        if (employees.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Deque capacity exceeded");
        }
        employees.push_back(employee);
    }

    Employee pop_back() {
        std::lock_guard<std::mutex> lock(mutex);
        if (employees.empty()) {
            throw std::underflow_error("Deque is empty");
        }
        Employee employee = employees.back();
        employees.pop_back();
        return employee;
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mutex);
        return employees.empty();
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mutex);
        return employees.size();
    }

