            throw std::invalid_argument("Employee name cannot be empty");
        }
        if (age < 0 || age > 150) {
            throw std::invalid_argument("Employee age must be between 0 and 150");
        }
    }

    const std::string& getName() const { return name; }
    int getAge() const { return age; }

    void setName(const std::string& newName) {
        if (newName.empty()) {
            throw std::invalid_argument("Employee name cannot be empty");
        }
        name = newName;
    }

    void setAge(int newAge) {
        if (newAge < 0 || newAge > 150) {
            throw std::invalid_argument("Employee age must be between 0 and 150");
        }
        age = newAge;
    }
};

struct EmployeeComparator {
    bool operator()(const Employee& a, const Employee& b) const {
        if (a.getAge() != b.getAge()) {
            return a.getAge() < b.getAge();
        }
        return a.getName() < b.getName();
    }
};

class ThreadSafeEmployeeDeque {
private:
    std::deque<Employee> employees;
    mutable std::mutex mtx;
    static const size_t MAX_SIZE = 600;

public:
    void push_back(const Employee& employee) {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.size() >= MAX_SIZE) {
            throw std::runtime_error("Deque has reached maximum capacity of 600 employees");
        }
        employees.push_back(employee);
    }

    void pop_back() {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            throw std::runtime_error("Cannot pop from empty deque");
        }
        employees.pop_back();
    }

    void stableSort() {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            return;
        }
        std::stable_sort(employees.begin(), employees.end(), EmployeeComparator());
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.size();
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return employees.empty();
    }

    Employee back() const {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            throw std::runtime_error("Cannot access back element of empty deque");
        }
        return employees.back();
    }

    Employee front() const {
        std::lock_guard<std::mutex> lock(mtx);
        if (employees.empty()) {
            throw std::runtime_error("Cannot access front element of empty deque");
        }
        return employees.front();
    }

    void clear() {
        std::lock_guard<std::mutex> lock(mtx);
        employees.clear();
    }
};

class EmployeeManager {
private:
    ThreadSafeEmployeeDeque employeeDeque;

public:
    void addEmployee(const std::string& name, int age) {
        if (name.empty()) {
            return;
        }
        try {
            Employee emp(name, age);
            employeeDeque.push_back(emp);
        } catch (const std::exception& e) {
            throw;
        }
    }

    void removeLastEmployee() {
        if (!employeeDeque.empty()) {
            employeeDeque.pop_back();
        }
    }

    void sortEmployees() {
        employeeDeque.stableSort();
    }

    size_t getEmployeeCount() const {
        return employeeDeque.size();
    }

    bool isEmpty() const {
        return employeeDeque.empty();
    }

    Employee getLastEmployee() const {
        return employeeDeque.back();
    }

    Employee getFirstEmployee() const {
        return employeeDeque.front();
    }

    void clearAllEmployees() {
        employeeDeque.clear();
    }
};
