        args[2].parse::<usize>().unwrap_or(10)
    } else {
        10
    };

    let path = Path::new(filename);
    let file = File::open(path)?;
    let reader = BufReader::new(file);

    let mut word_counts: HashMap<String, usize> = HashMap::with_capacity(10000);

    for line in reader.lines() {
        let line = line?;
        let words = tokenize(&line);

        for word in words {
            if !word.is_empty() {
                let count = word_counts.entry(word).or_insert(0);
                *count += 1;

                // Ensure hashmap doesn't exceed size limit
                if word_counts.len() > 10000 {
                    remove_least_frequent_word(&mut word_counts);
                }
            }
        }
    }

    display_most_frequent(word_counts, top_n);

    Ok(())
}

fn tokenize(text: &str) -> Vec<String> {
    text.split(|c: char| !c.is_alphabetic())
        .map(|word| word.to_lowercase())
        .filter(|word| !word.is_empty())
        .collect()
}

fn remove_least_frequent_word(word_counts: &mut HashMap<String, usize>) {
    if let Some((least_frequent_word, _)) = word_counts
        .iter()
        .min_by_key(|(_, count)| **count) {
        let key_to_remove = least_frequent_word.clone();
        word_counts.remove(&key_to_remove);
    }
}

fn display_most_frequent(word_counts: HashMap<String, usize>, n: usize) {
    let mut counts: Vec<(String, usize)> = word_counts.into_iter().collect();
    counts.sort_by(|a, b| b.1.cmp(&a.1));

    println!("Top {} most frequent words:", n);
    for (i, (word, count)) in counts.iter().take(n).enumerate() {
        println!("{}. {} - {} occurrences", i + 1, word, count);
    }
}
