        Self {
            map: HashMap::new(),
            max_size,
        }
    }

    fn insert(&mut self, key: String, value: usize) -> bool {
        if self.map.contains_key(&key) {
            *self.map.get_mut(&key).unwrap() += value;
            true
        } else if self.map.len() < self.max_size {
            self.map.insert(key, value);
            true
        } else {
            false
        }
    }

    fn get(&self, key: &str) -> Option<&usize> {
        self.map.get(key)
    }

    fn display_tree(&self, words: &[(String, usize)], depth: usize, index: usize) {
        if index >= words.len() {
            return;
        }

        let indent = "  ".repeat(depth);
        println!("{}├── {}: {}", indent, words[index].0, words[index].1);

        let left_child = 2 * index + 1;
        let right_child = 2 * index + 2;

        if left_child < words.len() {
            self.display_tree(words, depth + 1, left_child);
        }
        if right_child < words.len() {
            self.display_tree(words, depth + 1, right_child);
        }
    }

    fn display_hierarchical(&self) {
        let mut words: Vec<(String, usize)> = self.map.iter()
            .map(|(k, v)| (k.clone(), *v))
            .collect();
        words.sort_by(|a, b| b.1.cmp(&a.1));

        println!("Word Frequency Tree:");
        if !words.is_empty() {
            self.display_tree(&words, 0, 0);
        }
    }

    fn get_sorted_words(&self) -> Vec<(String, usize)> {
        let mut words: Vec<(String, usize)> = self.map.iter()
            .map(|(k, v)| (k.clone(), *v))
            .collect();
        words.sort_by(|a, b| b.1.cmp(&a.1));
        words
    }
}

