struct LimitedHashMap {
    data: Vec<(String, u32)>,
    max_size: usize,
}

impl LimitedHashMap {
    fn new(max_size: usize) -> Self {
        LimitedHashMap {
            data: Vec::new(),
            max_size,
        }
    }

    fn insert(&mut self, key: String, value: u32) {
        for (existing_key, existing_value) in &mut self.data {
            if *existing_key == key {
                *existing_value = value;
                return;
            }
        }

        if self.data.len() < self.max_size {
            self.data.push((key, value));
        }
    }

    fn get(&self, key: &str) -> Option<u32> {
        for (existing_key, value) in &self.data {
            if existing_key == key {
                return Some(*value);
            }
        }
        None
    }

    fn increment(&mut self, key: String) {
        let current_value = self.get(&key).unwrap_or(0);
        self.insert(key, current_value + 1);
    }

    fn display_tree(&self, level: usize, index: usize) {
        if index >= self.data.len() {
            return;
        }

        let indent = "  ".repeat(level);
        println!("{}├── {}: {}", indent, self.data[index].0, self.data[index].1);

        let left_child = 2 * index + 1;
        let right_child = 2 * index + 2;

        if left_child < self.data.len() {
            self.display_tree(level + 1, left_child);
        }
        if right_child < self.data.len() {
            self.display_tree(level + 1, right_child);
        }
    }

    fn display(&self) {
        if self.data.is_empty() {
            println!("Empty hash map");
            return;
        }
        println!("Hash Map Tree Structure:");
        self.display_tree(0, 0);
    }

    fn get_sorted_by_frequency(&self) -> Vec<(String, u32)> {
        let mut sorted_data = self.data.clone();
        sorted_data.sort_by(|a, b| b.1.cmp(&a.1));
        sorted_data
    }
