enum QueueError {
    QueueFull,
    MessageNotFound,
    InvalidOperation,
}

impl fmt::Display for QueueError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            QueueError::QueueFull => write!(f, "Queue is full (max 500 messages)"),
            QueueError::MessageNotFound => write!(f, "Message not found"),
            QueueError::InvalidOperation => write!(f, "Invalid operation"),
        }
    }
}

impl Error for QueueError {}

struct MessageQueue {
    queue: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    fn new() -> Self {
        MessageQueue {
            queue: LinkedList::new(),
            max_size: 500,
        }
    }

    fn enqueue(&mut self, id: u64, content: String) -> Result<(), QueueError> {
        if self.queue.len() >= self.max_size {
            return Err(QueueError::QueueFull);
        }

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        let message = Message {
            id,
            content,
            timestamp,
        };

        self.queue.push_back(message);
        Ok(())
    }

    fn dequeue(&mut self) -> Result<Message, QueueError> {
        self.queue.pop_front().ok_or(QueueError::InvalidOperation)
    }

    fn lookup(&self, id: u64) -> Result<&Message, QueueError> {
        self.queue
            .iter()
            .find(|msg| msg.id == id)
            .ok_or(QueueError::MessageNotFound)
    }

    fn size(&self) -> usize {
        self.queue.len()
    }
}

