        Ok(_) => println!("Message 2 enqueued"),
        Err(e) => eprintln!("Error: {}", e),
    }

    // Lookup message
    match queue.lookup(1) {
        Ok(msg) => println!("Found message: {:?}", msg),
        Err(e) => eprintln!("Error: {}", e),
    }

