pub enum QueueError {
    QueueOverflow,
    QueueEmpty,
    MessageNotFound,
    InvalidOperation,
}

impl std::fmt::Display for QueueError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            QueueError::QueueOverflow => write!(f, "Queue overflow: maximum capacity of 500 messages exceeded"),
            QueueError::QueueEmpty => write!(f, "Queue is empty"),
            QueueError::MessageNotFound => write!(f, "Message not found"),
            QueueError::InvalidOperation => write!(f, "Invalid operation"),
        }
    }
}

impl std::error::Error for QueueError {}

pub struct MessageQueue {
    queue: LinkedList<Message>,
    max_capacity: usize,
}

impl MessageQueue {
    pub fn new() -> Self {
        MessageQueue {
            queue: LinkedList::new(),
            max_capacity: 500,
        }
    }

    pub fn push(&mut self, message: Message) -> Result<(), QueueError> {
        if self.queue.len() >= self.max_capacity {
            return Err(QueueError::QueueOverflow);
        }

        self.queue.push_back(message);
        Ok(())
    }

    pub fn pop(&mut self) -> Result<Message, QueueError> {
        self.queue.pop_back().ok_or(QueueError::QueueEmpty)
    }

