        self.queue
            .iter()
            .find(|msg| msg.id == id)
            .ok_or(QueueError::MessageNotFound)
    }

    pub fn size(&self) -> usize {
        self.queue.len()
    }

    pub fn is_empty(&self) -> bool {
        self.queue.is_empty()
    }

    pub fn is_full(&self) -> bool {
        self.queue.len() >= self.max_capacity
    }
}

