use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::time::{SystemTime, UNIX_EPOCH};
use std::thread;
use std::time::Duration;

#[derive(Debug, Clone)]
pub struct Message {
    pub id: u64,
    pub content: String,
    pub timestamp: u64,
}

impl Message {
    pub fn new(id: u64, content: String) -> Self {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        Message {
            id,
            content,
            timestamp,
        }
    }

    pub fn is_expired(&self, expiration_seconds: u64) -> bool {
        let current_time = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_secs();

        current_time - self.timestamp > expiration_seconds
    }
}

#[derive(Debug)]
pub enum QueueError {
    QueueOverflow,
    QueueEmpty,
    MessageNotFound,
    InvalidOperation,
}

impl std::fmt::Display for QueueError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            QueueError::QueueOverflow => write!(f, "Queue has reached maximum capacity"),
            QueueError::QueueEmpty => write!(f, "Queue is empty"),
            QueueError::MessageNotFound => write!(f, "Message with specified ID not found"),
            QueueError::InvalidOperation => write!(f, "Invalid operation attempted"),
        }
    }
}

impl std::error::Error for QueueError {}

pub struct MessageQueue {
    queue: Arc<Mutex<LinkedList<Message>>>,
    max_capacity: usize,
    expiration_seconds: u64,
}

impl MessageQueue {
    pub fn new() -> Self {
        MessageQueue {
            queue: Arc::new(Mutex::new(LinkedList::new())),
            max_capacity: 500,
            expiration_seconds: 30,
        }
    }

    pub fn push(&self, message: Message) -> Result<(), QueueError> {
        let mut queue = self.queue.lock().unwrap();

        self.cleanup_expired_messages(&mut queue);

        if queue.len() >= self.max_capacity {
            return Err(QueueError::QueueOverflow);
        }

        queue.push_back(message);
        Ok(())
    }

    pub fn pop(&self) -> Result<Message, QueueError> {
        let mut queue = self.queue.lock().unwrap();

        self.cleanup_expired_messages(&mut queue);

        queue.pop_back().ok_or(QueueError::QueueEmpty)
    }

    pub fn lookup(&self, id: u64) -> Result<Message, QueueError> {
        let mut queue = self.queue.lock().unwrap();

        self.cleanup_expired_messages(&mut queue);

        for message in queue.iter() {
            if message.id == id {
                return Ok(message.clone());
            }
        }

        Err(QueueError::MessageNotFound)
    }

    pub fn size(&self) -> usize {
        let mut queue = self.queue.lock().unwrap();
        self.cleanup_expired_messages(&mut queue);
        queue.len()
    }

    fn cleanup_expired_messages(&self, queue: &mut LinkedList<Message>) {
        queue.retain(|message| !message.is_expired(self.expiration_seconds));
    }

    pub fn start_cleanup_thread(&self) -> thread::JoinHandle<()> {
        let queue_clone = Arc::clone(&self.queue);
        let expiration_seconds = self.expiration_seconds;

        thread::spawn(move || {
            loop {
                thread::sleep(Duration::from_secs(5));

                let mut queue = queue_clone.lock().unwrap();
                queue.retain(|message| !message.is_expired(expiration_seconds));
            }
        })
    }
}

