        let mut queue = self.messages.lock().unwrap();

        self.cleanup_old_messages(&mut queue);

        queue.pop_back().ok_or(QueueError::QueueEmpty)
    }

    pub fn get_by_id(&self, id: u64) -> Result<Message, QueueError> {
        let mut queue = self.messages.lock().unwrap();

        self.cleanup_old_messages(&mut queue);

        for message in queue.iter() {
            if message.id == id {
                return Ok(message.clone());
            }
        }

