    bool isActive;
};

class CinemaBookingSystem {
private:
    std::vector<Reservation> reservations;
    std::mutex bookingMutex;
    const size_t MAX_RESERVATIONS = 10000;
    int totalSeats;

public:
    CinemaBookingSystem(int seats) : totalSeats(seats) {
        reservations.reserve(MAX_RESERVATIONS);
    }

    bool checkSeatAvailability(int seatId) {
        if (seatId <= 0 || seatId > totalSeats) {
            throw std::out_of_range("Invalid seat number");
        }

        std::lock_guard<std::mutex> lock(bookingMutex);
        for (const auto& res : reservations) {
            if (res.seatId == seatId && res.isActive) {
                return false;
            }
        }
        return true;
    }

    void makeReservation(int seatId, const std::string& customerName) {
        if (reservations.size() >= MAX_RESERVATIONS) {
            throw std::runtime_error("Booking system capacity reached");
        }

        if (!checkSeatAvailability(seatId)) {
            throw std::runtime_error("Seat already booked");
        }

        std::lock_guard<std::mutex> lock(bookingMutex);
        reservations.push_back({seatId, customerName, true});
        std::cout << "Seat " << seatId << " reserved for " << customerName << std::endl;
    }

    void cancelReservation(int seatId, const std::string& customerName) {
        std::lock_guard<std::mutex> lock(bookingMutex);

        for (auto it = reservations.begin(); it != reservations.end(); ++it) {
            if (it->seatId == seatId && it->customerName == customerName && it->isActive) {
                it->isActive = false;
                std::cout << "Reservation for seat " << seatId << " canceled" << std::endl;
                return;
            }
        }

        throw std::runtime_error("Reservation not found");
    }

    void displayReservations() {
        std::lock_guard<std::mutex> lock(bookingMutex);
        std::cout << "Current active reservations:" << std::endl;
        for (const auto& res : reservations) {
            if (res.isActive) {
                std::cout << "Seat " << res.seatId << ": " << res.customerName << std::endl;
            }
        }
    }
};

