    std::mutex reservationMutex;
    int totalRows;
    int seatsPerRow;

public:
    CinemaReservationSystem(int rows, int seats) : totalRows(rows), seatsPerRow(seats) {
        reservations.reserve(MAX_RESERVATIONS);
    }

    bool isSeatAvailable(int row, int seat) {
        if (row <= 0 || row > totalRows || seat <= 0 || seat > seatsPerRow) {
            throw std::invalid_argument("Invalid seat or row number");
        }

        std::lock_guard<std::mutex> lock(reservationMutex);
        for (const auto& res : reservations) {
            if (res.row == row && res.seat == seat && res.isActive) {
                return false;
            }
        }
        return true;
    }

    int makeReservation(int row, int seat, const std::string& customerName) {
        if (row <= 0 || row > totalRows || seat <= 0 || seat > seatsPerRow) {
            throw std::invalid_argument("Invalid seat or row number");
        }

        std::lock_guard<std::mutex> lock(reservationMutex);

        if (reservations.size() >= MAX_RESERVATIONS) {
            throw std::runtime_error("Maximum reservation capacity reached");
        }

        for (const auto& res : reservations) {
            if (res.row == row && res.seat == seat && res.isActive) {
                throw std::runtime_error("Seat is already reserved");
            }
        }

        Reservation newReservation{row, seat, customerName, true};
        reservations.push_back(newReservation);
        return reservations.size() - 1; // Return reservation ID
    }

    void cancelReservation(int reservationId) {
        std::lock_guard<std::mutex> lock(reservationMutex);

        if (reservationId < 0 || reservationId >= reservations.size()) {
            throw std::invalid_argument("Invalid reservation ID");
        }

        if (!reservations[reservationId].isActive) {
            throw std::runtime_error("Reservation already cancelled");
        }

        reservations[reservationId].isActive = false;
    }

    void displayReservations() {
        std::lock_guard<std::mutex> lock(reservationMutex);
        std::cout << "Current Reservations (" << reservations.size() << "/" << MAX_RESERVATIONS << "):" << std::endl;

        for (size_t i = 0; i < reservations.size(); i++) {
            if (reservations[i].isActive) {
                std::cout << "ID: " << i 
                          << ", Row: " << reservations[i].row 
                          << ", Seat: " << reservations[i].seat 
                          << ", Customer: " << reservations[i].customerName << std::endl;
            }
        }
    }
