#include <iostream>
#include <stack>
#include <vector>
#include <string>
#include <stdexcept>
#include <map>

class CinemaSeatReservation {
private:
    static const int MAX_RESERVATIONS = 10000;
    std::stack<std::string> reservationStack;
    std::map<std::string, bool> seatAvailability;
    int totalSeats;

public:
    CinemaSeatReservation(int seats) : totalSeats(seats) {
        for (int i = 1; i <= seats; i++) {
            seatAvailability["S" + std::to_string(i)] = true;
        }
    }

    void makeReservation(const std::string& seatId) {
        if (reservationStack.size() >= MAX_RESERVATIONS) {
            throw std::overflow_error("Maximum reservation limit reached");
        }

        if (seatAvailability.find(seatId) == seatAvailability.end()) {
            throw std::invalid_argument("Invalid seat ID");
        }

        if (!seatAvailability[seatId]) {
            throw std::runtime_error("Seat already booked");
        }

        reservationStack.push(seatId);
        seatAvailability[seatId] = false;
        std::cout << "Reservation confirmed for seat: " << seatId << std::endl;
    }

    void cancelLastReservation() {
        if (reservationStack.empty()) {
            throw std::underflow_error("No reservations to cancel");
        }

        std::string lastSeat = reservationStack.top();
        reservationStack.pop();
        seatAvailability[lastSeat] = true;
        std::cout << "Cancelled reservation for seat: " << lastSeat << std::endl;
    }

    bool isSeatAvailable(const std::string& seatId) {
        if (seatAvailability.find(seatId) == seatAvailability.end()) {
            return false;
        }
        return seatAvailability[seatId];
    }

    int getReservationCount() {
        return reservationStack.size();
    }

    void displayAvailableSeats() {
        std::cout << "Available seats: ";
        for (const auto& seat : seatAvailability) {
            if (seat.second) {
                std::cout << seat.first << " ";
            }
        }
        std::cout << std::endl;
    }

    void processMultipleReservations(const std::vector<std::string>& seatIds) {
        for (const std::string& seatId : seatIds) {
            try {
                makeReservation(seatId);
            } catch (const std::exception& e) {
                std::cout << "Error booking seat " << seatId << ": " << e.what() << std::endl;
            }
        }
    }
};

int main() {
    try {
        CinemaSeatReservation cinema(50);

        std::vector<std::string> reservations = {"S1", "S2", "S3", "S1", "S4"};
        cinema.processMultipleReservations(reservations);

        std::cout << "Total reservations: " << cinema.getReservationCount() << std::endl;
        cinema.displayAvailableSeats();

        cinema.cancelLastReservation();
        cinema.cancelLastReservation();

        std::cout << "After cancellations - Total reservations: " << cinema.getReservationCount() << std::endl;
        cinema.displayAvailableSeats();

    } catch (const std::exception& e) {
        std::cout << "System error: " << e.what() << std::endl;
    }

    return 0;
