import heapq
from datetime import datetime, timedelta
from typing import List, Tuple, Optional

class TaskManager:
    def __init__(self):
        self.heap: List[Tuple[datetime, int, str]] = []
        self.task_counter = 0
        self.max_tasks = 50

    def add_task(self, description: str, deadline: datetime) -> bool:
        if len(self.heap) >= self.max_tasks:
            return False

        self.task_counter += 1
        task = (deadline, self.task_counter, description)
        heapq.heappush(self.heap, task)
        return True

    def get_next_task(self) -> Optional[Tuple[datetime, str]]:
        if not self.heap:
            return None

        deadline, _, description = heapq.heappop(self.heap)
        return (deadline, description)

    def update_task(self, old_description: str, new_deadline: datetime, new_description: str) -> bool:
        temp_tasks = []
        found = False

        while self.heap:
            task = heapq.heappop(self.heap)
            if task[2] == old_description and not found:
                found = True
                self.task_counter += 1
                updated_task = (new_deadline, self.task_counter, new_description)
                temp_tasks.append(updated_task)
            else:
                temp_tasks.append(task)

        for task in temp_tasks:
            heapq.heappush(self.heap, task)

        return found

    def delete_task(self, description: str) -> bool:
        temp_tasks = []
        found = False

        while self.heap:
            task = heapq.heappop(self.heap)
            if task[2] == description and not found:
                found = True
            else:
                temp_tasks.append(task)

        for task in temp_tasks:
            heapq.heappush(self.heap, task)

        return found

    def replace_earliest_task(self, new_description: str, new_deadline: datetime) -> Optional[Tuple[datetime, str]]:
        if not self.heap:
            return None

        self.task_counter += 1
        new_task = (new_deadline, self.task_counter, new_description)
        old_task = heapq.heapreplace(self.heap, new_task)
        return (old_task[0], old_task[2])

    def peek_next_task(self) -> Optional[Tuple[datetime, str]]:
        if not self.heap:
            return None
        return (self.heap[0][0], self.heap[0][2])

    def get_task_count(self) -> int:
        return len(self.heap)

    def is_full(self) -> bool:
        return len(self.heap) >= self.max_tasks

def main():
    task_manager = TaskManager()

    sample_tasks = [
        ("Complete project proposal", datetime.now() + timedelta(days=3)),
        ("Submit tax documents", datetime.now() + timedelta(days=1)),
        ("Attend team meeting", datetime.now() + timedelta(hours=2)),
        ("Review code changes", datetime.now() + timedelta(days=2)),
        ("Prepare presentation", datetime.now() + timedelta(days=5))
    ]

    for desc, deadline in sample_tasks:
        task_manager.add_task(desc, deadline)

    print(f"Tasks added. Current count: {task_manager.get_task_count()}")

    next_task = task_manager.peek_next_task()
    if next_task:
        print(f"Next task: {next_task[1]} (Due: {next_task[0]})")

    completed_task = task_manager.get_next_task()
    if completed_task:
        print(f"Completed task: {completed_task[1]}")

    task_manager.update_task("Review code changes", datetime.now() + timedelta(hours=1), "Urgent code review")

    task_manager.delete_task("Prepare presentation")

    if task_manager.is_full():
        replaced = task_manager.replace_earliest_task("Emergency task", datetime.now() + timedelta(minutes=30))
        if replaced:
            print(f"Replaced task: {replaced[1]}")

if __name__ == "__main__":
    main()
