import datetime

class TaskManager:
    def __init__(self):
        self.tasks = []
        self.capacity = 50

    def add_task(self, task_name, deadline, priority):
        if len(self.tasks) >= self.capacity:
            return False

        task = {
            'name': task_name,
            'deadline': deadline,
            'priority': priority,
            'created': datetime.datetime.now()
        }

        self.tasks.append(task)
        self._maintain_priority_order()
        return True

    def remove_highest_priority_task(self):
        if not self.tasks:
            return None

        highest_priority_index = self._find_highest_priority_index()
        task = self.tasks[highest_priority_index]

        # Move the last element to the position of the removed element
        if highest_priority_index < len(self.tasks) - 1:
            self.tasks[highest_priority_index] = self.tasks[-1]

        self.tasks.pop()
        self._maintain_priority_order()
        return task

    def _find_highest_priority_index(self):
        if not self.tasks:
            return -1

        highest_index = 0
        for i in range(1, len(self.tasks)):
            if self._is_higher_priority(self.tasks[i], self.tasks[highest_index]):
                highest_index = i

        return highest_index

    def _is_higher_priority(self, task1, task2):
        # Higher priority number means higher priority
        if task1['priority'] != task2['priority']:
            return task1['priority'] > task2['priority']

        # If same priority, earlier deadline has higher priority
        return task1['deadline'] < task2['deadline']

    def _maintain_priority_order(self):
        # Simple bubble sort to maintain order using only append and pop
        if len(self.tasks) <= 1:
            return

        # Extract all tasks
        temp_tasks = []
        while self.tasks:
            temp_tasks.append(self.tasks.pop())

        # Sort using bubble sort
        n = len(temp_tasks)
        for i in range(n):
            for j in range(0, n - i - 1):
                if not self._is_higher_priority(temp_tasks[j], temp_tasks[j + 1]):
                    temp_tasks[j], temp_tasks[j + 1] = temp_tasks[j + 1], temp_tasks[j]

        # Add back in sorted order
        for task in temp_tasks:
            self.tasks.append(task)

    def get_task_count(self):
        return len(self.tasks)

    def is_full(self):
        return len(self.tasks) >= self.capacity

    def peek_highest_priority(self):
        if not self.tasks:
            return None

        highest_index = self._find_highest_priority_index()
        return self.tasks[highest_index]

    def display_tasks(self):
        if not self.tasks:
            print("No tasks in queue")
            return

        print(f"Tasks in queue ({len(self.tasks)}/{self.capacity}):")
        for i, task in enumerate(self.tasks):
            print(f"{i+1}. {task['name']} - Priority: {task['priority']} - Deadline: {task['deadline']}")

def main():
    task_manager = TaskManager()

    while True:
        print("\n=== Task Manager ===")
        print("1. Add Task")
        print("2. Remove Highest Priority Task")
        print("3. View All Tasks")
        print("4. View Highest Priority Task")
        print("5. Check Capacity")
        print("6. Exit")

        choice = input("Enter your choice (1-6): ").strip()

        if choice == '1':
            if task_manager.is_full():
                print("Task queue is full! Cannot add more tasks.")
                continue

            name = input("Enter task name: ").strip()
            try:
                priority = int(input("Enter priority (higher number = higher priority): "))
                deadline_str = input("Enter deadline (YYYY-MM-DD HH:MM): ").strip()
                deadline = datetime.datetime.strptime(deadline_str, "%Y-%m-%d %H:%M")

                if task_manager.add_task(name, deadline, priority):
                    print("Task added successfully!")
                else:
                    print("Failed to add task - queue is full!")
            except ValueError:
                print("Invalid input format!")

        elif choice == '2':
            task = task_manager.remove_highest_priority_task()
            if task:
                print(f"Removed task: {task['name']} (Priority: {task['priority']})")
            else:
                print("No tasks to remove!")

        elif choice == '3':
            task_manager.display_tasks()

        elif choice == '4':
            task = task_manager.peek_highest_priority()
            if task:
                print(f"Highest priority task: {task['name']} (Priority: {task['priority']}, Deadline: {task['deadline']})")
            else:
                print("No tasks in queue!")

        elif choice == '5':
            print(f"Current capacity: {task_manager.get_task_count()}/{task_manager.capacity}")

        elif choice == '6':
            print("Goodbye!")
            break

        else:
            print("Invalid choice! Please try again.")

if __name__ == "__main__":
    main()
