import java.util.*;
import java.util.logging.Logger;
import java.util.logging.Level;
import java.util.logging.ConsoleHandler;
import java.util.logging.SimpleFormatter;

class Task implements Comparable<Task> {
    private final String id;
    private final int priority;

    public Task(String id, int priority) {
        this.id = id;
        this.priority = priority;
    }

    public String getId() {
        return id;
    }

    public int getPriority() {
        return priority;
    }

    @Override
    public int compareTo(Task other) {
        // Higher priority tasks come first
        int priorityComparison = Integer.compare(other.priority, this.priority);
        if (priorityComparison != 0) {
            return priorityComparison;
        }
        // If priorities are the same, compare by ID for uniqueness
        return this.id.compareTo(other.id);
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Task task = (Task) o;
        return priority == task.priority && Objects.equals(id, task.id);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id, priority);
    }

    @Override
    public String toString() {
        return "Task{id='" + id + "', priority=" + priority + '}';
    }
}

class TaskScheduler {
    private static final int MAX_TASKS = 200;
    private final TreeSet<Task> tasks;
    private static final Logger LOGGER = Logger.getLogger(TaskScheduler.class.getName());

    static {
        ConsoleHandler handler = new ConsoleHandler();
        handler.setFormatter(new SimpleFormatter());
        LOGGER.addHandler(handler);
        LOGGER.setLevel(Level.ALL);
    }

    public TaskScheduler() {
        tasks = new TreeSet<>();
        LOGGER.info("Task scheduler initialized with max capacity of " + MAX_TASKS + " tasks");
    }

    public void addTask(Task task) throws IllegalStateException {
        if (tasks.size() >= MAX_TASKS) {
            LOGGER.severe("Failed to add task " + task.getId() + ": Maximum capacity reached");
            throw new IllegalStateException("Cannot add more tasks. Maximum capacity of " + MAX_TASKS + " reached.");
        }

        tasks.add(task);
        LOGGER.info("Added task: " + task + ". Current task count: " + tasks.size());
    }

    public void removeTask(String id) {
        Task taskToRemove = null;

        for (Task task : tasks) {
            if (task.getId().equals(id)) {
                taskToRemove = task;
                break;
            }
        }

        if (taskToRemove != null) {
            tasks.remove(taskToRemove);
            LOGGER.info("Removed task: " + taskToRemove + ". Current task count: " + tasks.size());
        } else {
            LOGGER.warning("Failed to remove task with ID " + id + ": Task not found");
        }
    }

    public Task getNextTask() throws NoSuchElementException {
        if (tasks.isEmpty()) {
            LOGGER.severe("Failed to retrieve next task: Scheduler is empty");
            throw new NoSuchElementException("No tasks available. Scheduler is empty.");
        }

        Task nextTask = tasks.first();
        LOGGER.info("Retrieved next task: " + nextTask);
        return nextTask;
    }

    public Task fetchAndRemoveNextTask() throws NoSuchElementException {
        if (tasks.isEmpty()) {
            LOGGER.severe("Failed to fetch and remove next task: Scheduler is empty");
            throw new NoSuchElementException("No tasks available. Scheduler is empty.");
        }

        Task nextTask = tasks.pollFirst();
        LOGGER.info("Fetched and removed task: " + nextTask + ". Current task count: " + tasks.size());
        return nextTask;
    }

    public boolean hasTask(String id) {
        for (Task task : tasks) {
            if (task.getId().equals(id)) {
                LOGGER.fine("Task with ID " + id + " found in scheduler");
                return true;
            }
        }
        LOGGER.fine("Task with ID " + id + " not found in scheduler");
        return false;
    }

    public int getTaskCount() {
        return tasks.size();
    }

    public boolean isEmpty() {
        return tasks.isEmpty();
    }

    public void clear() {
        int taskCount = tasks.size();
        tasks.clear();
        LOGGER.info("Cleared all tasks. Removed " + taskCount + " tasks.");
    }
}

public class TaskSchedulerDemo {
    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();

        try {
            // Add some tasks
            scheduler.addTask(new Task("T1", 5));
            scheduler.addTask(new Task("T2", 10));
            scheduler.addTask(new Task("T3", 3));

            // Fetch the highest priority task
            Task nextTask = scheduler.getNextTask();
            System.out.println("Next task to execute: " + nextTask);

            // Process and remove the highest priority task
            Task processedTask = scheduler.fetchAndRemoveNextTask();
            System.out.println("Processed task: " + processedTask);

            // Add more tasks
            scheduler.addTask(new Task("T4", 7));

            // Remove a task
            scheduler.removeTask("T3");

            // Check if task exists
            System.out.println("Does T2 exist? " + scheduler.hasTask("T2"));
            System.out.println("Does T3 exist? " + scheduler.hasTask("T3"));

        } catch (IllegalStateException | NoSuchElementException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
