    }
}

class TaskSchedulerFullException extends Exception {
    public TaskSchedulerFullException(String message) {
        super(message);
    }
}

class TaskSchedulerEmptyException extends Exception {
    public TaskSchedulerEmptyException(String message) {
        super(message);
    }
}

public class TaskScheduler {
    private static final int MAX_CAPACITY = 200;
    private final TreeSet<Task> taskSet;
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());

    public TaskScheduler() {
        this.taskSet = new TreeSet<>();
        setupLogger();
    }

    private void setupLogger() {
        logger.setLevel(Level.ALL);
        ConsoleHandler handler = new ConsoleHandler();
        handler.setLevel(Level.ALL);
        logger.addHandler(handler);
        logger.setUseParentHandlers(false);
    }

    public void add(Task task) throws TaskSchedulerFullException {
        if (taskSet.size() >= MAX_CAPACITY) {
            logger.severe("Failed to add task " + task + ": TreeSet is at full capacity (" + MAX_CAPACITY + ")");
            throw new TaskSchedulerFullException("Cannot add task: TreeSet is at full capacity");
        }

        boolean added = taskSet.add(task);
        if (added) {
            logger.info("Successfully added task: " + task + ". Current size: " + taskSet.size());
        } else {
            logger.warning("Task " + task + " already exists in the TreeSet");
        }
    }

    public boolean remove(Task task) {
        boolean removed = taskSet.remove(task);
        if (removed) {
            logger.info("Successfully removed task: " + task + ". Current size: " + taskSet.size());
        } else {
            logger.warning("Failed to remove task " + task + ": Task not found in TreeSet");
        }
        return removed;
    }

    public Task pollFirst() throws TaskSchedulerEmptyException {
        if (taskSet.isEmpty()) {
            logger.severe("Failed to poll first task: TreeSet is empty");
            throw new TaskSchedulerEmptyException("Cannot poll from empty TreeSet");
        }

        Task firstTask = taskSet.pollFirst();
        logger.info("Successfully polled first task: " + firstTask + ". Current size: " + taskSet.size());
        return firstTask;
    }

    public int size() {
        return taskSet.size();
    }

    public boolean isEmpty() {
        return taskSet.isEmpty();
    }

    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();

        try {
            scheduler.add(new Task(1, 5));
            scheduler.add(new Task(2, 3));
            scheduler.add(new Task(3, 7));
            scheduler.add(new Task(4, 3));

            System.out.println("Current size: " + scheduler.size());

            Task highestPriorityTask = scheduler.pollFirst();
            System.out.println("Polled task: " + highestPriorityTask);

            scheduler.remove(new Task(3, 7));

            System.out.println("Final size: " + scheduler.size());

        } catch (TaskSchedulerFullException | TaskSchedulerEmptyException e) {
            System.err.println("Exception: " + e.getMessage());
        }
    }
}
