        if (tasks.size() >= MAX_TASKS) {
            LOGGER.severe("Failed to add task: Maximum capacity reached");
            throw new CapacityExceededException("Cannot add more tasks. Maximum capacity reached.");
        }
        tasks.add(task);
        LOGGER.info("Task added: " + task);
    }

    public void remove(Task task) throws MinimumCapacityException {
        if (tasks.size() <= MIN_TASKS) {
            LOGGER.severe("Failed to remove task: Minimum capacity reached");
            throw new MinimumCapacityException("Cannot remove more tasks. Minimum capacity reached.");
        }
        boolean removed = tasks.remove(task);
        if (removed) {
            LOGGER.info("Task removed: " + task);
        } else {
            LOGGER.warning("Task not found: " + task);
        }
    }

