import java.util.*;
import java.util.logging.*;

class Task implements Comparable<Task> {
    private final int id;
    private final int priority;

    public Task(int id, int priority) {
        this.id = id;
        this.priority = priority;
    }

    public int getId() {
        return id;
    }

    public int getPriority() {
        return priority;
    }

    @Override
    public int compareTo(Task other) {
        int priorityComparison = Integer.compare(this.priority, other.priority);
        if (priorityComparison != 0) {
            return priorityComparison;
        }
        return Integer.compare(this.id, other.id);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        Task task = (Task) obj;
        return id == task.id && priority == task.priority;
    }

    @Override
    public int hashCode() {
        return Objects.hash(id, priority);
    }

    @Override
    public String toString() {
        return "Task{id=" + id + ", priority=" + priority + "}";
    }
}

class TaskSchedulerException extends Exception {
    public TaskSchedulerException(String message) {
        super(message);
    }
}

class TaskScheduler {
    private static final int MIN_TASKS = 150;
    private static final int MAX_TASKS = 200;
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());

    private final TreeSet<Task> taskSet;

    public TaskScheduler() {
        this.taskSet = new TreeSet<>();
        setupLogger();
    }

    private void setupLogger() {
        logger.setLevel(Level.ALL);
        ConsoleHandler handler = new ConsoleHandler();
        handler.setLevel(Level.ALL);
        logger.addHandler(handler);
        logger.setUseParentHandlers(false);
    }

    public void add(Task task) throws TaskSchedulerException {
        if (taskSet.size() >= MAX_TASKS) {
            logger.severe("Failed to add task " + task + ": TreeSet at full capacity (" + MAX_TASKS + ")");
            throw new TaskSchedulerException("Cannot add task: TreeSet is at full capacity of " + MAX_TASKS + " tasks");
        }

        boolean added = taskSet.add(task);
        if (added) {
            logger.info("Successfully added task " + task + ". Current size: " + taskSet.size());
        } else {
            logger.warning("Task " + task + " already exists in TreeSet. Current size: " + taskSet.size());
        }
    }

    public boolean remove(Task task) throws TaskSchedulerException {
        if (taskSet.size() <= MIN_TASKS) {
            logger.severe("Failed to remove task " + task + ": Cannot drop below minimum of " + MIN_TASKS + " tasks");
            throw new TaskSchedulerException("Cannot remove task: TreeSet cannot drop below " + MIN_TASKS + " tasks");
        }

        boolean removed = taskSet.remove(task);
        if (removed) {
            logger.info("Successfully removed task " + task + ". Current size: " + taskSet.size());
        } else {
            logger.warning("Task " + task + " not found in TreeSet. Current size: " + taskSet.size());
        }
        return removed;
    }

    public Task pollFirst() throws TaskSchedulerException {
        if (taskSet.isEmpty()) {
            logger.severe("Failed to poll first task: TreeSet is empty");
            throw new TaskSchedulerException("Cannot poll from empty TreeSet");
        }

        if (taskSet.size() <= MIN_TASKS) {
            logger.severe("Failed to poll first task: Cannot drop below minimum of " + MIN_TASKS + " tasks");
            throw new TaskSchedulerException("Cannot poll task: TreeSet cannot drop below " + MIN_TASKS + " tasks");
        }

        Task firstTask = taskSet.pollFirst();
        logger.info("Successfully polled first task " + firstTask + ". Current size: " + taskSet.size());
        return firstTask;
    }

    public int size() {
        return taskSet.size();
    }

    public boolean isEmpty() {
        return taskSet.isEmpty();
    }
}

public class TaskSchedulerProgram {
    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();

        try {
            // Initialize with minimum required tasks
            for (int i = 1; i <= 150; i++) {
                scheduler.add(new Task(i, i % 10));
            }

            // Test add operation
            scheduler.add(new Task(151, 5));

            // Test remove operation
            scheduler.remove(new Task(1, 1));

            // Test pollFirst operation
            Task polledTask = scheduler.pollFirst();
            System.out.println("Polled task: " + polledTask);

            // Test exception scenarios
            try {
                // Try to add when at capacity
                for (int i = 152; i <= 202; i++) {
                    scheduler.add(new Task(i, i % 10));
                }
            } catch (TaskSchedulerException e) {
                System.out.println("Expected exception: " + e.getMessage());
            }

        } catch (TaskSchedulerException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}
