struct Item {
    int id;
    std::string name;
    int urgency;  // Higher value means higher priority
    double price;

    // Operator overloading for priority queue comparison
    bool operator<(const Item& other) const {
        return urgency < other.urgency;  // Higher urgency has higher priority
    }
};

class InventorySystem {
private:
    std::priority_queue<Item> items;
    const int MAX_CAPACITY = 500;
    int nextId = 1;

public:
    // Add an item to the inventory
    void addItem(const std::string& name, int urgency, double price) {
        if (items.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Inventory is full (max 500 items). Remove items before adding more.");
        }

        Item newItem{nextId++, name, urgency, price};
        items.push(newItem);
        std::cout << "Added item: " << name << " (ID: " << newItem.id << ", Urgency: " << urgency << ")\n";
    }

    // Remove the highest priority item
    Item removeHighestPriority() {
        if (items.empty()) {
            throw std::underflow_error("Inventory is empty. No items to remove.");
        }

        Item topItem = items.top();
        items.pop();
        std::cout << "Removed highest priority item: " << topItem.name << " (ID: " << topItem.id << ")\n";
        return topItem;
    }

    // Get the highest priority item without removing it
    Item getHighestPriority() const {
        if (items.empty()) {
            throw std::underflow_error("Inventory is empty. No items available.");
        }

        return items.top();
    }

    // Get the current size of the inventory
    int size() const {
        return items.size();
    }

    // Check if the inventory is empty
    bool isEmpty() const {
        return items.empty();
    }

    // Check if the inventory is full
    bool isFull() const {
        return items.size() >= MAX_CAPACITY;
    }
};

