class InventorySystem {
private:
    struct Item {
        std::string name;
        int id;
        int priority; // Higher number means higher priority
        double price;

        Item(const std::string& n, int i, int p, double pr) 
            : name(n), id(i), priority(p), price(pr) {}
    };

    std::vector<Item> pq;
    const size_t MAX_CAPACITY = 500;

public:
    void push(const std::string& name, int id, int priority, double price) {
        if (pq.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Inventory is full (maximum 500 items)");
        }

        pq.emplace_back(name, id, priority, price);
        std::push_heap(pq.begin(), pq.end(), 
            [](const Item& a, const Item& b) { return a.priority < b.priority; });
    }

    void pop() {
        if (pq.empty()) {
            throw std::underflow_error("Inventory is empty");
        }

        std::pop_heap(pq.begin(), pq.end(), 
            [](const Item& a, const Item& b) { return a.priority < b.priority; });
        pq.pop_back();
    }

    const Item& top() const {
        if (pq.empty()) {
            throw std::underflow_error("Inventory is empty");
        }

        return pq.front();
    }

    bool empty() const {
        return pq.empty();
    }

    size_t size() const {
        return pq.size();
    }
};

