struct Item {
    std::string name;
    int urgency;
    int quantity;

    Item(const std::string& n, int u, int q) : name(n), urgency(u), quantity(q) {}

    bool operator<(const Item& other) const {
        return urgency < other.urgency;
    }
};

class InventoryPriorityQueue {
private:
    std::vector<Item> heap;
    static const int MAX_CAPACITY = 500;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[index] < heap[parent]) break;
            std::swap(heap[index], heap[parent]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int size = heap.size();
        while (true) {
            int largest = index;
            int left = 2 * index + 1;
            int right = 2 * index + 2;

            if (left < size && heap[largest] < heap[left]) {
                largest = left;
            }
            if (right < size && heap[largest] < heap[right]) {
                largest = right;
            }

            if (largest == index) break;
            std::swap(heap[index], heap[largest]);
            index = largest;
        }
    }

public:
    void push(const Item& item) {
        if (heap.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Priority queue has reached maximum capacity of 500 items");
        }
        heap.push_back(item);
        heapifyUp(heap.size() - 1);
    }

    void pop() {
        if (heap.empty()) {
            throw std::underflow_error("Cannot pop from empty priority queue");
        }
        heap[0] = heap.back();
        heap.pop_back();
        if (!heap.empty()) {
            heapifyDown(0);
        }
    }

    const Item& top() const {
        if (heap.empty()) {
            throw std::underflow_error("Cannot access top of empty priority queue");
        }
        return heap[0];
    }

    bool empty() const {
        return heap.empty();
    }

    size_t size() const {
        return heap.size();
    }
};

class ElectronicStoreInventory {
private:
    InventoryPriorityQueue inventory;

public:
    void addItem(const std::string& name, int urgency, int quantity) {
        try {
            inventory.push(Item(name, urgency, quantity));
            std::cout << "Added: " << name << " (Urgency: " << urgency << ", Quantity: " << quantity << ")\n";
        } catch (const std::exception& e) {
            std::cout << "Error adding item: " << e.what() << "\n";
        }
    }

    void removeHighestPriorityItem() {
        try {
            Item item = inventory.top();
            inventory.pop();
            std::cout << "Removed: " << item.name << " (Urgency: " << item.urgency << ", Quantity: " << item.quantity << ")\n";
        } catch (const std::exception& e) {
            std::cout << "Error removing item: " << e.what() << "\n";
        }
    }

    void viewHighestPriorityItem() {
        try {
            const Item& item = inventory.top();
            std::cout << "Highest priority item: " << item.name << " (Urgency: " << item.urgency << ", Quantity: " << item.quantity << ")\n";
        } catch (const std::exception& e) {
