package main

import (
	"errors"
	"fmt"
)

type Employee struct {
	ID         int
	Name       string
	Department string
}

type EmployeeStack struct {
	records []Employee
	top     int
}

func NewEmployeeStack() *EmployeeStack {
	return &EmployeeStack{
		records: make([]Employee, 0, 4500),
		top:     -1,
	}
}

func (s *EmployeeStack) Push(emp Employee) error {
	if s.top >= 4499 {
		return errors.New("stack overflow: maximum capacity of 4500 records reached")
	}
	s.records = append(s.records, emp)
	s.top++
	return nil
}

func (s *EmployeeStack) IsEmpty() bool {
	return s.top == -1
}

func (s *EmployeeStack) Size() int {
	return s.top + 1
}

func (s *EmployeeStack) GetRecords() []Employee {
	return s.records[:s.top+1]
}

func ProcessEmployeeRecords(employees []Employee, excludeDepartment string) (*EmployeeStack, error) {
	if len(employees) > 5000 {
		return nil, errors.New("input exceeds maximum limit of 5000 records")
	}

	if excludeDepartment == "" {
		return nil, errors.New("exclude department cannot be empty")
	}

	stack := NewEmployeeStack()

	for _, emp := range employees {
		if emp.Department == "" {
			return nil, errors.New("employee department cannot be empty")
		}
		if emp.Name == "" {
			return nil, errors.New("employee name cannot be empty")
		}
		if emp.ID <= 0 {
			return nil, errors.New("employee ID must be positive")
		}

		if emp.Department != excludeDepartment {
			if err := stack.Push(emp); err != nil {
				return nil, fmt.Errorf("failed to add employee %d: %w", emp.ID, err)
			}
		}
	}

	return stack, nil
}
