use std::fmt;

#[derive(Debug, Clone)]
enum MediaType {
    Book { title: String, author: String, pages: u32 },
    Movie { title: String, director: String, duration: u32 },
    Music { title: String, artist: String, duration: u32 },
}

impl fmt::Display for MediaType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            MediaType::Book { title, author, pages } => {
                write!(f, "Book: {} by {} ({} pages)", title, author, pages)
            }
            MediaType::Movie { title, director, duration } => {
                write!(f, "Movie: {} directed by {} ({} minutes)", title, director, duration)
            }
            MediaType::Music { title, artist, duration } => {
                write!(f, "Music: {} by {} ({} seconds)", title, artist, duration)
            }
        }
    }
}

#[derive(Debug)]
enum LibraryError {
    CollectionFull,
    CollectionEmpty,
    InvalidIndex,
    InvalidMediaType,
}

impl fmt::Display for LibraryError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            LibraryError::CollectionFull => write!(f, "Library collection is full (max 1000 entries)"),
            LibraryError::CollectionEmpty => write!(f, "Library collection is empty"),
            LibraryError::InvalidIndex => write!(f, "Invalid index provided"),
            LibraryError::InvalidMediaType => write!(f, "Invalid media type"),
        }
    }
}

struct DigitalLibrary {
    media_collection: Vec<MediaType>,
    max_capacity: usize,
}

impl DigitalLibrary {
    fn new() -> Self {
        DigitalLibrary {
            media_collection: Vec::new(),
            max_capacity: 1000,
        }
    }

    fn add_media(&mut self, media: MediaType) -> Result<(), LibraryError> {
        if self.media_collection.len() >= self.max_capacity {
            return Err(LibraryError::CollectionFull);
        }
        self.media_collection.push(media);
        Ok(())
    }

    fn remove_last_media(&mut self) -> Result<MediaType, LibraryError> {
        self.media_collection.pop().ok_or(LibraryError::CollectionEmpty)
    }

    fn update_media(&mut self, index: usize, new_media: MediaType) -> Result<(), LibraryError> {
        if index >= self.media_collection.len() {
            return Err(LibraryError::InvalidIndex);
        }
        self.media_collection[index] = new_media;
        Ok(())
    }

    fn get_media(&self, index: usize) -> Result<&MediaType, LibraryError> {
        self.media_collection.get(index).ok_or(LibraryError::InvalidIndex)
    }

    fn find_media_by_title(&self, title: &str) -> Vec<(usize, &MediaType)> {
        self.media_collection
            .iter()
            .enumerate()
            .filter(|(_, media)| {
                match media {
                    MediaType::Book { title: t, .. } |
                    MediaType::Movie { title: t, .. } |
                    MediaType::Music { title: t, .. } => t.to_lowercase().contains(&title.to_lowercase())
                }
            })
            .collect()
    }

    fn display_all_media(&self) {
        if self.media_collection.is_empty() {
            println!("Library is empty");
            return;
        }

        for (index, media) in self.media_collection.iter().enumerate() {
            println!("{}: {}", index, media);
        }
    }

    fn get_media_count(&self) -> usize {
        self.media_collection.len()
    }

    fn get_capacity_remaining(&self) -> usize {
        self.max_capacity - self.media_collection.len()
    }

    fn get_media_by_type(&self, media_type: &str) -> Vec<(usize, &MediaType)> {
        self.media_collection
            .iter()
            .enumerate()
            .filter(|(_, media)| {
                match (media_type.to_lowercase().as_str(), media) {
                    ("book", MediaType::Book { .. }) => true,
                    ("movie", MediaType::Movie { .. }) => true,
