}

#[derive(Debug)]
enum LibraryError {
    CollectionFull,
    InvalidMediaType,
    MediaNotFound,
    EmptyCollection,
}

impl fmt::Display for LibraryError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            LibraryError::CollectionFull => write!(f, "Library collection is full (1000 entries max)"),
            LibraryError::InvalidMediaType => write!(f, "Invalid media type provided"),
            LibraryError::MediaNotFound => write!(f, "Media entry not found"),
            LibraryError::EmptyCollection => write!(f, "Library collection is empty"),
        }
    }
}

struct MediaLibrary {
    collection: Vec<MediaType>,
}

impl MediaLibrary {
    fn new() -> Self {
        MediaLibrary {
            collection: Vec::new(),
        }
    }

    fn add_media(&mut self, media: MediaType) -> Result<(), LibraryError> {
        if self.collection.len() >= 1000 {
            return Err(LibraryError::CollectionFull);
        }

        match media {
            MediaType::Book { .. } | MediaType::Movie { .. } | MediaType::Music { .. } => {
                self.collection.push(media);
                Ok(())
            }
        }
    }

    fn remove_last_media(&mut self) -> Result<MediaType, LibraryError> {
        match self.collection.pop() {
            Some(media) => Ok(media),
            None => Err(LibraryError::EmptyCollection),
        }
    }

    fn update_media(&mut self, index: usize, new_media: MediaType) -> Result<(), LibraryError> {
        if index >= self.collection.len() {
            return Err(LibraryError::MediaNotFound);
        }

        let mut temp_stack = Vec::new();
        let target_index = self.collection.len() - 1 - index;

        for _ in 0..target_index {
            if let Some(media) = self.collection.pop() {
                temp_stack.push(media);
            }
        }

        if self.collection.pop().is_some() {
            self.collection.push(new_media);
        } else {
            return Err(LibraryError::MediaNotFound);
        }

        while let Some(media) = temp_stack.pop() {
            self.collection.push(media);
        }

        Ok(())
    }

    fn find_media(&self, title: &str) -> Option<(usize, &MediaType)> {
        for (index, media) in self.collection.iter().enumerate() {
            let media_title = match media {
                MediaType::Book { title, .. } => title,
                MediaType::Movie { title, .. } => title,
                MediaType::Music { title, .. } => title,
            };
            if media_title == title {
                return Some((index, media));
            }
