public class StudentRecordManager {
    private static final int MAX_CAPACITY = 500;
    private HashSet<Student> students;

    public StudentRecordManager() {
        students = new HashSet<>();
    }

    public boolean addStudent(Student student) throws IllegalStateException {
        if (students.size() >= MAX_CAPACITY) {
            throw new IllegalStateException("Cannot add more students. Maximum capacity reached.");
        }
        return students.add(student);
    }

    public boolean removeStudent(int studentId) throws NoSuchElementException {
        Student studentToRemove = findStudentById(studentId);
        if (studentToRemove == null) {
            throw new NoSuchElementException("Student with ID " + studentId + " not found.");
        }
        return students.remove(studentToRemove);
    }

    public boolean containsStudent(int studentId) {
        return findStudentById(studentId) != null;
    }

    private Student findStudentById(int studentId) {
        for (Student student : students) {
            if (student.getStudentId() == studentId) {
                return student;
            }
        }
        return null;
    }

    public int getStudentCount() {
        return students.size();
    }

    public static class Student {
        private int studentId;
        private String name;
        private String grade;

        public Student(int studentId, String name, String grade) {
            this.studentId = studentId;
            this.name = name;
            this.grade = grade;
        }

        public int getStudentId() {
            return studentId;
        }

        public String getName() {
            return name;
        }

        public String getGrade() {
            return grade;
        }

