import os
import re
from collections import Counter
import sys

class ErrorStack:
    def __init__(self, max_size=20):
        self.stack = []
        self.max_size = max_size

    def push(self, error):
        if len(self.stack) >= self.max_size:
            self.stack.pop(0)  # Remove oldest error if at capacity
        self.stack.append(error)

    def pop(self):
        if self.stack:
            return self.stack.pop()
        return None

def process_log_file(filepath, ip_counter, error_stack):
    try:
        with open(filepath, 'r') as file:
            for line in file:
                # Extract IP addresses using regex
                ip_matches = re.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b', line)

                # Update counter with found IPs
                for ip in ip_matches:
                    ip_counter[ip] += 1

                    # Limit counter to 10,000 IPs
                    if len(ip_counter) > 10000:
                        ip_counter.pop(min(ip_counter, key=ip_counter.get))

                # Check for error messages
                if "ERROR" in line or "error" in line or "Exception" in line:
                    error_stack.push(line.strip())

    except IOError as e:
        error_stack.push(f"IO Error processing {filepath}: {str(e)}")
    except Exception as e:
        error_stack.push(f"Unexpected error processing {filepath}: {str(e)}")

def main():
    if len(sys.argv) < 2:
        print("Usage: python script.py <log_directory_or_file>")
        return

    path = sys.argv[1]
    ip_counter = Counter()
    error_stack = ErrorStack(20)

    if os.path.isdir(path):
        for filename in os.listdir(path):
            if filename.endswith('.log'):
                process_log_file(os.path.join(path, filename), ip_counter, error_stack)
    elif os.path.isfile(path):
        process_log_file(path, ip_counter, error_stack)
    else:
        print(f"Path {path} is not valid")
        return

    # Print summary
    print(f"Top 10 IP addresses:")
    for ip, count in ip_counter.most_common(10):
        print(f"{ip}: {count}")

    print("\nLast 5 errors:")
    errors = []
    for _ in range(5):
        error = error_stack.pop()
        if error:
            errors.append(error)

    for error in reversed(errors):
        print(error)

if __name__ == "__main__":
    main()
