use smallvec::SmallVec;
use std::cmp::Ordering;

#[derive(Debug, Clone)]
pub struct Task {
    id: u32,
    priority: i32,
    description: String,
}

impl Task {
    pub fn new(id: u32, priority: i32, description: String) -> Self {
        Self { id, priority, description }
    }
}

impl PartialEq for Task {
    fn eq(&self, other: &Self) -> bool {
