        Some(self.cmp(other))
    }
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        other.priority.cmp(&self.priority)
    }
}

#[derive(Debug)]
pub enum TaskError {
    QueueFull,
    TaskNotFound,
    InvalidPriority,
}

pub struct TaskPriorityQueue {
    tasks: SmallVec<[Task; 200]>,
}

impl TaskPriorityQueue {
    pub fn new() -> Self {
        Self {
            tasks: SmallVec::new(),
        }
    }

    pub fn push(&mut self, task: Task) -> Result<(), TaskError> {
        if self.tasks.len() >= 200 {
            return Err(TaskError::QueueFull);
        }

        self.tasks.push(task);
        self.heapify_up(self.tasks.len() - 1);
        Ok(())
    }

    pub fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            return None;
        }

        let last_idx = self.tasks.len() - 1;
        self.tasks.swap(0, last_idx);
        let task = self.tasks.pop();

        if !self.tasks.is_empty() {
            self.heapify_down(0);
        }

        task
    }

    pub fn update_priority(&mut self, task_id: u32, new_priority: i32) -> Result<(), TaskError> {
        let position = self.tasks.iter().position(|t| t.id == task_id)
            .ok_or(TaskError::TaskNotFound)?;

        let old_priority = self.tasks[position].priority;
        self.tasks[position].priority = new_priority;

        match new_priority.cmp(&old_priority) {
            Ordering::Greater => self.heapify_up(position),
            Ordering::Less => self.heapify_down(position),
            Ordering::Equal => {}
        }

        Ok(())
    }

    fn heapify_up(&mut self, mut index: usize) {
        while index > 0 {
            let parent = (index - 1) / 2;
            if self.tasks[index] <= self.tasks[parent] {
                break;
            }
            self.tasks.swap(index, parent);
            index = parent;
        }
    }

    fn heapify_down(&mut self, mut index: usize) {
        loop {
            let left = 2 * index + 1;
            let right = 2 * index + 2;
            let mut largest = index;

            if left < self.tasks.len() && self.tasks[left] > self.tasks[largest] {
                largest = left;
            }

            if right < self.tasks.len() && self.tasks[right] > self.tasks[largest] {
                largest = right;
            }

            if largest == index {
                break;
            }

            self.tasks.swap(index, largest);
            index = largest;
        }
    }

    pub fn len(&self) -> usize {
        self.tasks.len()
    }

    pub fn is_empty(&self) -> bool {
        self.tasks.is_empty()
    }

    pub fn is_full(&self) -> bool {
        self.tasks.len() >= 200
    }
}
