func NewLogCounter(maxSize int) *LogCounter {
	return &LogCounter{
		entries: make(map[string]int),
		maxSize: maxSize,
	}
}

func (lc *LogCounter) Increment(entry string) {
	lc.mutex.Lock()
	defer lc.mutex.Unlock()

	// Check if we need to make room
	if len(lc.entries) >= lc.maxSize && lc.entries[entry] == 0 {
		// Simple eviction strategy: remove a random entry
		for k := range lc.entries {
			delete(lc.entries, k)
			break
		}
	}

	lc.entries[entry]++
}

func (lc *LogCounter) Count(entry string) int {
	lc.mutex.RLock()
	defer lc.mutex.RUnlock()
	return lc.entries[entry]
}

func (lc *LogCounter) Delete(entry string) {
	lc.mutex.Lock()
	defer lc.mutex.Unlock()
	delete(lc.entries, entry)
}

func (lc *LogCounter) Size() int {
	lc.mutex.RLock()
	defer lc.mutex.RUnlock()
	return len(lc.entries)
}

func processLogFile(filePath string, counter *LogCounter, wg *sync.WaitGroup) {
	defer wg.Done()

