package main

import (
	"bufio"
	"container/list"
	"fmt"
	"log"
	"os"
	"sync"
	"time"
)

type LRUCache struct {
	mu       sync.RWMutex
	capacity int
	cache    map[string]*list.Element
	list     *list.List
}

type entry struct {
	key   string
	value int
}

func NewLRUCache(capacity int) *LRUCache {
	return &LRUCache{
		capacity: capacity,
		cache:    make(map[string]*list.Element),
		list:     list.New(),
	}
}

func (c *LRUCache) Increment(key string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, exists := c.cache[key]; exists {
		c.list.MoveToFront(elem)
		elem.Value.(*entry).value++
		return
	}

	if c.list.Len() >= c.capacity {
		oldest := c.list.Back()
		if oldest != nil {
			c.list.Remove(oldest)
			delete(c.cache, oldest.Value.(*entry).key)
		}
	}

	newEntry := &entry{key: key, value: 1}
	elem := c.list.PushFront(newEntry)
	c.cache[key] = elem
}

func (c *LRUCache) Check(key string) (int, bool) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	if elem, exists := c.cache[key]; exists {
		return elem.Value.(*entry).value, true
	}
	return 0, false
}

func (c *LRUCache) Delete(key string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, exists := c.cache[key]; exists {
		c.list.Remove(elem)
		delete(c.cache, key)
		return true
	}
	return false
}

func processLogFile(filename string, cache *LRUCache, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filename)
	if err != nil {
		log.Printf("Error opening file %s: %v", filename, err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := scanner.Text()
		if line != "" {
			cache.Increment(line)
		}
	}

	if err := scanner.Err(); err != nil {
		log.Printf("Error reading file %s: %v", filename, err)
	}
}

func main() {
	cache := NewLRUCache(20000)
	var wg sync.WaitGroup

	logFiles := []string{
		"log1.txt",
		"log2.txt",
		"log3.txt",
		"log4.txt",
	}

	start := time.Now()

	for _, filename := range logFiles {
		wg.Add(1)
		go processLogFile(filename, cache, &wg)
	}

	wg.Wait()

	fmt.Printf("Processing completed in %v\n", time.Since(start))
	fmt.Printf("Total unique entries processed: %d\n", cache.list.Len())

	if count, exists := cache.Check("sample log entry"); exists {
		fmt.Printf("Sample entry count: %d\n", count)
	}

	cache.Delete("sample log entry")
}
