package main

import (
	"bufio"
	"container/list"
	"fmt"
	"os"
	"path/filepath"
	"sync"
)

// LogEntry represents a unique log entry with its count and position in LRU
type LogEntry struct {
	value string
	count int
}

// LRUVector implements a thread-safe vector with LRU eviction policy
type LRUVector struct {
	mutex    sync.RWMutex
	entries  map[string]*list.Element
	lruList  *list.List
	capacity int
}

// NewLRUVector creates a new LRUVector with specified capacity
func NewLRUVector(capacity int) *LRUVector {
	return &LRUVector{
		entries:  make(map[string]*list.Element),
		lruList:  list.New(),
		capacity: capacity,
	}
}

// Increment adds or increments an entry in the vector
func (v *LRUVector) Increment(value string) {
	v.mutex.Lock()
	defer v.mutex.Unlock()

	if elem, exists := v.entries[value]; exists {
		v.lruList.MoveToFront(elem)
		entry := elem.Value.(*LogEntry)
		entry.count++
		return
	}

	// Check if we need to evict
	if len(v.entries) >= v.capacity {
		// Remove least recently used item
		oldest := v.lruList.Back()
		if oldest != nil {
			entry := oldest.Value.(*LogEntry)
			delete(v.entries, entry.value)
			v.lruList.Remove(oldest)
		}
	}

	// Add new entry
	entry := &LogEntry{value: value, count: 1}
	elem := v.lruList.PushFront(entry)
	v.entries[value] = elem
}

// Check returns the count of an entry if it exists
func (v *LRUVector) Check(value string) (int, bool) {
	v.mutex.RLock()
	defer v.mutex.RUnlock()

	if elem, exists := v.entries[value]; exists {
		v.lruList.MoveToFront(elem)
		return elem.Value.(*LogEntry).count, true
	}
	return 0, false
}

// Delete removes an entry from the vector
func (v *LRUVector) Delete(value string) bool {
	v.mutex.Lock()
	defer v.mutex.Unlock()

	if elem, exists := v.entries[value]; exists {
		v.lruList.Remove(elem)
		delete(v.entries, value)
		return true
	}
	return false
}

// ProcessLogFile reads and processes a log file
func ProcessLogFile(filePath string, vector *LRUVector, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file %s: %v\n", filePath, err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		line := scanner.Text()
		vector.Increment(line)
	}

	if err := scanner.Err(); err != nil {
		fmt.Printf("Error reading file %s: %v\n", filePath, err)
	}
}

func main() {
	// Create LRUVector with capacity of 20,000
	vector := NewLRUVector(20000)

	// Get log files from directory
	logDir := "./logs" // Change this to your log directory
	logFiles, err := filepath.Glob(filepath.Join(logDir, "*.log"))
	if err != nil {
		fmt.Printf("Error finding log files: %v\n", err)
		return
	}

	// Process each log file concurrently
	var wg sync.WaitGroup
	for _, file := range logFiles {
		wg.Add(1)
		go ProcessLogFile(file, vector, &wg)
	}

	// Wait for all goroutines to complete
	wg.Wait()

	fmt.Println("Log processing complete")
}
