import queue

def floyd_warshall_shortest_path(graph, num_nodes):
    # Initialize distance matrix with infinity
    INF = float('inf')
    dist = [[INF for _ in range(num_nodes)] for _ in range(num_nodes)]

    # Set distance from each node to itself as 0
    for i in range(num_nodes):
        dist[i][i] = 0

    # Set initial distances from graph
    for u in range(num_nodes):
        for v in range(num_nodes):
            if graph[u][v] != 0:
                dist[u][v] = graph[u][v]

    # Create queue with maximum capacity of 1000
    node_queue = queue.Queue(maxsize=1000)

    # Floyd-Warshall algorithm with queue management
    for k in range(num_nodes):
        # Add node pairs to queue for processing
        for i in range(num_nodes):
            for j in range(num_nodes):
                # Check queue capacity constraint (max 500 items)
                if node_queue.qsize() >= 500:
                    # Process items from queue
                    while node_queue.qsize() > 0:
                        pair_data = node_queue.get()
                        src, dest, intermediate = pair_data
                        if dist[src][intermediate] + dist[intermediate][dest] < dist[src][dest]:
                            dist[src][dest] = dist[src][intermediate] + dist[intermediate][dest]

                # Add current pair to queue
                node_queue.put((i, j, k))

        # Process remaining items in queue
        while node_queue.qsize() > 0:
            pair_data = node_queue.get()
            src, dest, intermediate = pair_data
            if dist[src][intermediate] + dist[intermediate][dest] < dist[src][dest]:
                dist[src][dest] = dist[src][intermediate] + dist[intermediate][dest]

    return dist
