use std::collections::HashMap;

#[derive(Debug, Clone)]
struct Employee {
    id: u32,
    score: f64,
}

struct EmployeeProcessor {
    data: ArrayVec<(u32, f64), 100>,
}

impl EmployeeProcessor {
    fn new() -> Self {
        info!("Initializing EmployeeProcessor");
        Self {
            data: ArrayVec::new(),
        }
    }

    fn insert(&mut self, employee_id: u32, score: f64) -> Result<(), &'static str> {
        if self.data.is_full() {
            error!("ArrayVec overflow: Cannot add more than 100 tuples");
            return Err("ArrayVec overflow");
        }

        if score.is_nan() || score.is_infinite() {
            warn!("Invalid score for employee {}: {}", employee_id, score);
            return Err("Invalid score");
        }

        self.data.push((employee_id, score));
        info!("Inserted employee {} with score {}", employee_id, score);
        Ok(())
    }

    fn get(&self, index: usize) -> Option<&(u32, f64)> {
        let result = self.data.get(index);
        if result.is_some() {
            info!("Retrieved data at index {}", index);
        } else {
            warn!("No data found at index {}", index);
        }
        result
    }

    fn remove(&mut self, index: usize) -> Option<(u32, f64)> {
        if index < self.data.len() {
            let removed = self.data.remove(index);
            info!("Removed data at index {}: {:?}", index, removed);
            Some(removed)
        } else {
            warn!("Cannot remove: index {} out of bounds", index);
            None
        }
    }

    fn calculate_averages(&self) -> HashMap<u32, f64> {
        info!("Starting average calculation");

        if self.data.is_empty() {
            warn!("No data available for average calculation");
            return HashMap::new();
        }

        let mut employee_scores: HashMap<u32, Vec<f64>> = HashMap::new();

        for (id, score) in &self.data {
            employee_scores.entry(*id).or_insert_with(Vec::new).push(*score);
        }

        let mut averages = HashMap::new();
        for (id, scores) in employee_scores {
            if scores.is_empty() {
                warn!("Empty scores for employee {}", id);
                continue;
            }

            let average = scores.iter().sum::<f64>() / scores.len() as f64;
            averages.insert(id, average);
            info!("Calculated average for employee {}: {:.2}", id, average);
        }

        info!("Average calculation completed for {} employees", averages.len());
        averages
    }

    fn remove_duplicates(&mut self) {
        info!("Starting duplicate removal");
        let mut seen = std::collections::HashSet::new();
        let mut i = 0;

        while i < self.data.len() {
            let tuple = self.data[i];
            if seen.contains(&tuple) {
                self.remove(i);
                warn!("Removed duplicate entry: {:?}", tuple);
            } else {
                seen.insert(tuple);
                i += 1;
            }
        }

        info!("Duplicate removal completed");
    }

    fn len(&self) -> usize {
        self.data.len()
    }

    fn is_empty(&self) -> bool {
        self.data.is_empty()
    }
}

fn main() {
    env_logger::init();

    let mut processor = EmployeeProcessor::new();

    let sample_data = vec![
        (1, 85.5),
        (2, 92.0),
        (1, 78.5),
        (3, 88.0),
        (2, 95.5),
        (1, 85.5), // duplicate
        (4, 76.0),
    ];

    for (id, score) in sample_data {
        if let Err(e) = processor.insert(id, score) {
            error!("Failed to insert employee {}: {}", id, e);
        }
    }

    processor.remove_duplicates();

    let averages = processor.calculate_averages();

    println!("Employee Average Scores:");
    for (id, avg) in &averages {
        println!("Employee {}: {:.2}", id, avg);
    }

    info!("Processing completed with {} unique entries", processor.len());
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_insert_and_get() {
        let mut processor = EmployeeProcessor::new();
        assert!(processor.insert(1, 85.0).is_ok());
        assert_eq!(processor.get(0), Some(&(1, 85.0)));
    }

    #[test]
    fn test_overflow() {
        let mut processor = EmployeeProcessor::new();
        for i in 0..100 {
            assert!(processor.insert(i, 85.0).is_ok());
        }
        assert!(processor.insert(100, 85.0).is_err());
    }

    #[test]
    fn test_empty_data() {
        let processor = EmployeeProcessor::new();
        let averages = processor.calculate_averages();
        assert!(averages.is_empty());
    }

    #[test]
    fn test_remove_duplicates() {
        let mut processor = EmployeeProcessor::new();
        processor.insert(1, 85.0).unwrap();
        processor.insert(1, 85.0).unwrap();
        processor.remove_duplicates();
        assert_eq!(processor.len(), 1);
    }

    #[test]
    fn test_average_calculation() {
        let mut processor = EmployeeProcessor::new();
        processor.insert(1, 80.0).unwrap();
        processor.insert(1, 90.0).unwrap();
        let averages = processor.calculate_averages();
        assert_eq!(averages.get(&1), Some(&85.0));
    }
}
