        Ok(())
    }

    fn get(&self, index: usize) -> Option<&(u32, f64)> {
        info!("Retrieving data at index: {}", index);
        match self.data.get(index) {
            Some(data) => {
                info!("Found data at index {}: {:?}", index, data);
                Some(data)
            }
            None => {
                warn!("No data found at index: {}", index);
                None
            }
        }
    }

    fn remove(&mut self, index: usize) -> Option<(u32, f64)> {
        info!("Attempting to remove data at index: {}", index);

        if index >= self.data.len() {
            warn!("Invalid index for removal: {}", index);
            return None;
        }

        let removed = self.data.remove(index);
        info!("Successfully removed data: {:?}", removed);
        Some(removed)
    }

    fn calculate_average_scores(&self) -> HashMap<u32, f64> {
        info!("Starting calculation of average scores per employee");

        if self.data.is_empty() {
            warn!("No data available for processing - empty dataset");
            return HashMap::new();
        }

        let mut employee_scores: HashMap<u32, Vec<f64>> = HashMap::new();
        let mut duplicate_count = 0;

        for (employee_id, score) in &self.data {
            info!("Processing employee ID: {}, score: {}", employee_id, score);

            let scores = employee_scores.entry(*employee_id).or_insert_with(Vec::new);
            if !scores.is_empty() {
                duplicate_count += 1;
                info!("Duplicate entry found for employee ID: {}", employee_id);
            }
            scores.push(*score);
        }

        info!("Total duplicate entries processed: {}", duplicate_count);

        let mut averages = HashMap::new();
        for (employee_id, scores) in employee_scores {
            let average = scores.iter().sum::<f64>() / scores.len() as f64;
            averages.insert(employee_id, average);
            info!("Calculated average for employee ID {}: {:.2}", employee_id, average);
        }

        info!("Completed average score calculation for {} employees", averages.len());
        averages
    }

    fn len(&self) -> usize {
        self.data.len()
    }

    fn is_empty(&self) -> bool {
        self.data.is_empty()
    }
}

fn main() {
    env_logger::init();

    let mut processor = EmployeeProcessor::new();

    // Sample data processing
    let sample_data = vec![
        (101, 85.5),
        (102, 92.0),
        (101, 78.5), // Duplicate employee
        (103, 88.0),
        (102, 95.5), // Duplicate employee
    ];

    info!("Starting data processing with {} entries", sample_data.len());

    for (id, score) in sample_data {
        match processor.insert(id, score) {
            Ok(()) => info!("Successfully processed employee {} with score {}", id, score),
            Err(e) => error!("Failed to process data: {}", e),
        }
    }

    // Calculate and display averages
