int longestConsecutive(const std::vector<int>& nums) {
    if (nums.empty()) {
        return 0;
    }

    if (nums.size() > 1000) {
        throw std::invalid_argument("Array size exceeds maximum allowed size of 1000");
    }

    std::unordered_map<int, bool> numSet;
    int operations = 0;

    try {
        // Insert all numbers into unordered_map
        for (int num : nums) {
            if (operations >= 120) {
                throw std::runtime_error("Operation limit exceeded");
            }
            numSet[num] = true;
            operations++;
        }

        int maxLength = 0;

        for (int num : nums) {
            if (operations >= 120) {
                throw std::runtime_error("Operation limit exceeded");
            }

            // Check if this number is the start of a sequence
            if (numSet.find(num - 1) == numSet.end()) {
                operations++;
                int currentNum = num;
                int currentLength = 1;

                // Count consecutive numbers
                while (operations < 120 && numSet.find(currentNum + 1) != numSet.end()) {
                    operations++;
                    currentNum++;
                    currentLength++;
                }

                maxLength = std::max(maxLength, currentLength);
            } else {
                operations++;
            }
        }

        return maxLength;
    } catch (const std::exception& e) {
        throw std::runtime_error("Error processing array: " + std::string(e.what()));
    }
}
