def manage_user_data(operation, user_id=None, data=None, user_dict=None):
    """
    Manages a dataset of user inputs with a maximum of 1000 entries.

    Args:
        operation (str): Operation to perform ('insert', 'update', 'delete', 'get', 'list_all')
        user_id (str, optional): User identifier
        data (any, optional): Data to store for the user
        user_dict (dict, optional): Existing user dictionary, creates new one if None

    Returns:
        tuple: (user_dict, result of operation)
    """
    # Initialize dictionary if not provided
    if user_dict is None:
        user_dict = {}

    # Handle different operations
    if operation == "insert":
        if len(user_dict) >= 1000:
            return user_dict, "Error: Maximum capacity of 1000 entries reached"
        if user_id in user_dict:
            return user_dict, "Error: User ID already exists"
        user_dict[user_id] = data
        return user_dict, "Success: Entry inserted"

    elif operation == "update":
        if user_id not in user_dict:
            return user_dict, "Error: User ID not found"
        user_dict[user_id] = data
        return user_dict, "Success: Entry updated"

    elif operation == "delete":
        if user_id not in user_dict:
            return user_dict, "Error: User ID not found"
        del user_dict[user_id]
        return user_dict, "Success: Entry deleted"

    elif operation == "get":
        if user_id not in user_dict:
            return user_dict, "Error: User ID not found"
        return user_dict, user_dict[user_id]

    elif operation == "list_all":
        return user_dict, user_dict

    else:
        return user_dict, "Error: Invalid operation"
