from collections import OrderedDict

class LRUDataManager:
    def __init__(self, max_size=500):
        self.max_size = max_size
        self.data = OrderedDict()

    def insert(self, key, value):
        if key in self.data:
            raise ValueError(f"Key '{key}' already exists. Use update() to modify existing entries.")

        if len(self.data) >= self.max_size:
            # Remove least recently used item
            self.data.popitem(last=False)

        self.data[key] = value

    def update(self, key, value):
        if key not in self.data:
            raise KeyError(f"Key '{key}' does not exist. Use insert() to add new entries.")

        # Move to end (mark as recently used)
        self.data.move_to_end(key)
        self.data[key] = value

    def delete(self, key):
        if key not in self.data:
            raise KeyError(f"Key '{key}' does not exist.")

        del self.data[key]

    def fetch(self, key):
        if key not in self.data:
            raise KeyError(f"Key '{key}' does not exist.")

        # Move to end (mark as recently used)
        self.data.move_to_end(key)
        return self.data[key]

def create_user_data_manager():
    return LRUDataManager()
