struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class LoopDetector {
public:
    ListNode* detectLoop(ListNode* head) {
        if (!head || !head->next) return nullptr;

        std::unordered_set<ListNode*> visited;
        ListNode* current = head;

        while (current) {
            // Check if set size exceeds limit
            if (visited.size() >= 500) {
                // Clear set and continue with Floyd's algorithm as fallback
                return floydDetectLoop(current);
            }

            if (visited.find(current) != visited.end()) {
                return current; // Loop start found
            }

            visited.insert(current);
            current = current->next;
        }

        return nullptr; // No loop found
    }

private:
    ListNode* floydDetectLoop(ListNode* head) {
        ListNode* slow = head;
        ListNode* fast = head;

        // Detect if loop exists
        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
            if (slow == fast) break;
        }

        if (!fast || !fast->next) return nullptr;

        // Find loop start
        slow = head;
        while (slow != fast) {
            slow = slow->next;
            fast = fast->next;
        }

        return slow;
    }
};

