import java.util.ArrayList;
import java.util.Scanner;

public class StockAnalyzer {
    private ArrayList<Double> stockPrices;
    private static final int MAX_CAPACITY = 2000;

    public StockAnalyzer() {
        this.stockPrices = new ArrayList<>();
    }

    public boolean addPrice(double price) {
        if (stockPrices.size() >= MAX_CAPACITY) {
            return false;
        }
        return stockPrices.add(price);
    }

    public boolean removePrice(int index) {
        if (index >= 0 && index < stockPrices.size()) {
            stockPrices.remove(index);
            return true;
        }
        return false;
    }

    public double calculateMaxProfit() {
        if (stockPrices.size() < 2) {
            return 0.0;
        }

        double minPrice = stockPrices.get(0);
        double maxProfit = 0.0;

        for (int i = 1; i < stockPrices.size(); i++) {
            double currentPrice = stockPrices.get(i);
            double profit = currentPrice - minPrice;

            if (profit > maxProfit) {
                maxProfit = profit;
            }

            if (currentPrice < minPrice) {
                minPrice = currentPrice;
            }
        }

        return maxProfit;
    }

    public void displayPrices() {
        System.out.println("Stock Prices: " + stockPrices);
    }

    public int getSize() {
        return stockPrices.size();
    }

    public static void main(String[] args) {
        StockAnalyzer analyzer = new StockAnalyzer();
        Scanner scanner = new Scanner(System.in);

        System.out.println("Stock Price Analyzer (Max 2000 entries)");

        while (true) {
            System.out.println("\n1. Add price");
            System.out.println("2. Remove price");
            System.out.println("3. Calculate max profit");
            System.out.println("4. Display prices");
            System.out.println("5. Exit");
            System.out.print("Choose option: ");

            int choice = scanner.nextInt();

            switch (choice) {
                case 1:
                    System.out.print("Enter stock price: ");
                    double price = scanner.nextDouble();
                    if (analyzer.addPrice(price)) {
                        System.out.println("Price added successfully");
                    } else {
                        System.out.println("Cannot add price - capacity limit reached");
                    }
                    break;

                case 2:
                    System.out.print("Enter index to remove: ");
                    int index = scanner.nextInt();
                    if (analyzer.removePrice(index)) {
                        System.out.println("Price removed successfully");
                    } else {
                        System.out.println("Invalid index");
                    }
                    break;

                case 3:
                    double maxProfit = analyzer.calculateMaxProfit();
                    System.out.println("Maximum profit: $" + String.format("%.2f", maxProfit));
                    break;

                case 4:
                    analyzer.displayPrices();
                    System.out.println("Total entries: " + analyzer.getSize());
