public class StockAnalyzer {
    private ArrayList<Double> stockPrices;

    public StockAnalyzer() {
        this.stockPrices = new ArrayList<>();
        initializePrices();
    }

    private void initializePrices() {
        Random random = new Random();
        for (int i = 0; i < 500; i++) {
            double price = 50.0 + (random.nextDouble() * 100.0);
            stockPrices.add(price);
        }
    }

    public void addPrice(double price) {
        if (stockPrices.size() < 500) {
            stockPrices.add(price);
        } else {
            stockPrices.remove(0);
            stockPrices.add(price);
        }
    }

    public void removePrice(int index) {
        if (index >= 0 && index < stockPrices.size() && stockPrices.size() > 1) {
            stockPrices.remove(index);
        }
    }

    public double calculateMaxProfit() {
        if (stockPrices.size() < 2) {
            return 0.0;
        }

        double minPrice = stockPrices.get(0);
        double maxProfit = 0.0;

        for (int i = 1; i < stockPrices.size(); i++) {
            double currentPrice = stockPrices.get(i);
            double profit = currentPrice - minPrice;

            if (profit > maxProfit) {
                maxProfit = profit;
            }

            if (currentPrice < minPrice) {
                minPrice = currentPrice;
            }
        }

        return maxProfit;
    }

    public void ensureExactSize() {
        Random random = new Random();
        while (stockPrices.size() < 500) {
            double price = 50.0 + (random.nextDouble() * 100.0);
            stockPrices.add(price);
        }
        while (stockPrices.size() > 500) {
            stockPrices.remove(stockPrices.size() - 1);
        }
    }

    public int getSize() {
        return stockPrices.size();
    }

    public ArrayList<Double> getPrices() {
        return new ArrayList<>(stockPrices);
    }

