        analyzer.ensureExactSize();

        System.out.println("Stock prices count: " + analyzer.getSize());
        System.out.println("Maximum profit: $" + String.format("%.2f", analyzer.calculateMaxProfit()));

        analyzer.addPrice(125.50);
        analyzer.removePrice(0);
        analyzer.ensureExactSize();

        System.out.println("After operations - Stock prices count: " + analyzer.getSize());
        System.out.println("Updated maximum profit: $" + String.format("%.2f", analyzer.calculateMaxProfit()));
    }
