import java.util.Stack;
import java.util.Random;

public class StockAnalyzer {
    private static final int STACK_SIZE = 500;

    public static void main(String[] args) {
        Stack<Double> prices = generatePrices();
        double maxProfit = calculateMaxProfit(prices);
        System.out.println("Maximum possible profit: $" + maxProfit);
    }

    private static Stack<Double> generatePrices() {
        Stack<Double> prices = new Stack<>();
        Random random = new Random();

        for (int i = 0; i < STACK_SIZE; i++) {
            double price = 50 + random.nextDouble() * 50; // Random prices between $50 and $100
            prices.push(price);
        }

        return prices;
    }

    private static double calculateMaxProfit(Stack<Double> prices) {
        if (prices.size() != STACK_SIZE) {
            throw new IllegalArgumentException("Stack must contain exactly " + STACK_SIZE + " elements");
        }

        Stack<Double> tempStack = new Stack<>();
        double maxProfit = 0;

        // Transfer all elements to temporary stack (reversing order)
        while (!prices.isEmpty()) {
            tempStack.push(prices.pop());
        }

        double minPrice = tempStack.pop();
        prices.push(minPrice);

        // Process each price
        while (!tempStack.isEmpty()) {
            double currentPrice = tempStack.pop();
            prices.push(currentPrice);

            // Update max profit if selling at current price
            maxProfit = Math.max(maxProfit, currentPrice - minPrice);

            // Update minimum price if needed
            minPrice = Math.min(minPrice, currentPrice);
        }

        return maxProfit;
    }
}
