use std::collections::BTreeMap;
use std::io::{self, BufRead};

struct MedianStream {
    left_size: usize,
    right_size: usize,
    elements: BTreeMap<i32, usize>,
}

impl MedianStream {
    fn new() -> Self {
        MedianStream {
            left_size: 0,
            right_size: 0,
            elements: BTreeMap::new(),
        }
    }

    fn add(&mut self, value: i32) {
        *self.elements.entry(value).or_insert(0) += 1;

        // Rebalance the halves
        let total_size = self.left_size + self.right_size + 1;
        let target_left_size = total_size / 2;

        if self.left_size < target_left_size {
            self.left_size += 1;
        } else {
            self.right_size += 1;
        }

        self.rebalance();
    }

    fn rebalance(&mut self) {
        let total = self.left_size + self.right_size;
        let target_left = total / 2 + total % 2;

        if self.left_size == target_left {
            return;
        }

        let mut current_count = 0;
        let mut keys: Vec<i32> = self.elements.keys().cloned().collect();
        keys.sort();

        self.left_size = 0;
        self.right_size = 0;

        for key in keys {
            let count = self.elements[&key];
            let remaining = count.min(target_left - self.left_size);

            if remaining > 0 {
                self.left_size += remaining;
                if count > remaining {
                    self.right_size += count - remaining;
                }
            } else {
                self.right_size += count;
            }
        }
    }

    fn get_median(&self) -> f64 {
        if self.left_size + self.right_size == 0 {
            return 0.0;
        }

        let total = self.left_size + self.right_size;
        let is_odd = total % 2 == 1;

        let mut count = 0;
        let mut left_median = 0;
        let mut right_median = 0;

        for (&key, &freq) in &self.elements {
            count += freq;

            if count >= self.left_size && left_median == 0 {
                left_median = key;
            }

            if count >= self.left_size + 1 && right_median == 0 {
                right_median = key;
                break;
            }
        }

        if is_odd {
            left_median as f64
        } else {
            (left_median as f64 + right_median as f64) / 2.0
        }
    }

    fn size(&self) -> usize {
        self.left_size + self.right_size
    }
}

fn main() {
    let mut stream = MedianStream::new();
    let stdin = io::stdin();

    println!("Integer Stream Median Calculator");
    println!("Commands:");
    println!("  add <value>  - Add an integer to the stream");
    println!("  median       - Calculate the current median");
    println!("  size         - Show the current size of the stream");
    println!("  exit         - Exit the application");

    for line in stdin.lock().lines() {
        if let Ok(input) = line {
            let parts: Vec<&str> = input.split_whitespace().collect();

            if parts.is_empty() {
                continue;
            }

            match parts[0] {
                "add" => {
                    if parts.len() < 2 {
                        println!("Please provide a value to add");
                        continue;
                    }

                    if let Ok(value) = parts[1].parse::<i32>() {
                        if stream.size() >= 5000 {
                            println!("Maximum stream size (5000) reached");
                        } else {
                            stream.add(value);
                            println!("Added {} to the stream", value);
                        }
                    } else {
                        println!("Invalid integer value");
                    }
                },
                "median" => {
                    if stream.size() == 0 {
                        println!("Stream is empty");
                    } else {
                        println!("Current median: {}", stream.get_median());
                    }
                },
                "size" => {
                    println!("Current stream size: {}", stream.size());
                },
                "exit" => {
                    println!("Exiting...");
                    break;
                },
                _ => {
                    println!("Unknown command");
                }
            }
        }
    }
