impl MedianFinder {
    fn new() -> Self {
        Self {
            data: BTreeMap::new(),
            total_count: 0,
        }
    }

    fn add(&mut self, value: i32) {
        *self.data.entry(value).or_insert(0) += 1;
        self.total_count += 1;
    }

    fn find_median(&self) -> Option<f64> {
        if self.total_count == 0 {
            return None;
        }

        let mid = self.total_count / 2;
        let is_even = self.total_count % 2 == 0;

        let mut current_count = 0;
        let mut values = Vec::new();

        for (&value, &count) in &self.data {
            current_count += count;

            if is_even {
                if current_count >= mid && values.is_empty() {
                    values.push(value);
                }
                if current_count > mid && values.len() == 1 {
                    values.push(value);
                    break;
                }
            } else {
                if current_count > mid {
                    return Some(value as f64);
                }
            }
        }

        if is_even && values.len() == 2 {
            Some((values[0] + values[1]) as f64 / 2.0)
        } else if is_even && values.len() == 1 {
            Some(values[0] as f64)
        } else {
            None
        }
    }

    fn size(&self) -> usize {
        self.total_count
    }
}

