struct MedianFinder {
    data: BTreeMap<i32, usize>,
    total_count: usize,
    max_entries: usize,
}

impl MedianFinder {
    fn new() -> Self {
        Self {
            data: BTreeMap::new(),
            total_count: 0,
            max_entries: 2000,
        }
    }

    fn add(&mut self, num: i32) {
        if self.total_count >= 5000 {
            return;
        }

        *self.data.entry(num).or_insert(0) += 1;
        self.total_count += 1;

        if self.data.len() > self.max_entries {
            self.compact();
        }
    }

    fn compact(&mut self) {
        let target_size = self.max_entries / 2;
        let mut to_remove = Vec::new();

        for (&key, &count) in &self.data {
            if count == 0 {
                to_remove.push(key);
            }
            if self.data.len() - to_remove.len() <= target_size {
                break;
            }
        }

        for key in to_remove {
            self.data.remove(&key);
        }
    }

    fn find_median(&mut self) -> Option<f64> {
        if self.total_count == 0 {
            return None;
        }

        let mut cumulative_count = 0;
        let median_pos1 = (self.total_count + 1) / 2;
        let median_pos2 = (self.total_count + 2) / 2;

        let mut median1 = None;
        let mut median2 = None;

        for (&value, &count) in &self.data {
            cumulative_count += count;

            if median1.is_none() && cumulative_count >= median_pos1 {
                median1 = Some(value);
            }

            if median2.is_none() && cumulative_count >= median_pos2 {
                median2 = Some(value);
                break;
            }
        }

        match (median1, median2) {
            (Some(m1), Some(m2)) => Some((m1 as f64 + m2 as f64) / 2.0),
            _ => None,
        }
    }

    fn size(&self) -> usize {
        self.total_count
    }
}

fn main() {
    let mut finder = MedianFinder::new();

    println!("Median Finder - Enter integers or 'median' to compute, 'quit' to exit:");

