        print!("> ");
        io::stdout().flush().unwrap();

        let mut input = String::new();
        io::stdin().read_line(&mut input).unwrap();
        let input = input.trim();

        match input {
            "quit" => break,
            "median" => {
                match finder.find_median() {
                    Some(median) => println!("Current median: {}", median),
                    None => println!("No data available"),
                }
            }
            "size" => {
                println!("Current size: {}", finder.size());
            }
            _ => {
                match input.parse::<i32>() {
                    Ok(num) => {
                        finder.add(num);
                        println!("Added: {}", num);
                    }
                    Err(_) => println!("Invalid input. Enter an integer, 'median', or 'quit'"),
                }
            }
        }
    }
