struct MedianFinder {
    data: BTreeMap<i32, usize>,
    total_count: usize,
    max_entries: usize,
    max_integers: usize,
}

impl MedianFinder {
    fn new() -> Self {
        Self {
            data: BTreeMap::new(),
            total_count: 0,
            max_entries: 2000,
            max_integers: 5000,
        }
    }

    fn add(&mut self, num: i32) -> Result<(), &'static str> {
        if self.total_count >= self.max_integers {
            return Err("Maximum number of integers (5000) reached");
        }

        if self.data.len() >= self.max_entries && !self.data.contains_key(&num) {
            return Err("Maximum BTreeMap entries (2000) reached");
        }

        *self.data.entry(num).or_insert(0) += 1;
        self.total_count += 1;
        Ok(())
    }

    fn find_median(&self) -> Option<f64> {
        if self.total_count == 0 {
            return None;
        }

        let mid = self.total_count / 2;
        let mut count = 0;
        let mut values = Vec::new();

        for (&value, &freq) in &self.data {
            count += freq;
            if values.is_empty() && count > mid {
                values.push(value);
                if self.total_count % 2 == 1 {
                    break;
                }
            }
            if values.len() == 1 && count > mid {
                values.push(value);
                break;
            }
            if count == mid && self.total_count % 2 == 0 {
                values.push(value);
            }
        }

        if self.total_count % 2 == 1 {
            Some(values[0] as f64)
        } else {
            Some((values[0] + values[1]) as f64 / 2.0)
