type StockPrice struct {
	Price     float64
	Timestamp time.Time
}

type RollingAverage struct {
	BatchNum int
	Average  float64
}

func main() {
	// Input channel for real-time stock prices
	priceChan := make(chan StockPrice, 1000)

	// Channel for rolling averages output
	avgChan := make(chan RollingAverage, 100)

	var wg sync.WaitGroup

	// Start stock price generator (simulating real-time data)
	wg.Add(1)
	go func() {
		defer wg.Done()
		defer close(priceChan)
		generateStockPrices(priceChan)
	}()

	// Start processing engine
	wg.Add(1)
	go func() {
		defer wg.Done()
		defer close(avgChan)
		processStockPrices(priceChan, avgChan)
	}()

	// Start output consumer
	wg.Add(1)
	go func() {
		defer wg.Done()
		consumeAverages(avgChan)
	}()

	wg.Wait()
}

func generateStockPrices(priceChan chan<- StockPrice) {
	// Simulate generating stock prices
	for i := 0; i < 10000; i++ {
		price := StockPrice{
			Price:     100.0 + rand.Float64()*10.0,
			Timestamp: time.Now(),
		}
		priceChan <- price
		time.Sleep(time.Microsecond * 100) // Simulate real-time delay
	}
}

func processStockPrices(priceChan <-chan StockPrice, avgChan chan<- RollingAverage) {
	batch := make([]float64, 0, 1000)
	batchNum := 1

	for price := range priceChan {
		batch = append(batch, price.Price)

		if len(batch) == 1000 {
			// Process batch asynchronously to not block incoming data
			processBatch(batch, batchNum, avgChan)
			batch = make([]float64, 0, 1000)
			batchNum++
		}
	}

	// Process any remaining prices
	if len(batch) > 0 {
		processBatch(batch, batchNum, avgChan)
	}
}

func processBatch(batch []float64, batchNum int, avgChan chan<- RollingAverage) {
	go func() {
		sum := 0.0
		for _, price := range batch {
			sum += price
		}

		avg := RollingAverage{
			BatchNum: batchNum,
			Average:  sum / float64(len(batch)),
		}

		avgChan <- avg
	}()
}

func consumeAverages(avgChan <-chan RollingAverage) {
	for avg := range avgChan {
		fmt.Printf("Batch %d: Average Price = %.2f\n", avg.BatchNum, avg.Average)
	}
