	stockChannel := make(chan StockPrice, 1000)

	var wg sync.WaitGroup

	// Start the price processor
	wg.Add(1)
	go processPrices(stockChannel, &wg)

	// Start the price generator (simulating real-time data)
	wg.Add(1)
	go generatePrices(stockChannel, &wg)

	// Let it run for demonstration
	time.Sleep(10 * time.Second)
	close(stockChannel)

	wg.Wait()
}

func generatePrices(ch chan<- StockPrice, wg *sync.WaitGroup) {
	defer wg.Done()

	symbols := []string{"AAPL", "GOOGL", "MSFT", "TSLA", "AMZN"}

	for i := 0; i < 5000; i++ {
		price := StockPrice{
			Symbol: symbols[i%len(symbols)],
			Price:  100.0 + float64(i%100),
			Time:   time.Now(),
		}

		// Send operation
		select {
		case ch <- price:
		default:
			// Channel full, skip this price to avoid blocking
		}

		time.Sleep(time.Millisecond)
	}
}

func processPrices(ch <-chan StockPrice, wg *sync.WaitGroup) {
	defer wg.Done()

	batch := make([]StockPrice, 0, 1000)

	for {
		// Receive operation
		price, ok := <-ch
		if !ok {
			// Channel closed, process remaining batch if any
			if len(batch) > 0 {
				processRollingAverage(batch)
			}
			break
		}

		batch = append(batch, price)

		// Process batch when it reaches 1000 items
		if len(batch) == 1000 {
			// Process in separate goroutine to avoid blocking
			go processRollingAverage(batch)
			batch = make([]StockPrice, 0, 1000)
		}
	}
}

func processRollingAverage(batch []StockPrice) {
	if len(batch) == 0 {
		return
	}

	// Group by symbol
	symbolPrices := make(map[string][]float64)

	for _, price := range batch {
		symbolPrices[price.Symbol] = append(symbolPrices[price.Symbol], price.Price)
	}

	// Calculate rolling averages for each symbol
	for symbol, prices := range symbolPrices {
		if len(prices) > 0 {
			sum := 0.0
			for _, price := range prices {
				sum += price
			}
			average := sum / float64(len(prices))
			fmt.Printf("Rolling average for %s: %.2f (batch size: %d)\n", 
				symbol, average, len(prices))
		}
	}
}
