func generateStockPrices(ch chan<- StockPrice) {
	symbols := []string{"AAPL", "GOOGL", "MSFT", "TSLA", "AMZN"}

	for {
		// Send (push) operation - non-blocking due to buffer
		select {
		case ch <- StockPrice{
			Symbol: symbols[rand.Intn(len(symbols))],
			Price:  100 + rand.Float64()*50,
		}:
		default:
			// Channel full, skip this price to avoid blocking
		}
		time.Sleep(time.Millisecond)
	}
}

func processStockPrices(ch <-chan StockPrice) {
	batch := make([]float64, 0, 1000)
	batchCount := 1

	for {
		// Receive (pop) operation - FIFO behavior
		price := <-ch

		// Add price to current batch
		batch = append(batch, price.Price)

		// Process batch when it reaches 1000 prices
		if len(batch) == 1000 {
			avg := calculateAverage(batch)
			fmt.Printf("Batch %d - Rolling Average: %.2f\n", batchCount, avg)

			// Reset batch for next 1000 prices
			batch = batch[:0]
			batchCount++
		}
	}
}

func calculateAverage(prices []float64) float64 {
	sum := 0.0
	for _, price := range prices {
		sum += price
	}
	return sum / float64(len(prices))
