import heapq

class KthSmallestFinder:
    def __init__(self, k):
        self.k = min(k, 400)  # Ensure k is at most 400
        self.min_heap = []    # Min-heap to store k largest elements
        self.count = 0        # Total elements seen so far

    def insert(self, num):
        if self.count < self.k:
            # If we haven't seen k elements yet, just add to the heap
            heapq.heappush(self.min_heap, num)
        elif num > self.min_heap[0]:
            # If new number is larger than the smallest in our heap,
            # remove the smallest and add the new number
            heapq.heappop(self.min_heap)
            heapq.heappush(self.min_heap, num)

        self.count += 1

    def get_kth_smallest(self):
        if self.count < self.k:
            return None  # Not enough elements yet
        return self.min_heap[0]
