#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

class PermutationGenerator {
private:
    std::vector<int> current_permutation;
    std::set<std::vector<int>> unique_permutations;
    std::vector<int> numbers;
    std::vector<bool> used;

public:
    void generatePermutations(const std::vector<int>& input) {
        numbers = input;
        used.resize(numbers.size(), false);
        current_permutation.clear();
        unique_permutations.clear();

        backtrack();
    }

    void backtrack() {
        if (current_permutation.size() == numbers.size()) {
            if (unique_permutations.size() < 1500) {
                unique_permutations.insert(current_permutation);
            }
            return;
        }

        for (int i = 0; i < numbers.size(); i++) {
            if (!used[i]) {
                current_permutation.push_back(numbers[i]);
                used[i] = true;

                backtrack();

                current_permutation.pop_back();
                used[i] = false;
            }
        }
    }

    void printPermutations() {
        for (const auto& perm : unique_permutations) {
            for (int num : perm) {
                std::cout << num << " ";
            }
            std::cout << std::endl;
        }
        std::cout << "Total unique permutations: " << unique_permutations.size() << std::endl;
    }
};

int main() {
    std::vector<int> numbers = {1, 2, 2, 3};

    PermutationGenerator generator;
    generator.generatePermutations(numbers);
    generator.printPermutations();

    return 0;
}
