#include <algorithm>
#include <set>

class PermutationGenerator {
private:
    std::vector<std::vector<int>> tempStorage;
    std::set<std::vector<int>> uniquePerms;

    void generatePermutations(std::vector<int>& nums, int start) {
        if (start == nums.size()) {
            tempStorage.push_back(nums);

            // Clear vector when it reaches size limit for memory management
            if (tempStorage.size() >= 1500) {
                for (const auto& perm : tempStorage) {
                    uniquePerms.insert(perm);
                }
                tempStorage.clear();
            }
            return;
        }

        for (int i = start; i < nums.size(); i++) {
            std::swap(nums[start], nums[i]);
            generatePermutations(nums, start + 1);
            std::swap(nums[start], nums[i]);
        }
    }

public:
    std::vector<std::vector<int>> findUniquePermutations(std::vector<int> nums) {
        tempStorage.clear();
        uniquePerms.clear();

        generatePermutations(nums, 0);

        // Process remaining permutations in tempStorage
        for (const auto& perm : tempStorage) {
            uniquePerms.insert(perm);
        }
        tempStorage.clear();

        // Convert set back to vector using push_back
        std::vector<std::vector<int>> result;
        for (const auto& perm : uniquePerms) {
            result.push_back(perm);
        }

        return result;
    }
};

int main() {
    PermutationGenerator generator;
    std::vector<int> numbers = {1, 2, 2, 3};

    std::vector<std::vector<int>> uniquePermutations = generator.findUniquePermutations(numbers);

    std::cout << "Unique permutations:\n";
    for (const auto& perm : uniquePermutations) {
        for (int num : perm) {
            std::cout << num << " ";
        }
        std::cout << "\n";
    }

    return 0;
}
