#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>
#include <set>

class PermutationGenerator {
private:
    std::vector<std::vector<int>> permutations;
    std::stack<std::vector<int>> processingStack;
    std::set<std::vector<int>> uniqueCheck;

    void generatePermutations(std::vector<int>& nums, std::vector<int>& current, std::vector<bool>& used) {
        if (current.size() == nums.size()) {
            if (uniqueCheck.find(current) == uniqueCheck.end()) {
                uniqueCheck.insert(current);
                permutations.push_back(current);

                if (permutations.size() >= 1500) {
                    processingStack.push(permutations.back());
                    permutations.clear();
                }
            }
            return;
        }

        for (int i = 0; i < nums.size(); i++) {
            if (!used[i]) {
                used[i] = true;
                current.push_back(nums[i]);
                generatePermutations(nums, current, used);
                current.pop_back();
                used[i] = false;
            }
        }
    }

public:
    void findUniquePermutations(std::vector<int>& numbers) {
        std::vector<int> current;
        std::vector<bool> used(numbers.size(), false);

        permutations.clear();
        while (!processingStack.empty()) {
            processingStack.pop();
        }
        uniqueCheck.clear();

        generatePermutations(numbers, current, used);
    }

    void displayResults() {
        std::cout << "Unique permutations found:\n";

        while (!processingStack.empty()) {
            std::vector<int> perm = processingStack.top();
            processingStack.pop();

            for (int num : perm) {
                std::cout << num << " ";
            }
            std::cout << "\n";
        }

        for (const auto& perm : permutations) {
            for (int num : perm) {
                std::cout << num << " ";
            }
            std::cout << "\n";
        }

        permutations.clear();
    }
};

int main() {
    std::vector<int> numbers = {1, 2, 2, 3};

    PermutationGenerator generator;
    generator.findUniquePermutations(numbers);
    generator.displayResults();

    return 0;
}
