struct Customer {
    id: u32,
    arrival_time: u32,
    service_time: u32,
}

fn serve_customers(customer_list: Vec<(u32, u32)>) -> f64 {
    let mut queue = VecDeque::new();
    let mut current_time = 0;
    let mut total_wait_time = 0;
    let mut customers_processed = 0;

    // Create customers from the input list
    let mut customers = customer_list.iter().enumerate().map(|(index, (arrival, service))| {
        Customer {
            id: index as u32 + 1,
            arrival_time: *arrival,
            service_time: *service,
        }
    }).collect::<Vec<Customer>>();

    // Sort customers by arrival time
    customers.sort_by_key(|c| c.arrival_time);

    for customer in customers {
        // If current time is less than arrival time, advance time
        if current_time < customer.arrival_time {
            current_time = customer.arrival_time;
        }

        // Enqueue customer
        queue.push_back(customer);

        // Process customers from queue
        while !queue.is_empty() {
            // Dequeue customer
            if let Some(next_customer) = queue.pop_front() {
                // Calculate wait time
                let wait_time = current_time - next_customer.arrival_time;
                total_wait_time += wait_time;

                // Process this customer
                current_time += next_customer.service_time;
                customers_processed += 1;

                println!("Customer {} processed. Wait time: {} units", next_customer.id, wait_time);
            }
        }
    }

    // Calculate and return average wait time
    if customers_processed > 0 {
        let average_wait_time = total_wait_time as f64 / customers_processed as f64;
        println!("Average wait time: {:.2} units", average_wait_time);
        average_wait_time
    } else {
        0.0
    }
}
