use std::collections::VecDeque;

fn serve_customers(arrival_times: &[u64], service_times: &[u64]) -> f64 {
    const MAX_CAPACITY: usize = 100;
    let mut queue: VecDeque<(u64, u64)> = VecDeque::with_capacity(MAX_CAPACITY);
    let mut current_time = 0;
    let mut total_wait_time = 0;
    let mut customers_served = 0;

    for i in 0..arrival_times.len() {
        if queue.len() >= MAX_CAPACITY {
            println!("Queue at maximum capacity. Cannot accept more customers.");
            continue;
        }

        let arrival_time = arrival_times[i];
        let service_time = service_times[i];

        // Add customer to queue
        queue.push_back((arrival_time, service_time));

        // Process customers when possible
        while !queue.is_empty() {
            let (customer_arrival, customer_service) = *queue.front().unwrap();

            // Update current time if needed
            if current_time < customer_arrival {
                current_time = customer_arrival;
            }

            // Calculate wait time and serve customer
            let wait_time = current_time - customer_arrival;
            total_wait_time += wait_time;
            current_time += customer_service;
            customers_served += 1;

            // Remove served customer
            queue.pop_front();

            // Only process one customer per iteration
            break;
        }
    }

    // Process any remaining customers in the queue
    while !queue.is_empty() {
        let (customer_arrival, customer_service) = *queue.front().unwrap();

        // Calculate wait time and serve customer
        let wait_time = current_time - customer_arrival;
        total_wait_time += wait_time;
        current_time += customer_service;
        customers_served += 1;

        // Remove served customer
        queue.pop_front();
    }

    // Calculate and return average wait time
    if customers_served > 0 {
        total_wait_time as f64 / customers_served as f64
    } else {
        0.0
    }
}
