import java.util.*;
import java.time.LocalDateTime;

class Alert {
    private int severity;
    private LocalDateTime timestamp;
    private String message;

    public Alert(int severity, LocalDateTime timestamp, String message) {
        this.severity = severity;
        this.timestamp = timestamp;
        this.message = message;
    }

    public int getSeverity() { return severity; }
    public LocalDateTime getTimestamp() { return timestamp; }
    public String getMessage() { return message; }

    @Override
    public String toString() {
        return String.format("Alert[Severity: %d, Time: %s, Message: %s]", 
                           severity, timestamp, message);
    }
}

class AlertComparator implements Comparator<Alert> {
    @Override
    public int compare(Alert a1, Alert a2) {
        // Higher severity first (descending order)
        int severityCompare = Integer.compare(a2.getSeverity(), a1.getSeverity());
        if (severityCompare != 0) {
            return severityCompare;
        }
        // If same severity, earlier timestamp first
        return a1.getTimestamp().compareTo(a2.getTimestamp());
    }
}

public class EmergencyAlertSystem {
    private PriorityQueue<Alert> alertQueue;
    private static final int MAX_ALERTS = 10;

    public EmergencyAlertSystem() {
        this.alertQueue = new PriorityQueue<>(MAX_ALERTS, new AlertComparator());
    }

    public void processEmergencyAlerts() {
        // Add alert to queue
        addAlert(new Alert(5, LocalDateTime.now(), "Critical system failure"));
        addAlert(new Alert(3, LocalDateTime.now(), "Network connectivity issue"));
        addAlert(new Alert(5, LocalDateTime.now(), "Security breach detected"));

        // Process alerts
        processAlerts();
    }

    public boolean addAlert(Alert alert) {
        if (alertQueue.size() >= MAX_ALERTS) {
            // Remove lowest priority alert if queue is full
            Alert lowestPriority = Collections.min(alertQueue, new AlertComparator().reversed());
            if (new AlertComparator().compare(alert, lowestPriority) < 0) {
                alertQueue.remove(lowestPriority);
                alertQueue.offer(alert);
                return true;
            }
            return false;
        }
        return alertQueue.offer(alert);
    }

    public Alert peekAlert() {
        return alertQueue.peek();
    }

    public Alert removeAlert() {
        return alertQueue.poll();
    }

    public void processAlerts() {
        System.out.println("Processing alerts in priority order:");
        while (!alertQueue.isEmpty()) {
            Alert alert = removeAlert();
            System.out.println("Processing: " + alert);
        }
    }

    public int getQueueSize() {
        return alertQueue.size();
    }

    public boolean isQueueFull() {
        return alertQueue.size() >= MAX_ALERTS;
    }
}
