        std::stack<int> temp = scores;
        while (!temp.empty()) {
            if (temp.top() == score) {
                return true;
            }
            temp.pop();
        }
        return false;
    }

    void sortDescending() {
        std::vector<int> temp;
        while (!scores.empty()) {
            temp.push_back(scores.top());
            scores.pop();
        }
        std::sort(temp.begin(), temp.end(), std::greater<int>());
        for (int score : temp) {
            scores.push(score);
        }
    }

    std::stack<int> getScores() const {
        return scores;
    }
};

