package main

import (
	"fmt"
	"math/rand"
	"sync"
	"time"
)

type StockQuote struct {
	Ticker string
	Price  float64
}

func streamStockQuotes() {
	quotes := make(chan StockQuote, 100)
	priceMap := make(map[string][]float64)
	var mu sync.RWMutex

	tickers := []string{"AAPL", "GOOGL", "MSFT", "TSLA", "AMZN"}

	// Start goroutines for each ticker
	for _, ticker := range tickers {
		go func(t string) {
			for {
				price := 100 + rand.Float64()*200 // Random price between 100-300
				quotes <- StockQuote{Ticker: t, Price: price}
				time.Sleep(time.Duration(rand.Intn(1000)+500) * time.Millisecond)
			}
		}(ticker)
	}

	// Start goroutine to print averages regularly
	go func() {
		ticker := time.NewTicker(5 * time.Second)
		defer ticker.Stop()
		for range ticker.C {
			mu.RLock()
			fmt.Println("\n--- Average Stock Prices ---")
			for ticker, prices := range priceMap {
				if len(prices) > 0 {
					sum := 0.0
					for _, price := range prices {
						sum += price
					}
					avg := sum / float64(len(prices))
					fmt.Printf("%s: $%.2f (samples: %d)\n", ticker, avg, len(prices))
				}
			}
			fmt.Println("---------------------------")
			mu.RUnlock()
		}
	}()

	// Main goroutine processes quotes
	for quote := range quotes {
		mu.Lock()
		prices := priceMap[quote.Ticker]

		// Add new price
		prices = append(prices, quote.Price)

		// Remove oldest price if limit exceeded (pop operation)
		if len(prices) > 50 {
			prices = prices[1:] // Remove first element
		}

		priceMap[quote.Ticker] = prices
		mu.Unlock()
	}
}

func main() {
	streamStockQuotes()
}
