        match inventory_changes.get(product_id) {
            Some(&current_change) => {
                inventory_changes.insert(product_id.to_string(), current_change + change);
            },
            None => {
                inventory_changes.insert(product_id.to_string(), change);
            }
        }

        true
    }

    // Example usage
    add_inventory_change(&mut inventory_changes, "PROD001", 10);
    add_inventory_change(&mut inventory_changes, "PROD002", -5);
    add_inventory_change(&mut inventory_changes, "PROD001", -2);

    inventory_changes
