def merge_intervals(intervals):
    if len(intervals) > 5:
        return "Error: Cannot process more than 5 intervals"

    if not intervals:
        return []

    intervals.sort(key=lambda x: x[0])
    result = [intervals[0]]

    for i in range(1, len(intervals)):
        current = intervals[i]
        last = result[-1]

        if current[0] <= last[1]:
            last_interval = result.pop()
            result.append((last_interval[0], max(last_interval[1], current[1])))
        else:
            result.append(current)

    return result
