def manageEmergencyQueue():
    # Initialize the emergency queue with max capacity of 10
    emergency_queue = deque(maxlen=10)

    def add_patient(patient_id, severity_score):
        """Add a new patient to the queue based on severity"""
        patient = (patient_id, severity_score)

        # If queue is empty, just append
        if not emergency_queue:
            emergency_queue.append(patient)
            return True

        # Find the right position based on severity
        for i in range(len(emergency_queue)):
            if severity_score > emergency_queue[i][1]:
                emergency_queue.insert(i, patient)
                return True

        # If this patient has lowest priority, append to the end
        if len(emergency_queue) < 10:
            emergency_queue.append(patient)
            return True
        return False  # Queue is full and new patient has lowest priority

    def get_next_patient():
        """Get the highest priority patient"""
        if emergency_queue:
            return emergency_queue.popleft()
        return None

    def reevaluate_priority(patient_id, new_severity):
        """Update severity score for a patient and reposition in queue"""
        # Find and remove the patient
        for i in range(len(emergency_queue)):
            if emergency_queue[i][0] == patient_id:
                emergency_queue.remove(emergency_queue[i])
                # Re-add with new severity
                add_patient(patient_id, new_severity)
                return True
        return False

    def view_queue():
        """Return the current queue"""
        return list(emergency_queue)

    # Return functions to interact with the queue
    return {
        "add": add_patient,
        "next": get_next_patient,
        "reevaluate": reevaluate_priority,
        "view": view_queue
    }
