        emergency_queue.append(patient)
        # Sort by severity (highest first)
        sorted_queue = sorted(emergency_queue, key=lambda x: x[1], reverse=True)
        emergency_queue.clear()
        for patient in sorted_queue:
            emergency_queue.append(patient)
        return list(emergency_queue)

    def process_next_patient():
        if emergency_queue:
            return emergency_queue.pop()
        return None

    def get_queue():
        return list(emergency_queue)

    return {
        "add_patient": add_patient,
        "process_next_patient": process_next_patient,
        "get_queue": get_queue
