use std::collections::LinkedList;

#[derive(Debug, Clone)]
struct Track {
    id: u32,
    title: String,
    artist: String,
}

struct PlaybackQueue {
    tracks: LinkedList<Track>,
    current_position: usize,
    max_size: usize,
}

impl PlaybackQueue {
    fn new() -> Self {
        PlaybackQueue {
            tracks: LinkedList::new(),
            current_position: 0,
            max_size: 20,
        }
    }

    fn add_track(&mut self, track: Track) -> bool {
        if self.tracks.len() >= self.max_size {
            return false;
        }
        self.tracks.push_back(track);
        true
    }

    fn remove_track(&mut self, track_id: u32) -> bool {
        let mut cursor = self.tracks.cursor_front_mut();
        let mut index = 0;

        while let Some(track) = cursor.current() {
            if track.id == track_id {
                cursor.remove_current();
                if index < self.current_position {
                    self.current_position = self.current_position.saturating_sub(1);
                } else if index == self.current_position && self.current_position >= self.tracks.len() {
                    self.current_position = self.tracks.len().saturating_sub(1);
                }
                return true;
            }
            cursor.move_next();
            index += 1;
        }
        false
    }

    fn skip_next(&mut self) -> Option<&Track> {
        if self.tracks.is_empty() {
            return None;
        }
        self.current_position = (self.current_position + 1) % self.tracks.len();
        self.get_current_track()
    }

    fn skip_previous(&mut self) -> Option<&Track> {
        if self.tracks.is_empty() {
            return None;
        }
        if self.current_position == 0 {
            self.current_position = self.tracks.len() - 1;
        } else {
            self.current_position -= 1;
        }
        self.get_current_track()
    }

    fn reset_to_first(&mut self) -> Option<&Track> {
        if self.tracks.is_empty() {
            return None;
        }
        self.current_position = 0;
        self.get_current_track()
    }

    fn get_current_track(&self) -> Option<&Track> {
        if self.tracks.is_empty() {
            return None;
        }
        let mut cursor = self.tracks.cursor_front();
        for _ in 0..self.current_position {
            cursor.move_next();
        }
        cursor.current()
    }
}

fn manage_playback_queue() -> PlaybackQueue {
    PlaybackQueue::new()
}
