use std::collections::LinkedList;

pub fn manage_playback_queue(command: &str, track: Option<String>, queue: &mut LinkedList<String>) -> Result<(), String> {
    const MAX_QUEUE_SIZE: usize = 20;

    match command {
        "add" => {
            if let Some(track_name) = track {
                if queue.len() >= MAX_QUEUE_SIZE {
                    return Err("Queue is full (max 20 tracks)".to_string());
                }
                queue.push_back(track_name);
                Ok(())
            } else {
                Err("No track provided to add".to_string())
            }
        },
        "remove" => {
            if let Some(track_name) = track {
                let initial_len = queue.len();
                queue.retain(|t| t != &track_name);

                if queue.len() == initial_len {
                    return Err(format!("Track '{}' not found in queue", track_name));
                }
                Ok(())
            } else {
                Err("No track provided to remove".to_string())
            }
        },
        "next" => {
            if queue.is_empty() {
                return Err("Queue is empty".to_string());
            }

            let front = queue.pop_front().unwrap();
            queue.push_back(front);
            Ok(())
        },
        "previous" => {
            if queue.is_empty() {
                return Err("Queue is empty".to_string());
            }

            let back = queue.pop_back().unwrap();
            queue.push_front(back);
            Ok(())
        },
        "reset" => {
            if queue.is_empty() {
                return Err("Queue is empty".to_string());
            }
            Ok(())
        },
        _ => Err(format!("Unknown command: {}", command))
    }
}
