public void safeIncrementCount(List<String> responses, ConcurrentHashMap<String, Integer> countMap) {
    for (String response : responses) {
        countMap.putIfAbsent(response, 0);
        countMap.compute(response, (key, value) -> value + 1);

        // Restrict map size to 100 elements
        if (countMap.size() > 100) {
            // Find and remove entry with minimum count
            String minKey = null;
            int minValue = Integer.MAX_VALUE;

            for (Map.Entry<String, Integer> entry : countMap.entrySet()) {
                if (entry.getValue() < minValue) {
                    minValue = entry.getValue();
                    minKey = entry.getKey();
                }
            }

            if (minKey != null) {
                countMap.compute(minKey, (key, value) -> null); // Remove entry
