struct EmailQueue {
    queue: VecDeque<EmailTask>,
    max_size: usize,
}

impl EmailQueue {
    fn new(max_size: usize) -> Self {
        EmailQueue {
            queue: VecDeque::with_capacity(max_size),
            max_size,
        }
    }

    fn enqueue(&mut self, task: EmailTask) -> Result<(), &'static str> {
        if self.queue.len() >= self.max_size {
            return Err("Queue is full, cannot add more email tasks");
        }
        self.queue.push_back(task);
        Ok(())
    }

    fn dequeue(&mut self) -> Option<EmailTask> {
        self.queue.pop_front()
    }

    fn shuffle_urgent(&mut self) {
        let mut rng = thread_rng();
        let mut vec: Vec<_> = self.queue.drain(..).collect();

        // Move urgent emails toward the front
        vec.sort_by(|a, b| b.is_urgent.cmp(&a.is_urgent));

        // Add some randomness to urgent emails
        if let Some(urgent_section) = vec.iter_mut().position(|task| !task.is_urgent) {
            vec[0..urgent_section].shuffle(&mut rng);
        }

        self.queue.extend(vec);
    }
