use smallvec::SmallVec;

fn combine_small_data_streams<T, I>(streams: Vec<I>) -> impl Iterator<Item = T>
where
    T: Clone,
    I: Iterator<Item = T>,
{
    let streams = streams.into_iter().collect::<Vec<_>>();
    let mut buffer = SmallVec::<[T; 16]>::new();
    let mut current_stream = 0;

    std::iter::from_fn(move || {
        loop {
            if current_stream >= streams.len() {
                if !buffer.is_empty() {
                    let item = buffer[0].clone();
                    buffer.clear();
                    buffer.push(item);
                    return Some(item);
                }
                current_stream = 0;
            }

            if let Some(item) = streams[current_stream].next() {
                buffer.push(item);
                current_stream += 1;
                return Some(buffer[buffer.len() - 1].clone());
            } else {
                current_stream += 1;
            }
        }
    })
}
