func logEvents(eventStream <-chan string, batchSize int, flushInterval time.Duration) error {
	buffer := bytes.Buffer{}
	ticker := time.NewTicker(flushInterval)
	defer ticker.Stop()

	for {
		select {
		case event, ok := <-eventStream:
			if !ok {
				// Channel closed, flush remaining events
				if buffer.Len() > 0 {
					if err := flushBuffer(&buffer); err != nil {
						return err
					}
				}
				return nil
			}

			buffer.WriteString(event)
			buffer.WriteByte('\n')

			// Flush if buffer exceeds batch size
			if buffer.Len() >= batchSize {
				if err := flushBuffer(&buffer); err != nil {
					return err
				}
			}

		case <-ticker.C:
			// Periodic flush based on time interval
			if buffer.Len() > 0 {
				if err := flushBuffer(&buffer); err != nil {
					return err
				}
			}
		}
	}
}

