func logEvents(capacity int, flushInterval time.Duration, flushSize int) (*LogEventProcessor, error) {
	if capacity <= 0 || flushSize <= 0 || flushSize > capacity {
		return nil, fmt.Errorf("invalid buffer parameters")
	}

	processor := &LogEventProcessor{
		buffer:        bytes.NewBuffer(make([]byte, 0, capacity)),
		capacity:      capacity,
		flushSize:     flushSize,
		flushInterval: flushInterval,
		done:          make(chan struct{}),
	}

	go processor.periodicFlush()
	return processor, nil
}

type LogEventProcessor struct {
	buffer        *bytes.Buffer
	capacity      int
	flushSize     int
	flushInterval time.Duration
	mu            sync.Mutex
	done          chan struct{}
}

func (p *LogEventProcessor) Write(event []byte) error {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.buffer.Len()+len(event) > p.capacity {
		return fmt.Errorf("buffer capacity exceeded")
	}

	if _, err := p.buffer.Write(event); err != nil {
		return err
	}

	if p.buffer.Len() >= p.flushSize {
		return p.flush()
	}

	return nil
}

func (p *LogEventProcessor) Read(b []byte) (int, error) {
	p.mu.Lock()
	defer p.mu.Unlock()

	return p.buffer.Read(b)
}

func (p *LogEventProcessor) flush() error {
	// Implementation would write buffer contents to destination
	// This is a placeholder for actual implementation
	p.buffer.Reset()
	return nil
}

func (p *LogEventProcessor) periodicFlush() {
	ticker := time.NewTicker(p.flushInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			p.mu.Lock()
			p.flush()
			p.mu.Unlock()
		case <-p.done:
			return
		}
	}
}

func (p *LogEventProcessor) Close() error {
	p.mu.Lock()
	defer p.mu.Unlock()

	close(p.done)
	return p.flush()
}
