type EventLogger struct {
	buffer     *bytes.Buffer
	maxEvents  int
	eventCount int
	batchSize  int
	mu         sync.Mutex
	flushCh    chan struct{}
	done       chan struct{}
}

func NewEventLogger(maxEvents, batchSize int, flushInterval time.Duration) *EventLogger {
	logger := &EventLogger{
		buffer:     bytes.NewBuffer(nil),
		maxEvents:  maxEvents,
		batchSize:  batchSize,
		flushCh:    make(chan struct{}),
		done:       make(chan struct{}),
	}

	go logger.flushLoop(flushInterval)
	return logger
}

func (e *EventLogger) flushLoop(interval time.Duration) {
	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			e.Flush()
		case <-e.flushCh:
			e.Flush()
		case <-e.done:
			e.Flush()
			return
		}
	}
}

func (e *EventLogger) Write(event []byte) error {
	e.mu.Lock()
	defer e.mu.Unlock()

	if e.eventCount >= e.maxEvents {
		return errors.New("buffer capacity exceeded")
	}

	if _, err := e.buffer.Write(event); err != nil {
		return err
	}
	e.buffer.WriteByte('\n')

	e.eventCount++

	if e.eventCount >= e.batchSize {
		go func() { e.flushCh <- struct{}{} }()
	}

	return nil
}

func (e *EventLogger) Flush() {
	e.mu.Lock()
	defer e.mu.Unlock()

	if e.eventCount == 0 {
		return
	}

	// Process events here (e.g., send to storage, analytics, etc.)
	// For demonstration, we'll just print the buffer content
	// In a real implementation, you would process the data here

	e.buffer.Reset()
	e.eventCount = 0
}

func (e *EventLogger) Close() {
	close(e.done)
}

func logEvents(maxEvents, batchSize int, flushInterval time.Duration) *EventLogger {
	return NewEventLogger(maxEvents, batchSize, flushInterval)
