#include <vector>
#include <queue>
#include <algorithm>

std::vector<std::pair<int, int>> mergeMeetingTimes(const std::vector<std::pair<int, int>>& meetings) {
    if (meetings.empty()) return {};

    auto compare = [](const std::pair<int, int>& a, const std::pair<int, int>& b) {
        return a.first > b.first;
    };

    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, decltype(compare)> pq(compare);

    // Add at most 10 intervals to the priority queue
    for (size_t i = 0; i < std::min(meetings.size(), static_cast<size_t>(10)); ++i) {
        pq.push(meetings[i]);
    }

    std::vector<std::pair<int, int>> result;
    std::pair<int, int> current = pq.top();
    pq.pop();

    while (!pq.empty()) {
        std::pair<int, int> next = pq.top();
        pq.pop();

        // Check if intervals overlap
        if (current.second >= next.first) {
            // Merge intervals
            current.second = std::max(current.second, next.second);
        } else {
            // No overlap, add current to result and move to next
            result.push_back(current);
            current = next;
        }

        // Ensure the priority queue never exceeds 10 elements
        while (pq.size() >= 10) {
            pq.pop();
        }
    }

    // Add the last merged interval
    result.push_back(current);

    return result;
}
