def categorize_logs_by_event(logs: List[Tuple[str, str]], max_event_types: int = 10, max_keys: int = 15) -> Dict[str, int]:
    event_counts = defaultdict(int)

    for _, event_type in logs:
        if event_type in event_counts or len(event_counts) < max_event_types:
            event_counts[event_type] += 1
        else:
            event_counts['Other'] += 1

    # Ensure we don't exceed max_keys
    if len(event_counts) > max_keys:
        other_count = event_counts.pop('Other', 0)
        excess_keys = list(event_counts.keys())[max_keys-1:]
        for key in excess_keys:
            other_count += event_counts.pop(key)
        event_counts['Other'] = other_count

    return event_counts
