func trackInventoryStatus(productID string, operation string, quantity int, inventory map[string]int) (map[string]int, error) {
	if inventory == nil {
		inventory = make(map[string]int)
	}

	switch operation {
	case "add":
		if len(inventory) >= 100 && inventory[productID] == 0 {
			return inventory, fmt.Errorf("inventory full: cannot exceed 100 items")
		}
		inventory[productID] += quantity

	case "remove":
		if inventory[productID] < quantity {
			return inventory, fmt.Errorf("insufficient stock for product %s", productID)
		}
		inventory[productID] -= quantity
		if inventory[productID] == 0 {
			delete(inventory, productID)
		}

	case "modify":
		if inventory[productID] == 0 && quantity > 0 && len(inventory) >= 100 {
			return inventory, fmt.Errorf("inventory full: cannot exceed 100 items")
		}
		inventory[productID] = quantity
		if inventory[productID] == 0 {
			delete(inventory, productID)
		}

	case "check":
		if _, exists := inventory[productID]; !exists {
			return inventory, fmt.Errorf("product %s not found in inventory", productID)
		}

	default:
		return inventory, fmt.Errorf("invalid operation: %s", operation)
	}

	return inventory, nil
}
