std::vector<std::string> filterUniqueEmails(const std::vector<std::string>& emails) {
    std::set<std::string> uniqueEmails;

    for (const auto& email : emails) {
        std::string normalizedEmail;
        size_t atPos = email.find('@');

        if (atPos != std::string::npos) {
            std::string localPart = email.substr(0, atPos);
            std::string domainPart = email.substr(atPos);

            // Convert to lowercase
            std::transform(localPart.begin(), localPart.end(), localPart.begin(), 
                           [](unsigned char c) { return std::tolower(c); });
            std::transform(domainPart.begin(), domainPart.end(), domainPart.begin(), 
                           [](unsigned char c) { return std::tolower(c); });

            // Normalize dots in local part
            std::string normalizedLocal;
            for (char c : localPart) {
                if (c != '.') {
                    normalizedLocal += c;
                }
            }

            normalizedEmail = normalizedLocal + domainPart;
            uniqueEmails.insert(normalizedEmail);
        }
    }

    // Convert to sorted vector and limit to 50
    std::vector<std::string> result(uniqueEmails.begin(), uniqueEmails.end());
    std::sort(result.begin(), result.end());

    if (result.size() > 50) {
        result.resize(50);
    }

    return result;
}
