struct LogEntry {
    long long timestamp;
    std::string content;

    LogEntry(long long ts, const std::string& cnt) : timestamp(ts), content(cnt) {}
};

std::deque<LogEntry> sortLogsByTimestamp(std::deque<LogEntry>& logs) {
    // Map for handling duplicates by merging content
    std::unordered_map<long long, std::string> mergedLogs;

    // Process all logs and merge duplicates
    for (const auto& log : logs) {
        if (mergedLogs.find(log.timestamp) != mergedLogs.end()) {
            // Merge content for duplicate timestamps
            mergedLogs[log.timestamp] += " | " + log.content;
        } else {
            mergedLogs[log.timestamp] = log.content;
        }
    }

    // Create a new deque with merged logs
    std::deque<LogEntry> sortedLogs;
    for (const auto& pair : mergedLogs) {
        sortedLogs.emplace_back(pair.first, pair.second);
    }

    // Sort the logs by timestamp in ascending order
    std::sort(sortedLogs.begin(), sortedLogs.end(), 
              [](const LogEntry& a, const LogEntry& b) {
                  return a.timestamp < b.timestamp;
              });

    return sortedLogs;
}
