struct LogEntry {
    unsigned long long timestamp;
    std::string content;
};

class LogSorter {
private:
    std::deque<LogEntry> logs;
    const size_t maxSize = 100;
    std::unordered_map<unsigned long long, std::string> duplicateCache;

public:
    void sortLogsByTimestamp(unsigned long long timestamp, const std::string& content) {
        // Handle duplicates
        if (duplicateCache.find(timestamp) != duplicateCache.end()) {
            duplicateCache[timestamp] += "\n" + content;
            return;
        }

        // Create new log entry
        LogEntry newEntry{timestamp, content};

        // Handle empty deque case
        if (logs.empty()) {
            logs.push_back(newEntry);
            duplicateCache[timestamp] = content;
            return;
        }

        // Check if we need to prune due to size limit
        if (logs.size() >= maxSize) {
            // Remove oldest entry
            unsigned long long oldestTimestamp = logs.front().timestamp;
            duplicateCache.erase(oldestTimestamp);
            logs.pop_front();
        }

        // Find insertion point using binary search
        auto insertPos = std::lower_bound(logs.begin(), logs.end(), newEntry, 
            [](const LogEntry& a, const LogEntry& b) {
                return a.timestamp < b.timestamp;
            });

        // Insert at proper position
        logs.insert(insertPos, newEntry);
        duplicateCache[timestamp] = content;
    }

    const std::deque<LogEntry>& getSortedLogs() const {
        return logs;
    }
};
