fn manage_inventory() -> Vec<(String, i32)> {
    let mut inventory: Vec<(String, i32)> = Vec::new();

    // Initial inventory
    inventory.push(("Product1".to_string(), 100));
    inventory.push(("Product2".to_string(), 150));
