    // Process orders (deductions)
    process_order(&mut inventory, "Product1".to_string(), 15);
    process_order(&mut inventory, "Product2".to_string(), 25);
    process_order(&mut inventory, "Product3".to_string(), 10);

    // Process returns (additions)
    process_return(&mut inventory, "Product1".to_string(), 5);
    process_return(&mut inventory, "Product2".to_string(), 2);

    // Add new product
    add_new_product(&mut inventory, "Product4".to_string(), 50);

    // Generate and return the inventory report
    inventory
}

fn process_order(inventory: &mut Vec<(String, i32)>, product_id: String, quantity: i32) {
    for item in inventory.iter_mut() {
