        if id == "P003" {
            *qty += 5;
        }
    }

    // Add new product if space allows
    if inventory.len() < 10 {
        inventory.push(("P004".to_string(), 50));
    }

    // Remove discontinued product
    let mut i = 0;
    while i < inventory.len() {
        if inventory[i].0 == "P002" && inventory[i].1 <= 0 {
            inventory.pop();
            break;
        }
        i += 1;
    }

    inventory
}
