fn manage_inventory(transactions: &[(String, i32)]) -> Vec<(String, i32)> {
    let mut inventory: Vec<(String, i32)> = Vec::new();

    for (product_id, quantity) in transactions {
        let mut found = false;

        for i in 0..inventory.len() {
            if inventory[i].0 == *product_id {
                inventory[i].1 += quantity;
                found = true;

                if inventory[i].1 <= 0 {
                    inventory.swap_remove(i);
                }
                break;
            }
        }

        if !found && *quantity > 0 {
            if inventory.len() < 10 {
                inventory.push((product_id.clone(), *quantity));
            } else {
                // Find item with lowest stock to potentially replace
                let mut min_idx = 0;
                let mut min_qty = inventory[0].1;

                for i in 1..inventory.len() {
                    if inventory[i].1 < min_qty {
                        min_idx = i;
                        min_qty = inventory[i].1;
                    }
                }

                if *quantity > min_qty {
                    inventory.swap_remove(min_idx);
                    inventory.push((product_id.clone(), *quantity));
                }
            }
        }
    }

    inventory
}
