void batchProcessTasks(std::list<std::pair<int, std::string>>& tasks, 
                       const std::vector<std::pair<int, std::string>>& updates) {
    // Process updates
    for (const auto& update : updates) {
        int updateId = update.first;
        std::string updateStatus = update.second;

        // Find and update task if it exists
        bool found = false;
        for (auto it = tasks.begin(); it != tasks.end(); ++it) {
            if (it->first == updateId) {
                if (updateStatus == "completed") {
                    it = tasks.erase(it);
                    found = false;
                    break;
                } else {
                    it->second = updateStatus;
                    found = true;
                    break;
                }
            }
        }

        // Add new task if not found and not completed
        if (!found && updateStatus != "completed") {
            tasks.push_back(update);
        }
    }

    // Sort by task ID
    tasks.sort([](const auto& a, const auto& b) {
        return a.first < b.first;
    });

    // Limit to 50 tasks
    while (tasks.size() > 50) {
        tasks.erase(--tasks.end());
    }
}
