def compare_string_sequences(sequence1, sequence2):
    matches = 0
    mismatches = 0
    differences = []

    min_length = min(len(sequence1), len(sequence2))

    # Compare elements that both sequences have
    for i in range(min_length):
        if sequence1[i] == sequence2[i]:
            matches += 1
        else:
            mismatches += 1
            differences.append({"position": i, "value1": sequence1[i], "value2": sequence2[i]})

    # Account for extra elements in the longer sequence
    if len(sequence1) > len(sequence2):
        for i in range(min_length, len(sequence1)):
            mismatches += 1
            differences.append({"position": i, "value1": sequence1[i], "value2": None})
    elif len(sequence2) > len(sequence1):
        for i in range(min_length, len(sequence2)):
            mismatches += 1
            differences.append({"position": i, "value1": None, "value2": sequence2[i]})

    # Create the report dictionary
    report = {
        "matches": matches,
        "mismatches": mismatches,
        "differences": differences
    }

    return report
