def compare_string_sequences(seq1, seq2):
    if not (isinstance(seq1, tuple) and isinstance(seq2, tuple)):
        raise TypeError("Both inputs must be tuples")

    if len(seq1) != 4 or len(seq2) != 4:
        raise ValueError("Both tuples must contain exactly 4 strings")

    report = {
        "seq1_case_check": [],
        "seq2_case_check": [],
        "matches": 0,
        "mismatches": 0,
        "mismatch_positions": []
    }

    for i in range(4):
        if not (isinstance(seq1[i], str) and isinstance(seq2[i], str)):
            raise TypeError(f"Element at position {i} must be a string in both tuples")

        seq1_is_upper = seq1[i].isupper() and seq1[i] == seq1[i].upper()
        seq2_is_upper = seq2[i].isupper() and seq2[i] == seq2[i].upper()

        report["seq1_case_check"].append(seq1_is_upper)
        report["seq2_case_check"].append(seq2_is_upper)

        if seq1_is_upper and seq2_is_upper and seq1[i] == seq2[i]:
            report["matches"] += 1
        else:
            report["mismatches"] += 1
            report["mismatch_positions"].append(i)

