use arrayvec::ArrayVec;

struct GradeEntry {
    student_id: u32,
    grade: f32,
}

fn manage_student_grades(
    grades: &mut ArrayVec<GradeEntry, 50>,
    operation: &str,
    student_id: u32,
    new_grade: Option<f32>,
) -> Result<f32, &'static str> {
    match operation {
        "add" => {
            if grades.len() >= 50 {
                return Err("Cannot add more grades, maximum capacity reached");
            }

            if grades.iter().any(|entry| entry.student_id == student_id) {
                return Err("Student ID already exists");
            }

            if let Some(grade) = new_grade {
                grades.push(GradeEntry { student_id, grade });
                Ok(calculate_average(grades))
            } else {
                Err("Grade value is required for adding")
            }
        },

        "update" => {
            if let Some(index) = grades.iter().position(|entry| entry.student_id == student_id) {
                if let Some(grade) = new_grade {
                    grades[index].grade = grade;
                    Ok(calculate_average(grades))
                } else {
                    Err("Grade value is required for updating")
                }
            } else {
                Err("Student ID not found")
            }
        },

        "delete" => {
            if let Some(index) = grades.iter().position(|entry| entry.student_id == student_id) {
                grades.remove(index);
                if grades.is_empty() {
                    Ok(0.0)
                } else {
                    Ok(calculate_average(grades))
                }
            } else {
                Err("Student ID not found")
            }
        },

        _ => Err("Invalid operation. Use 'add', 'update', or 'delete'"),
    }
}

fn calculate_average(grades: &ArrayVec<GradeEntry, 50>) -> f32 {
    if grades.is_empty() {
        return 0.0;
    }

    let sum: f32 = grades.iter().map(|entry| entry.grade).sum();
    sum / grades.len() as f32
