    HashMap<String, String> wordToSorted = new HashMap<>();

    // Limit to 10 words maximum
    int limit = Math.min(wordsToCheck.length, 10);

    // Normalize and store sorted versions of words to check
    for (int i = 0; i < limit; i++) {
        String word = wordsToCheck[i].toLowerCase().replaceAll("[^a-z]", "");
        String sortedWord = sortString(word);
        wordToSorted.put(sortedWord, word);
        result.put(word, 0);
    }

    // Split article into words and check for anagrams
