    for (String articleWord : articleWords) {
        String cleanWord = articleWord.replaceAll("[^a-z]", "");
        if (cleanWord.length() > 0) {
            String sortedArticleWord = sortString(cleanWord);

            String originalWord = wordToSorted.get(sortedArticleWord);
            if (originalWord != null) {
                Integer currentCount = result.get(originalWord);
                result.put(originalWord, currentCount + 1);
            }
        }
    }

    return result;
}

private static String sortString(String str) {
    char[] chars = str.toCharArray();
    Arrays.sort(chars);
    return new String(chars);
