public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, String[] wordsToCheck) {
    HashMap<String, Integer> result = new HashMap<>();

    // Limit to first 10 words if more are provided
    String[] limitedWords = Arrays.copyOf(wordsToCheck, Math.min(wordsToCheck.length, 10));

    // Initialize HashMap with words and zero counts
    for (String word : limitedWords) {
        result.put(word.toLowerCase(), 0);
    }

    // Split article into words
    String[] articleWords = articleText.toLowerCase().replaceAll("[^a-zA-Z\\s]", "").split("\\s+");

    // Check each word in article against target words
    for (String articleWord : articleWords) {
        for (String targetWord : limitedWords) {
            if (isAnagram(articleWord, targetWord.toLowerCase())) {
                Integer currentCount = result.get(targetWord.toLowerCase());
                result.put(targetWord.toLowerCase(), currentCount + 1);
            }
        }
    }

    // Ensure exactly 10 entries if at least 10 words were provided
    while (result.size() < 10 && wordsToCheck.length >= 10) {
        result.put("placeholder" + (result.size() + 1), 0);
    }

    return result;
}

private static boolean isAnagram(String word1, String word2) {
    if (word1.length() != word2.length()) {
        return false;
    }

    char[] chars1 = word1.toCharArray();
    char[] chars2 = word2.toCharArray();
    Arrays.sort(chars1);
    Arrays.sort(chars2);

    return Arrays.equals(chars1, chars2);
}
