struct SurveyResponse {
    int participantId;
    double rating;

    SurveyResponse(int id, double r) : participantId(id), rating(r) {}
};

class SurveyDataManager {
private:
    std::vector<SurveyResponse> responses;
    static const size_t MAX_PARTICIPANTS = 100;

    auto findParticipant(int id) {
        return std::lower_bound(responses.begin(), responses.end(), id,
            [](const SurveyResponse& response, int id) {
                return response.participantId < id;
            });
    }

public:
    bool addResponse(int participantId, double rating) {
        auto it = findParticipant(participantId);

        if (it != responses.end() && it->participantId == participantId) {
            return false; // Participant already exists
        }

        if (responses.size() >= MAX_PARTICIPANTS) {
            return false; // Maximum capacity reached
        }

        responses.insert(it, SurveyResponse(participantId, rating));
        return true;
    }

    bool queryRating(int participantId, double& rating) {
        auto it = findParticipant(participantId);
        if (it != responses.end() && it->participantId == participantId) {
            rating = it->rating;
            return true;
        }
        return false;
    }

    bool updateRating(int participantId, double newRating) {
        auto it = findParticipant(participantId);
        if (it != responses.end() && it->participantId == participantId) {
            it->rating = newRating;
            return true;
        }
        return false;
    }

    bool deleteResponse(int participantId) {
        auto it = findParticipant(participantId);
        if (it != responses.end() && it->participantId == participantId) {
            responses.erase(it);
            return true;
        }
        return false;
    }

    size_t getParticipantCount() const {
        return responses.size();
    }
