    let mut word_count = HashMap::new();

    // Process text: convert to lowercase and remove punctuation
    let cleaned_text: String = feedback
        .chars()
        .map(|c| if c.is_alphabetic() || c.is_whitespace() { c.to_lowercase().collect::<String>() } else { " ".to_string() })
        .collect::<String>();

    // Split into words and count frequencies
    for word in cleaned_text.split_whitespace() {
        if !word.is_empty() {
            *word_count.entry(word.to_string()).or_insert(0) += 1;
        }
    }

    // Limit to 50 most frequent entries
    if word_count.len() > 50 {
        let mut word_vec: Vec<(String, u32)> = word_count.into_iter().collect();
        word_vec.sort_by(|a, b| b.1.cmp(&a.1));
        word_vec.truncate(50);
        word_count = word_vec.into_iter().collect();
    }

    word_count
}
