		return errors.New("stack overflow: cannot add more than 100 employees")
	}

	es.top++
	es.employees[es.top] = emp
	es.idMap[emp.ID] = es.top
	return nil
}

func (es *EmployeeStack) pop() (Employee, error) {
	if es.top < 0 {
		return Employee{}, errors.New("stack underflow: no employees to remove")
	}

	emp := es.employees[es.top]
	delete(es.idMap, emp.ID)
	es.top--
	return emp, nil
}

func (es *EmployeeStack) getByID(id int) (Employee, error) {
	index, exists := es.idMap[id]
	if !exists {
		return Employee{}, errors.New("employee not found")
	}
	return es.employees[index], nil
}

func (es *EmployeeStack) updateByID(id int, updatedEmp Employee) error {
	index, exists := es.idMap[id]
	if !exists {
		return errors.New("employee not found")
	}

	delete(es.idMap, es.employees[index].ID)
	es.employees[index] = updatedEmp
	es.idMap[updatedEmp.ID] = index
	return nil
}

func manageEmployeeRecords() *EmployeeStack {
	stack := NewEmployeeStack()

	// Add employee
	addEmployee := func(name string, id int, position string, salary float64) error {
		emp := Employee{
			Name:     name,
			ID:       id,
			Position: position,
			Salary:   salary,
		}
		return stack.push(emp)
	}

	// Update employee
	updateEmployee := func(id int, name string, position string, salary float64) error {
		updatedEmp := Employee{
			Name:     name,
			ID:       id,
			Position: position,
			Salary:   salary,
		}
		return stack.updateByID(id, updatedEmp)
	}

	// Retrieve employee
	getEmployee := func(id int) (Employee, error) {
		return stack.getByID(id)
	}

	// Remove last employee
	removeEmployee := func() (Employee, error) {
		return stack.pop()
	}

	// Example usage
	addEmployee("John Doe", 1001, "Software Engineer", 75000.0)
	addEmployee("Jane Smith", 1002, "Product Manager", 85000.0)

	emp, _ := getEmployee(1001)
