#include <vector>

std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    int n = temperatures.size();
    std::vector<double> result(n);

    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        int count = 0;

        // Calculate the start and end indices for the current window
        int windowStart = std::max(0, i - windowSize / 2);
        int windowEnd = std::min(n - 1, i + windowSize / 2);

        // Sum up all temperatures in the window
        for (int j = windowStart; j <= windowEnd; j++) {
            sum += temperatures[j];
            count++;
        }

        // Calculate the average for current position
        result[i] = sum / count;
    }

    return result;
}
