#include <deque>

std::vector<double> computeRollingAverages(const std::vector<double>& temperatures, int windowSize) {
    std::vector<double> intermediateCalcs;
    std::deque<double> rollingAverages;

    for (int i = 0; i < temperatures.size(); i++) {
        int start = std::max(0, i - windowSize + 1);
        int end = i + 1;

        double sum = 0.0;
        for (int j = start; j < end; j++) {
            sum += temperatures[j];
        }

        double average = sum / (end - start);
        intermediateCalcs.push_back(average);

        if (rollingAverages.size() < 10) {
            rollingAverages.push_back(average);
        }
    }

    std::vector<double> result;
    for (const auto& avg : rollingAverages) {
        result.push_back(avg);
    }

    return result;
}
