func processLogFile(filePath string) (map[string]int, error) {
	// Open the log file
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("error opening log file: %w", err)
	}
	defer file.Close()

	// Create a buffer for efficient reading
	buf := &bytes.Buffer{}
	_, err = buf.ReadFrom(file)
	if err != nil {
		return nil, fmt.Errorf("error reading log file into buffer: %w", err)
	}

	// Define common error patterns to search for
	errorPatterns := []string{
		"ERROR",
		"FAILURE",
		"CRITICAL",
		"EXCEPTION",
		"TIMEOUT",
		"CONNECTION REFUSED",
		"PERMISSION DENIED",
	}

	// Map to store error counts
	errorCounts := make(map[string]int)

	// Process the buffer line by line
	scanner := bufio.NewScanner(bytes.NewReader(buf.Bytes()))
	for scanner.Scan() {
		line := scanner.Text()
		// Check for each error pattern in the current line
		for _, pattern := range errorPatterns {
			if strings.Contains(line, pattern) {
				errorCounts[pattern]++
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("error scanning log buffer: %w", err)
	}

	return errorCounts, nil
}
