		entries: make([]string, 0, maxSize),
		maxSize: maxSize,
	}
}

func (lb *LogBuffer) push(entry string) {
	if len(lb.entries) >= lb.maxSize {
		lb.pop()
	}
	lb.entries = append(lb.entries, entry)
}

func (lb *LogBuffer) pop() string {
	if len(lb.entries) == 0 {
		return ""
	}
	entry := lb.entries[0]
	lb.entries = lb.entries[1:]
	return entry
}

