	Pattern string
	Count   int
	Entries []string
}

func processLogFile(filename string, errorPatterns []string) (map[string]ErrorReport, error) {
	buffer := NewLogBuffer(1000)

	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
