	for scanner.Scan() {
		buffer.push(scanner.Text())
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	reports := make(map[string]ErrorReport)

	for _, pattern := range errorPatterns {
		regex, err := regexp.Compile(pattern)
		if err != nil {
