		return ""
	}
	entry := b.entries[0]
	b.entries = b.entries[1:]
	return entry
}

type ErrorReport struct {
	Pattern    string
	Occurrences int
	Examples   []string
}

func processLogFile(filePath string, errorPatterns []string) (map[string]*ErrorReport, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	buffer := NewLogBuffer(1000)
	scanner := bufio.NewScanner(file)

	// Read logs into buffer
	for scanner.Scan() {
		buffer.push(scanner.Text())
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	// Search for error patterns
	errorReports := make(map[string]*ErrorReport)
	for _, pattern := range errorPatterns {
		errorReports[pattern] = &ErrorReport{
			Pattern:    pattern,
			Occurrences: 0,
			Examples:   make([]string, 0),
		}
	}

	// Count occurrences of each error pattern
	for _, entry := range buffer.entries {
		for _, pattern := range errorPatterns {
			if strings.Contains(entry, pattern) {
				report := errorReports[pattern]
				report.Occurrences++
				if len(report.Examples) < 5 { // Store up to 5 examples
					report.Examples = append(report.Examples, entry)
				}
			}
		}
	}

	return errorReports, nil
}
