fn detect_cycle_in_graph(graph: &Vec<Vec<usize>>, start: usize) -> bool {
    let mut visited = vec![false; graph.len()];
    let mut rec_stack = vec![false; graph.len()];

    fn dfs(node: usize, graph: &Vec<Vec<usize>>, visited: &mut Vec<bool>, rec_stack: &mut Vec<bool>) -> bool {
