import java.util.*;

public static ArrayList<Meeting> organizeMeetings(List<Meeting> meetings) {
    PriorityQueue<Meeting> urgentQueue = new PriorityQueue<>((a, b) -> Integer.compare(b.urgencyLevel, a.urgencyLevel));
    ArrayList<Meeting> processedMeetings = new ArrayList<>();

    for (Meeting meeting : meetings) {
        if (urgentQueue.size() < 10) {
            urgentQueue.offer(meeting);
        } else if (!urgentQueue.isEmpty() && meeting.urgencyLevel > urgentQueue.peek().urgencyLevel) {
            urgentQueue.poll();
            urgentQueue.offer(meeting);
        }

        if (urgentQueue.size() == 10) {
            Meeting completedMeeting = urgentQueue.poll();
            completedMeeting.status = "completed";
            processedMeetings.add(completedMeeting);
        }
    }

    while (!urgentQueue.isEmpty()) {
        Meeting completedMeeting = urgentQueue.poll();
        completedMeeting.status = "completed";
        processedMeetings.add(completedMeeting);
    }

    return processedMeetings;
}

class Meeting {
    int urgencyLevel;
    String status;
    String title;

    public Meeting(int urgencyLevel, String title) {
        this.urgencyLevel = urgencyLevel;
        this.title = title;
        this.status = "pending";
    }
}
