import java.util.*;

public class MeetingScheduler {

    public static class Meeting {
        private String name;
        private int urgency;
        private String status;

        public Meeting(String name, int urgency) {
            this.name = name;
            this.urgency = urgency;
            this.status = "pending";
        }

        public int getUrgency() {
            return urgency;
        }

        public String getName() {
            return name;
        }

        public void setStatus(String status) {
            this.status = status;
        }

        public String getStatus() {
            return status;
        }
    }

    public static ArrayList<Meeting> organizeMeetings(List<Meeting> meetings) {
        PriorityQueue<Meeting> meetingQueue = new PriorityQueue<>((a, b) -> 
            Integer.compare(b.getUrgency(), a.getUrgency()));

        ArrayList<Meeting> processedMeetings = new ArrayList<>();

        for (Meeting meeting : meetings) {
            if (meetingQueue.size() < 10) {
                meetingQueue.offer(meeting);
            } else if (meeting.getUrgency() > meetingQueue.peek().getUrgency()) {
                meetingQueue.poll();
                meetingQueue.offer(meeting);
            }
        }

        while (!meetingQueue.isEmpty()) {
            Meeting meeting = meetingQueue.poll();
            meeting.setStatus("completed");
            processedMeetings.add(meeting);
        }

        return processedMeetings;
    }
}
